INSERT INTO admin_settings (key, value)
INSERT INTO lessons (slug, title, category, subcategory, description, rating, tags, read_time, difficulty, content) VALUES
  ('espresso', 'إسبريسو', 'drinks', 'مشروبات القهوة', 'الإسبريسو ليس قهوة صغيرة ولا مجرد زر في الماكينة. هو الاختبار الأول لجودة البن، ودقة الطحن، وثبات الماكينة، ويد الباريستا. إذا كان الإسبريسو سيئًا فلن يختبئ داخل اللاتيه أو الكابتشينو؛ سيظهر بطعم حامض مزعج، مرارة جافة، أو جسم ضعيف. الإسبريسو الجيد يبدأ بوصفة واضحة قابلة للتكرار: جرعة بن دقيقة، طحن مناسب، توزيع متساو، كبس ثابت، واستخلاص (Extraction) يعطي حلاوة وقوامًا وكريما (Crema) نظيفة دون مبالغة في الأرقام.', 4.9, ARRAY["أساسي"], '30s', 'أساسي', '## الفكرة\nأساس أغلب مشروبات المقهى، وأول اختبار لجودة البن والطحن والاستخلاص (Extraction)\n\n## لماذا مهم؟\nلأن اللاتيه والكابتشينو والفلات وايت تبدأ منه؛ إذا فشلت جرعة الإسبريسو فشل المشروب كله\n\n## الوصفة المرجعية\nابدأ بجرعة 18g وكمية قهوة في الكوب قريبة من 36g خلال 25-30 ثانية، ثم احكم بالطعم\n\n## الطحن\nالطحن الناعم جدًا يبطئ الاستخلاص (Extraction) وقد يعطي مرارة وجفافًا؛ الخشن جدًا يسرع النزول ويعطي حموضة وضعفًا\n\n## التوزيع\nالتوزيع السيئ يسبب تسرّب الماء من مسار واحد داخل القهوة (Channeling)؛ فيستخلص الماء جزءًا أكثر من اللازم ويترك جزءًا آخر ضعيفًا\n\n## الكبس\nالكبس يجب أن يكون مستويًا وثابتًا؛ القوة المبالغ بها أقل أهمية من الاستواء\n\n## علامة الجودة\nكوب متوازن: حلاوة واضحة، قوام حاضر، مرارة نظيفة، وحموضة غير مزعجة\n\n## خطأ شائع\nالحكم على الإسبريسو من شكل الكريما (Crema) فقط؛ الكريما (Crema) مؤشر بصري وليست ضمانًا للطعم\n\n## نصيحة للباريستا\nغيّر متغيرًا واحدًا في كل مرة: الطحن أو الجرعة أو كمية القهوة الخارجة (Yield) في الكوب (Yield)، ولا تغيّر كل شيء معًا\n\n## لصاحب المقهى\nثبات وصفة الإسبريسو يحمي جودة المنيو ويقلل هدر البن والحليب وشكاوى العملاء\n\n## مناسب لمن؟\nلمن يريد فهم القاعدة التي تُبنى عليها أغلب مشروبات القهوة في المقهى\n\n## خطوات التحضير\n\n### 1. تسخين المجموعة والكوب\nابدأ بمعدات ساخنة ومستقرة. الإسبريسو حساس للحرارة، والكوب البارد يسرق جزءًا من حرارة جرعة الإسبريسو.\n⏱ 10s\n\n### 2. وزن الجرعة\nاستخدم الميزان بدل التقدير بالعين. جرعة 18g نقطة بداية ممتازة لكثير من السلال، لكنها ليست قانونًا ثابتًا لكل بن.\n⏱ 10s\n\n### 3. ضبط الطحن\nاطحن طازجًا بدرجة مناسبة للإسبريسو. إذا نزل الإسبريسو بسرعة كبيرة فالغالب أن الطحن خشن، وإذا اختنق فالغالب أنه ناعم جدًا.\n⏱ 15s\n\n### 4. توزيع القهوة\nوزّع القهوة داخل البورتافلتر قبل الكبس. الهدف أن تكون القهوة متساوية حتى لا يهرب الماء من جهة واحدة.\n⏱ 15s\n\n### 5. الكبس المستوي\nاكبس بسطح مستقيم وثابت. لا تحتاج استعراض قوة؛ تحتاج سطحًا مستويًا يمنح الماء مقاومة متوازنة.\n⏱ 10s\n\n### 6. شطف رأس المجموعة\nمرّر ماء قصيرًا قبل تركيب البورتافلتر لتنظيف بقايا القهوة وتثبيت الحرارة.\n⏱ 5s\n\n### 7. الاستخلاص (Extraction)\nابدأ الاستخلاص (Extraction) وراقب الوزن لا اللون فقط. نقطة بداية جيدة: 18g داخل السلة تعطي 36g في الكوب خلال 25-30 ثانية.\n⏱ 25-30s\n\n### 8. التذوق والتقييم\nلا تجعل الرقم ينتصر على الطعم. إن كانت جرعة الإسبريسو حامضة وضعيفة جرّب طحنًا أنعم، وإن كان مرًا وجافًا جرّب طحنًا أخشن أو قلّل كمية القهوة الخارجة (Yield) في الكوب (Yield).\n⏱ 20s\n\n### 9. تثبيت الوصفة\nعندما تصل لطعم جيد، سجّل الجرعة والطحن وكمية القهوة الخارجة (Yield) في الكوب (Yield) والوقت. ثبات الوصفة هو الفرق بين مقهى محترف ومقهى يتغير طعمه كل ساعة.\n⏱ 15s'),
  ('ristretto', 'ريستريتو', 'drinks', 'مشروبات القهوة', 'الريستريتو هو الوجه القصير والمكثف للإسبريسو. لا يعني أنه أفضل دائمًا، بل يعني أنك تختار كمية أقل في الكوب وتركيزًا أعلى. نجاحه يعتمد على بن مناسب وطحن مضبوط؛ إذا قللت كمية القهوة الخارجة (Yield) بطريقة عشوائية قد تحصل على كوب حاد وغير مكتمل بدل كوب حلو وكثيف.', 4.6, ARRAY["مركز"], '25s', 'مركز', '## الفكرة\nاستخلاص (Extraction) أقصر من الإسبريسو بحجم أقل وتركيز أعلى\n\n## الفرق عن الإسبريسو\nغالبًا كمية أقل في الكوب من نفس جرعة البن، لذلك يكون الطعم أكثر تركيزًا وأقصر في الفم\n\n## الوصفة المرجعية\nجرعة 18g قد تعطي كمية قهوة في الكوب بين 18-25g حسب البن والطعم المطلوب\n\n## الطعم المتوقع\nكثافة أعلى وحلاوة أوضح إذا كان البن مناسبًا، لكن قد تظهر حدة إذا كان الاستخلاص (Extraction) ناقصًا\n\n## خطأ شائع\nاعتبار الريستريتو أقوى أو أرقى دائمًا من الإسبريسو؛ هو أسلوب لا رتبة أعلى\n\n## نصيحة للباريستا\nلا تقلل كمية القهوة في الكوب فقط؛ راقب الطعم وعدّل الطحن حتى لا يصبح الكوب حامضًا أو خامًا\n\n## لصاحب المقهى\nاستخدمه عندما يخدم هوية المنيو، لا تضفه فقط لأنه يبدو فاخرًا في الاسم\n\n## مناسب لمن؟\nمن يحب النكهات القصيرة والكثيفة ولا يبحث عن كوب طويل\n\n## خطوات التحضير\n\n### 1. ابدأ بوصفة إسبريسو جيدة\nلا تبدأ من الصفر. خذ وصفة إسبريسو متوازنة ثم قلّل كمية القهوة الخارجة (Yield) تدريجيًا.\n⏱ 10s\n\n### 2. اضبط كمية القهوة في الكوب\nاستهدف كمية أقصر، مثل 18-25g من جرعة 18g كبداية قابلة للتعديل.\n⏱ 10s\n\n### 3. راقب القوام\nالهدف قوام أثقل وحلاوة مركزة، وليس مجرد كمية أقل بلا توازن.\n⏱ 15s\n\n### 4. تذوق قبل الاعتماد\nإذا كان الطعم حامضًا أو عشبيًا، قد يكون الاستخلاص (Extraction) ناقصًا ويحتاج تعديل طحن أو تعديل كمية القهوة الخارجة (Yield) في الكوب (Yield).\n⏱ 20s'),
  ('lungo', 'لونغو', 'drinks', 'مشروبات القهوة', 'اللونغو هو إسبريسو ممتد؛ الماء يمر عبر القهوة لمدة أطول ويخرج كمية أكبر في الكوب. هو ليس أمريكانو، لأن الأمريكيانو يخفف جرعة الإسبريسو بعد الاستخلاص (Extraction). اللونغو قد يعطي كوبًا ألطف وأطول، لكنه قد يصبح مرًا وجافًا إذا استخرجت من القهوة أكثر من اللازم.', 4.3, ARRAY["طويل"], '40s', 'طويل', '## الفكرة\nاستخلاص (Extraction) أطول من الإسبريسو بحجم أكبر في الكوب\n\n## الفرق عن الأمريكيانو\nفي اللونغو يمر الماء عبر القهوة؛ في الأمريكيانو يضاف الماء إلى الإسبريسو بعد تحضيره\n\n## الوصفة المرجعية\nقد يبدأ من 18g بن إلى 45-60g قهوة خارجة في الكوب، لكن الطعم هو الحكم\n\n## المخاطرة\nالاستخلاص (Extraction) الطويل قد يسحب مرارة وجفافًا من القهوة\n\n## خطأ شائع\nتمديد أي إسبريسو تلقائيًا واعتبار النتيجة لونغو جيد\n\n## نصيحة عملية\nاستخدم بنًا يتحمل الاستخلاص (Extraction) الأطول ولا تعتمد على الوقت وحده\n\n## لصاحب المقهى\nقد يناسب العملاء الذين يريدون قهوة أطول بطابع إسبريسو دون إضافة ماء منفصل\n\n## مناسب لمن؟\nمن يريد قهوة أكبر من الإسبريسو لكن لا يريد أمريكانو مخففًا\n\n## خطوات التحضير\n\n### 1. ابدأ من جرعة ثابتة\nاستخدم جرعة معروفة مثل 18g ولا تغيّر كل المتغيرات دفعة واحدة.\n⏱ 10s\n\n### 2. ارفع كمية القهوة الخارجة (Yield) تدريجيًا\nزِد كمية القهوة الخارجة (Yield) تدريجيًا بدل القفز مباشرة إلى كوب كبير.\n⏱ 20s\n\n### 3. راقب المرارة (Bitterness)\nإذا ظهر جفاف ومرارة واضحة، قلّل كمية القهوة الخارجة (Yield) أو عدّل الطحن.\n⏱ 15s\n\n### 4. قارن بالأمريكانو\nتذوق الفرق بين لونغو وأمريكانو حتى تفهم ما يناسب منيوك.\n⏱ 30s'),
  ('americano', 'أمريكانو', 'drinks', 'مشروبات القهوة', 'الأمريكانو يبدو بسيطًا، لكنه يكشف جودة الإسبريسو بوضوح. هو جرعة إسبريسو (Espresso Shot) تُخفف بالماء الساخن ليعطي كوبًا أطول وأخف. إذا كانت جرعة الإسبريسو متوازنة خرج كوب نظيف ومريح، وإذا كانت جرعة الإسبريسو سيئة ستظهر الحموضة (Acidity) أو المرارة (Bitterness) بشكل مباشر.', 4.4, ARRAY["سهل"], '2m', 'سهل', '## الفكرة\nجرعة إسبريسو (Espresso Shot) مضاف إليها ماء ساخن للحصول على كوب أطول وأخف\n\n## الفرق عن الفلتر\nالأمريكانو يبدأ من ضغط الإسبريسو، بينما الفلتر يعتمد على ترشيح بطيء\n\n## النسبة العملية\nابدأ بجرعة إسبريسو (Espresso Shot) مع 100-160ml ماء، وعدل حسب قوة البن وذوق العميل\n\n## ترتيب الصب\nالماء أولًا يعطي كريما (Crema) ألطف، والإسبريسو أولًا يعطي مظهرًا مختلفًا؛ الطعم هو الأهم\n\n## خطأ شائع\nاستخدام ماء شديد الحرارة يحرق الإحساس بالطعم ويجعل الكوب قاسيًا\n\n## نصيحة عملية\nلا تضعف الإسبريسو جدًا؛ العميل يريد كوبًا خفيفًا لا ماء بطعم قهوة\n\n## لصاحب المقهى\nالأمريكانو صنف أساسي وسهل التشغيل، لكن جودته مرتبطة بثبات وصفة الإسبريسو\n\n## مناسب لمن؟\nمن يريد قهوة سوداء أخف من الإسبريسو وأقصر طريقها من ماكينة الإسبريسو\n\n## خطوات التحضير\n\n### 1. حضّر الماء\nضع ماء ساخنًا في الكوب بدرجة لا تكون مغلية بعنف.\n⏱ 15s\n\n### 2. استخلص الإسبريسو\nحضّر جرعة إسبريسو (Espresso Shot) متوازنة لأن كل عيوبها ستظهر في الكوب.\n⏱ 30s\n\n### 3. ادمج بهدوء\nأضف الإسبريسو إلى الماء أو العكس حسب أسلوب التقديم المعتمد لديك.\n⏱ 10s\n\n### 4. تذوق القوة\nإن كان خفيفًا جدًا قلل الماء، وإن كان حادًا زِد الماء قليلًا أو راجع وصفة الإسبريسو.\n⏱ 20s'),
  ('cappuccino', 'كابتشينو', 'drinks', 'مشروبات القهوة', 'الكابتشينو ليس لاتيه صغيرًا. قوته في التوازن بين الإسبريسو والحليب والرغوة. إذا زاد الحليب أصبح لاتيه، وإذا زادت الرغوة صار كوبًا جافًا، وإذا ضعف الإسبريسو ضاعت شخصية المشروب. الكابتشينو الجيد يعطيك قهوة واضحة، حليبًا ناعمًا، ورغوة مريحة دون مبالغة.', 4.8, ARRAY["متوسط"], '3m', 'متوسط', '## الفكرة\nتوازن واضح بين الإسبريسو والحليب والرغوة\n\n## الفرق عن اللاتيه\nاللاتيه أكثر حليبًا وأنعم، أما الكابتشينو فيحافظ على حضور القهوة والرغوة\n\n## الوصفة المرجعية\nجرعة إسبريسو (Espresso Shot) مع حليب مبخر ورغوة واضحة في كوب متوسط\n\n## قوام الحليب\nالرغوة الدقيقة أهم من الرغوة الكثيرة؛ المطلوب نعومة لا فقاعات كبيرة\n\n## خطأ شائع\nاعتباره لاتيه صغيرًا أو ملء الكوب برغوة جافة بلا قوام\n\n## نصيحة للباريستا\nابدأ بإسبريسو جيد ثم بخّر الحليب حتى يصبح لامعًا وحريريًا\n\n## لصاحب المقهى\nالكابتشينو معيار مهم لجودة التدريب لأن العميل يلاحظ فورًا ضعف التبخير أو جرعة الإسبريسو\n\n## مناسب لمن؟\nمن يريد مشروبًا حليبيًا لكن لا يريد أن تختفي القهوة\n\n## خطوات التحضير\n\n### 1. حضّر الإسبريسو\nاستخلص جرعة إسبريسو (Espresso Shot) متوازنة قبل الانشغال بالحليب.\n⏱ 30s\n\n### 2. ابدأ التبخير\nأدخل هواء قليلًا في بداية التبخير فقط، ثم ركّز على تدوير الحليب.\n⏱ 15s\n\n### 3. اصنع القوام\nالهدف حليب لامع ورغوة دقيقة، لا فقاعات كبيرة على السطح.\n⏱ 35s\n\n### 4. ادمج الحليب\nحرّك الإبريق بلطف حتى يندمج الحليب والرغوة قبل الصب.\n⏱ 5s\n\n### 5. اسكب بتوازن\nاسكب بحيث يبقى طعم القهوة واضحًا وتظهر الرغوة دون أن تطغى.\n⏱ 20s\n\n### 6. قيّم الكوب\nإذا كان المشروب حليبيًا جدًا فهو أقرب للاتيه، وإذا كان جافًا جدًا راجع تبخيرك.\n⏱ 15s'),
  ('latte', 'لاتيه', 'drinks', 'مشروبات القهوة', 'اللاتيه هو أكثر مشروب يعلّمك معنى قوام الحليب. هو ليس حليبًا ساخنًا مع قهوة، بل مشروب ناعم يحتاج إسبريسو واضحًا وحليبًا حريريًا. نجاحه يظهر في أول رشفة: نعومة، حلاوة حليب، وقهوة حاضرة بدون قسوة.', 4.7, ARRAY["سهل"], '4m', 'سهل', '## الفكرة\nجرعة إسبريسو (Espresso Shot) مع كمية أكبر من الحليب وقوام ناعم جدًا\n\n## الفرق عن الكابتشينو\nرغوة أقل وحليب أكثر، لذلك يكون المشروب أهدأ وأنعم\n\n## الوصفة المرجعية\nجرعة إسبريسو (Espresso Shot) مع 180-240ml حليب حسب حجم الكوب وهوية المقهى\n\n## قوام الحليب\nرغوة حليب ناعمة جدًا (Microfoam) تندمج مع القهوة بدل طبقة رغوة منفصلة\n\n## خطأ شائع\nحليب كثير مع جرعة إسبريسو (Espresso Shot) ضعيفة يجعل المشروب بلا شخصية\n\n## نصيحة للباريستا\nلا ترفع حرارة الحليب أكثر من اللازم؛ الحرارة العالية تقتل الحلاوة (Sweetness) وتظهر طعمًا مطبوخًا\n\n## لصاحب المقهى\nاللاتيه من أكثر المشروبات طلبًا، وثباته مهم لأنه يحمل نكهات إضافية بسهولة\n\n## مناسب لمن؟\nالمبتدئين ومحبي المشروبات الناعمة والحليبية\n\n## خطوات التحضير\n\n### 1. استخلص الإسبريسو\nابدأ بجرعة إسبريسو (Espresso Shot) واضحة ومتوازنة لأن الحليب سيخفف حدتها.\n⏱ 30s\n\n### 2. حضّر الحليب\nاستخدم حليبًا باردًا ومناسبًا للتبخير للحصول على قوام أفضل.\n⏱ 10s\n\n### 3. أدخل هواء قليلًا\nاللاتيه لا يحتاج رغوة كثيرة؛ فقط ما يكفي لصنع قوام حريري.\n⏱ 10s\n\n### 4. دوّر الحليب\nاصنع دوامة داخل الإبريق لتكسير الفقاعات ودمج القوام.\n⏱ 35s\n\n### 5. اسكب بهدوء\nابدأ من ارتفاع أعلى للدمج، ثم اقترب من السطح لو أردت رسمًا بسيطًا.\n⏱ 25s\n\n### 6. راجع النتيجة\nإذا ظهرت فقاعات كبيرة أو طبقة منفصلة، فالمشكلة غالبًا في التبخير أو الدمج.\n⏱ 15s'),
  ('flat-white', 'فلات وايت', 'drinks', 'مشروبات القهوة', 'الفلات وايت مشروب حليبي لكنه أكثر تركيزًا من اللاتيه. فكرته أن تشعر بنعومة الحليب دون أن تخسر وضوح الإسبريسو. حجمه عادة أصغر، والرغوة فيه أدق وأقل، لذلك يظهر الفرق الحقيقي في جودة جرعة الإسبريسو وقوام الحليب.', 4.7, ARRAY["ناعم"], '3m', 'ناعم', '## الفكرة\nحليب ناعم مع قهوة أوضح من اللاتيه\n\n## الفرق عن اللاتيه\nحجم أقل، قهوة أوضح، ورغوة أدق لا تشبه رغوة الكابتشينو\n\n## الوصفة المرجعية\nجرعتان من الإسبريسو (Double Shot / 2 Shots)، أو جرعة مركزة حسب وصفة المقهى، مع حليب أقل من اللاتيه\n\n## قوام الحليب\nناعم ومندمج جدًا، بلا طبقة رغوة سميكة\n\n## خطأ شائع\nتقديمه كأنه لاتيه عادي باسم مختلف\n\n## نصيحة للباريستا\nقلل حجم الكوب بدل زيادة الحليب، واجعل الإسبريسو حاضرًا\n\n## لصاحب المقهى\nالفلات وايت يرفع إحساس الاحتراف في المنيو إذا تم شرحه وتقديمه بشكل صحيح\n\n## مناسب لمن؟\nمن يحب الحليب لكن يريد قهوة أوضح وقوامًا أنعم\n\n## خطوات التحضير\n\n### 1. ابدأ بجرعة إسبريسو (Espresso Shot) واضحة\nاستخدم وصفة إسبريسو متوازنة حتى تبقى القهوة واضحة في الكوب.\n⏱ 30s\n\n### 2. بخّر حليبًا ناعمًا\nأدخل هواء أقل من الكابتشينو وركز على اللمعان والاندماج.\n⏱ 40s\n\n### 3. اختر كوبًا مناسبًا\nالحجم الكبير سيحوّله عمليًا إلى لاتيه.\n⏱ 5s\n\n### 4. اسكب ببطء\nادمج الحليب مع الإسبريسو دون صنع رغوة سميكة.\n⏱ 20s\n\n### 5. قيّم الحضور\nإذا اختفت القهوة خلف الحليب، قلل الحليب أو قوّي وصفة الإسبريسو.\n⏱ 15s'),
  ('cortado', 'كورتادو', 'drinks', 'مشروبات القهوة', 'الكورتادو مشروب صغير ذكي: يخفف حدة الإسبريسو بكمية قريبة من الحليب دون أن يحوله إلى مشروب حليبي كبير. اسمه يعكس فكرته: قطع حدة القهوة لا إخفاؤها. لذلك هو مناسب لمن يريد قوة الإسبريسو بنعومة بسيطة.', 4.5, ARRAY["متوازن"], '2m', 'متوازن', '## الفكرة\nإسبريسو مع كمية قريبة من الحليب لتخفيف الحدة لا لإخفاء القهوة\n\n## الفرق عن اللاتيه\nأصغر بكثير، حليب أقل، وقهوة أوضح\n\n## الوصفة المرجعية\nنسبة قريبة من 1:1 بين الإسبريسو والحليب الدافئ\n\n## قوام الحليب\nناعم وخفيف، بدون رغوة عالية\n\n## خطأ شائع\nتكبير الحجم حتى يصبح لاتيه صغيرًا\n\n## نصيحة عملية\nاستخدم كوبًا صغيرًا وثبّت النسبة حتى لا يضيع تعريف المشروب\n\n## لصاحب المقهى\nممتاز للعملاء الذين يحبون القهوة الجادة لكن لا يريدون إسبريسو صافيًا\n\n## مناسب لمن؟\nمن يريد توازنًا سريعًا بين قوة القهوة ونعومة الحليب\n\n## خطوات التحضير\n\n### 1. استخلص الإسبريسو\nحضّر جرعة إسبريسو (Espresso Shot) قصيرة ومتوازنة.\n⏱ 30s\n\n### 2. سخّن الحليب\nبخّر كمية قليلة بقوام ناعم دون رغوة كبيرة.\n⏱ 25s\n\n### 3. حافظ على النسبة\nلا تجعل الحليب يغلب القهوة؛ الفكرة هي التوازن.\n⏱ 10s\n\n### 4. قدّم فورًا\nالكورتادو صغير، لذلك يتأثر بسرعة بالحرارة والتأخير.\n⏱ 5s'),
  ('macchiato', 'ماكياتو', 'drinks', 'مشروبات القهوة', 'الماكياتو الحقيقي ليس كوبًا كبيرًا بالكراميل. في أصله هو إسبريسو معلّم بلمسة حليب أو رغوة، أي أن القهوة تبقى البطل. قوته في البساطة: جرعة إسبريسو (Espresso Shot) واضحة، وكمية صغيرة جدًا من الحليب أو الرغوة تخفف الحدة دون أن تغير هوية المشروب.', 4.4, ARRAY["صغير"], '1m', 'صغير', '## الفكرة\nإسبريسو مع لمسة حليب أو رغوة فقط\n\n## معنى الاسم\nماكياتو تعني معلّم أو ملطخ؛ أي إسبريسو عليه علامة حليب بسيطة\n\n## الفرق عن المشروبات التجارية\nليس كوبًا كبيرًا محلى بالكراميل، بل مشروب قصير جدًا\n\n## الوصفة المرجعية\nجرعة إسبريسو (Espresso Shot) مع ملعقة صغيرة من رغوة الحليب أو الحليب المبخر\n\n## خطأ شائع\nإخفاء الإسبريسو بالحليب والسكر والنكهات ثم تسميته ماكياتو تقليدي\n\n## نصيحة للباريستا\nاجعل اللمسة خفيفة ومدروسة؛ لا تحوّل المشروب إلى كورتادو\n\n## لصاحب المقهى\nاشرحه في المنيو حتى لا يخلط العميل بينه وبين النسخ التجارية الحلوة\n\n## مناسب لمن؟\nمحبي الإسبريسو الذين يريدون حدة ألطف قليلًا\n\n## خطوات التحضير\n\n### 1. حضّر الإسبريسو\nاستخلص جرعة إسبريسو (Espresso Shot) متوازنة في كوب صغير.\n⏱ 30s\n\n### 2. أضف كمية صغيرة جدًا من الحليب أو الرغوة\nاستخدم رغوة قليلة أو كمية بسيطة من الحليب المبخر.\n⏱ 15s\n\n### 3. ضع علامة الحليب على الإسبريسو\nضع كمية الحليب الصغيرة على سطح الإسبريسو دون خلط زائد.\n⏱ 5s\n\n### 4. قدّم مباشرة\nالمشروب صغير وسريع، لذلك أفضل لحظته فور التحضير.\n⏱ 5s'),
  ('mocha', 'موكا', 'drinks', 'مشروبات القهوة', 'الموكا هو الجسر بين القهوة والشوكولاتة. ليس الهدف أن يتحول إلى شراب شوكولاتة ساخن، ولا أن تكون القهوة قاسية. نجاحه في التوازن: إسبريسو واضح، كاكاو جيد، حليب ناعم، وحلاوة محسوبة تجعل المشروب ممتعًا لا متعبًا.', 4.5, ARRAY["حلو"], '4m', 'حلو', '## الفكرة\nلاتيه بطابع شوكولاتة مع بقاء القهوة واضحة\n\n## المعادلة\nإسبريسو جيد + كاكاو أو شوكولاتة مناسبة + حليب ناعم\n\n## التحلية\nزيادة السكر أو صوص الشوكولاتة تخفي القهوة وتجعل المشروب ثقيلًا بعد أول رشفات\n\n## اختيار الكاكاو\nكلما كان الكاكاو أفضل قل احتياجك للسكر والنكهات الصناعية\n\n## خطأ شائع\nجعله شراب شوكولاتة فقط ثم إضافة قهوة ضعيفة فوقه\n\n## نصيحة للباريستا\nاخلط الشوكولاتة مع الإسبريسو أولًا حتى تذوب وتندمج قبل الحليب\n\n## لصاحب المقهى\nالموكا صنف رابح إذا ضُبطت تكلفة الشوكولاتة والحجم والتحلية\n\n## مناسب لمن؟\nمن يريد حلاوة مع طعم قهوة حقيقي\n\n## خطوات التحضير\n\n### 1. حضّر قاعدة الشوكولاتة\nضع كاكاو أو صوص شوكولاتة بجودة مناسبة في الكوب.\n⏱ 10s\n\n### 2. استخلص الإسبريسو\nاسكب جرعة الإسبريسو فوق الشوكولاتة وحرّك حتى تندمج.\n⏱ 30s\n\n### 3. بخّر الحليب\nاصنع قوامًا ناعمًا مثل اللاتيه.\n⏱ 45s\n\n### 4. ادمج المكونات\nاسكب الحليب فوق مزيج القهوة والشوكولاتة بهدوء.\n⏱ 20s\n\n### 5. وازن كمية التحلية\nتذوق النتيجة ولا تجعل السكر أو صوص الشوكولاتة يغطي طعم القهوة الطبيعي.\n⏱ 15s'),
  ('cold-brew', 'كولد برو', 'drinks', 'مشروبات القهوة', 'الكولد برو ليس قهوة باردة عادية؛ هو استخلاص (Extraction) طويل بالماء البارد أو بدرجة حرارة الغرفة. يعطي غالبًا كوبًا ناعمًا وأقل حدة، لكنه ليس بلا قواعد. النسبة، الطحن، وقت النقع، والتصفية كلها تحدد هل ستحصل على مشروب نظيف أم قهوة ثقيلة ومسطحة.', 4.6, ARRAY["بارد"], '12h', 'بارد', '## الفكرة\nاستخلاص (Extraction) طويل دون حرارة عالية للحصول على كوب بارد وناعم\n\n## الفرق عن القهوة المثلجة\nالقهوة المثلجة قد تكون قهوة ساخنة بُردت؛ الكولد برو يُستخلص باردًا من البداية\n\n## النسبة العملية\nابدأ بنسبة 1:8 إلى 1:10 كمركز، أو خفف حسب طريقة التقديم\n\n## الطحن\nطحن خشن إلى متوسط خشن يقلل العكارة والمرارة (Bitterness)\n\n## الوقت\nغالبًا 12-18 ساعة؛ الوقت الأطول ليس دائمًا أفضل\n\n## خطأ شائع\nاستخدام طحن ناعم جدًا فيخرج مشروب عكر وثقيل\n\n## لصاحب المقهى\nممتاز للتجهيز المسبق وخدمة الذروة، لكن يحتاج نظام حفظ وتاريخ إنتاج واضح\n\n## مناسب لمن؟\nالأسواق الحارة، المشروبات الجاهزة، والعملاء الذين يفضلون حموضة أقل\n\n## خطوات التحضير\n\n### 1. اختر الطحن\nاستخدم طحنًا خشنًا إلى متوسط خشن لتسهيل التصفية وتقليل العكارة.\n⏱ 30s\n\n### 2. اضبط النسبة\nابدأ بنسبة واضحة وسجلها؛ بدون تسجيل لن تعرف لماذا نجحت أو فشلت الدفعة.\n⏱ 30s\n\n### 3. انقع القهوة\nاترك القهوة مع الماء 12-18 ساعة حسب البن والنتيجة المطلوبة.\n⏱ 12-18h\n\n### 4. صفّ المشروب\nاستخدم فلترًا مناسبًا حتى تحصل على مشروب نظيف غير رملي.\n⏱ 3m\n\n### 5. خفف وقدّم\nإذا كان مركزًا، خففه بالماء أو الحليب حسب الوصفة المعتمدة.\n⏱ 30s\n\n### 6. احفظ بوضوح\nاكتب تاريخ التحضير ولا تترك الدفعات دون تتبع.\n⏱ 20s'),
  ('iced-latte', 'آيس لاتيه', 'drinks', 'مشروبات القهوة', 'الآيس لاتيه يبدو بسيطًا: ثلج، حليب، وإسبريسو. لكن بساطته خادعة؛ الثلج يخفف الطعم بسرعة، والحليب البارد يبرز ضعف جرعة الإسبريسو إن كانت غير متوازنة. الآيس لاتيه الجيد يبقى واضح القهوة حتى بعد أول دقائق من الذوبان.', 4.6, ARRAY["بارد"], '3m', 'بارد', '## الفكرة\nلاتيه بارد يعتمد على توازن الثلج والحليب والإسبريسو\n\n## المشكلة الأساسية\nالثلج يخفف الطعم، لذلك جرعة الإسبريسو الضعيفة ستختفي بسرعة\n\n## الوصفة العملية\nكوب ثلج، حليب بارد، ثم جرعة إسبريسو (Espresso Shot) أو جرعتان حسب حجم الكوب\n\n## الحليب\nالحليب البارد لا يخفي العيوب مثل الحليب المبخر، لذلك جودة الإسبريسو مهمة\n\n## خطأ شائع\nكوب كبير جدًا مع حليب كثير وجرعة إسبريسو واحدة (Single Shot) ضعيفة\n\n## نصيحة للباريستا\nاستخدم وصفة إسبريسو واضحة، ووازن حجم الكوب مع عدد جرعات الإسبريسو\n\n## لصاحب المقهى\nمن أهم مشروبات المقاهي الفلسطينية، ويحتاج ضبط تكلفة الحليب والثلج والإضافات\n\n## مناسب لمن؟\nمن يريد مشروبًا باردًا ناعمًا وسهل الشرب\n\n## خطوات التحضير\n\n### 1. املأ الكوب بالثلج\nاستخدم ثلجًا كافيًا حتى يبقى المشروب باردًا ولا يذوب بسرعة كبيرة.\n⏱ 10s\n\n### 2. أضف الحليب\nاسكب حليبًا باردًا بكمية تناسب حجم الكوب.\n⏱ 10s\n\n### 3. استخلص الإسبريسو\nحضّر جرعة إسبريسو (Espresso Shot) واضحة ومتوازنة، ويمكن استخدام جرعتين للأحجام الكبيرة.\n⏱ 30s\n\n### 4. اسكب القهوة\nأضف الإسبريسو فوق الحليب أو قبله حسب شكل التقديم المطلوب.\n⏱ 10s\n\n### 5. اختبر التوازن\nإذا اختفت القهوة بعد التحريك، فالمشكلة غالبًا في النسبة أو قوة جرعة الإسبريسو.\n⏱ 15s'),
  ('spanish-latte', 'سبانش لاتيه', 'drinks', 'مشروبات القهوة', 'السبانش لاتيه محبوب جدًا في فلسطين لأنه يجمع القهوة والحليب والتحلية في كوب واحد. لكن نجاحه ليس في زيادة الحليب المكثف (Condensed Milk) فقط. التحلية إذا زادت غطّت طعم القهوة وجعلت المشروب متعبًا. السبانش الجيد حلو، نعم، لكنه ما زال يقول: أنا قهوة.', 4.8, ARRAY["حلو"], '4m', 'حلو', '## الفكرة\nلاتيه حلو يعتمد غالبًا على الحليب المكثف (Condensed Milk) أو مزيج حليب محلى\n\n## لماذا نجح محليًا؟\nيناسب ذائقة تحب المشروبات المحلّاة والباردة مع بقاء نكهة القهوة\n\n## التوازن\nالتحلية يجب أن تدعم القهوة لا أن تطمسها\n\n## الوصفة العملية\nإسبريسو واضح، حليب بارد أو مبخر، وكمية تحلية محسوبة حسب حجم الكوب\n\n## خطأ شائع\nزيادة الحليب المكثف (Condensed Milk) حتى يصبح المشروب سكرًا باردًا\n\n## نصيحة للباريستا\nابدأ بكمية تحلية ثابتة ثم اختبرها مع ذوبان الثلج لا قبل التحريك فقط\n\n## لصاحب المقهى\nصنف مهم في المقاهي الفلسطينية، لكنه يحتاج ضبط تكلفة وبطاقة وصفة تشغيلية حتى لا يختلف بين الموظفين\n\n## مناسب لمن؟\nمحبي المشروبات الحلوة والباردة، ولقوائم المقاهي الفلسطينية\n\n## خطوات التحضير\n\n### 1. أضف مزيج التحلية (Sweetening Mix) أو الحليب المكثف (Condensed Milk)\nضع كمية محسوبة من الحليب المكثف (Condensed Milk) أو مزيج التحلية (Sweetening Mix) المعتمد داخل الكوب.\n⏱ 10s\n\n### 2. أضف الحليب\nاستخدم حليبًا باردًا أو مبخرًا حسب النسخة المطلوبة.\n⏱ 10s\n\n### 3. حضّر الإسبريسو\nجرعة الإسبريسو يجب أن تكون واضحة حتى لا تضيع القهوة خلف التحلية.\n⏱ 30s\n\n### 4. ادمج جيدًا\nحرّك أو رجّ المشروب حسب أسلوب التقديم حتى لا يبقى الحليب المكثف (Condensed Milk) أو مزيج التحلية (Sweetening Mix) في قاع الكوب.\n⏱ 15s\n\n### 5. اختبر بعد الثلج\nالتوازن الحقيقي يظهر بعد ذوبان جزء من الثلج، لا في أول رشفة فقط.\n⏱ 20s'),
  ('affogato', 'أفوجاتو', 'drinks', 'مشروبات القهوة', 'الأفوجاتو تجربة حلوى أكثر من كونه مشروبًا. فكرته بسيطة: آيس كريم جيد، وفوقه إسبريسو ساخن. الجمال في التباين بين البارد والساخن، الحلو والمر، الناعم والقوي. إذا كانت جودة الآيس كريم ضعيفة أو جرعة الإسبريسو سيئة، لا يوجد ما يخفي ذلك.', 4.5, ARRAY["حلو"], '1m', 'حلو', '## الفكرة\nآيس كريم مع جرعة إسبريسو (Espresso Shot) ساخنة فوقه\n\n## السر\nالتباين بين حرارة الإسبريسو وبرودة الآيس كريم\n\n## اختيار الآيس كريم\nالفانيلا خيار كلاسيكي لأنه يسمح للقهوة بالظهور\n\n## الإسبريسو\nيجب أن يكون متوازنًا؛ المرارة (Bitterness) الزائدة تفسد الحلوى\n\n## خطأ شائع\nتحضيره مسبقًا فيذوب ويفقد تجربته\n\n## نصيحة عملية\nقدمه فورًا وبكمية إسبريسو لا تغرق الآيس كريم\n\n## لصاحب المقهى\nصنف سهل يرفع قيمة المنيو إذا قُدم بجودة وتصوير جذاب\n\n## مناسب لمن؟\nمن يريد حلوى سريعة بطابع قهوة واضح\n\n## خطوات التحضير\n\n### 1. ضع الآيس كريم\nاستخدم كرة أو كرتين بجودة مناسبة في كوب أو طبق بارد.\n⏱ 10s\n\n### 2. حضّر الإسبريسو\nاستخلص جرعة إسبريسو (Espresso Shot) ساخنة ومتوازنة مباشرة قبل التقديم.\n⏱ 30s\n\n### 3. اسكب فورًا\nاسكب الإسبريسو فوق الآيس كريم أمام العميل إن أمكن.\n⏱ 5s\n\n### 4. قدّم بلا تأخير\nالتجربة تعتمد على التباين، والتأخير يحولها إلى خليط ذائب.\n⏱ 5s'),
  ('filter-coffee', 'قهوة فلتر', 'drinks', 'مشروبات القهوة', 'قهوة الفلتر ليست قهوة سوداء عادية. هي طريقة لإظهار شخصية البن بوضوح: العطر، الحموضة (Acidity)، الحلاوة (Sweetness)، القوام، والنهاية. لا يوجد حليب ولا سكر يخفي العيوب، لذلك جودة البن والطحن والماء والصب تظهر كما هي.', 4.5, ARRAY["نظيفة"], '4m', 'نظيفة', '## الفكرة\nكوب صافي يبرز شخصية البن دون إضافات\n\n## الفرق عن الأمريكيانو\nالفلتر يُحضّر بالترشيح من البداية، أما الأمريكيانو فهو إسبريسو مخفف بالماء\n\n## النسبة العملية\nابدأ بنسبة 1:15 إلى 1:17 بين القهوة والماء ثم عدل حسب الطعم\n\n## الطحن\nمتوسط إلى متوسط خشن حسب الأداة وسرعة النزول\n\n## الماء\nجودة الماء تؤثر مباشرة في الحلاوة (Sweetness) والوضوح\n\n## خطأ شائع\nاعتبارها قهوة خفيفة بلا قيمة لأنها بلا حليب\n\n## نصيحة عملية\nغيّر متغيرًا واحدًا: الطحن أو النسبة أو الحرارة، ولا تغيّرها كلها معًا\n\n## لصاحب المقهى\nقهوة الفلتر تبني ثقة عشاق القهوة المختصة وتحتاج تدريبًا وثباتًا لا مجرد أداة جميلة\n\n## مناسب لمن؟\nعشاق القهوة المختصة ومن يريد تذوق البن كما هو\n\n## خطوات التحضير\n\n### 1. زن القهوة والماء\nاستخدم نسبة واضحة مثل 15g قهوة إلى 250g ماء كبداية.\n⏱ 20s\n\n### 2. اطحن مناسبًا\nابدأ بطحن متوسط وعدل حسب سرعة النزول والطعم.\n⏱ 20s\n\n### 3. اشطف الفلتر\nبلل الفلتر وسخّن الأداة لإزالة طعم الورق وتثبيت الحرارة.\n⏱ 20s\n\n### 4. ابدأ تفتّح القهوة (Bloom)\nاسكب كمية صغيرة من الماء لترطيب القهوة أولًا قبل إكمال الصب.\n⏱ 30s\n\n### 5. أكمل الصب\nاسكب على دفعات هادئة ومتوازنة حتى تصل للوزن المطلوب.\n⏱ 2-3m\n\n### 6. تذوق وسجل\nسجل النسبة والطحن والوقت حتى تستطيع تكرار النتيجة أو تحسينها.\n⏱ 30s'),
  ('v60', 'V60', 'homebrew', 'طرق التحضير', 'الـ V60 ليست مجرد قمع وفلتر. هي طريقة تكشف شخصية البن بوضوح: العطر، الحلاوة (Sweetness)، الحموضة (Acidity)، ونظافة الكوب. قوتها أنها لا تخفي الأخطاء؛ طحن غير مناسب، صب عنيف، ماء بارد، أو وصفة عشوائية ستظهر فورًا في الطعم. الـ V60 الجيدة تبدأ بوصفة بسيطة قابلة للتكرار، ثم تتحسن بالتذوق والتعديل الهادئ: غيّر متغيرًا واحدًا فقط، وافهم لماذا تغير الكوب.', 4.8, ARRAY["متقدم"], '3m', 'متقدم', '## الفكرة\nترشيح يدوي نظيف يبرز شخصية البن بدل إخفائها بالحليب أو السكر\n\n## لماذا مهمة؟\nلأنها تعلّمك العلاقة بين الطحن، الماء، الصب، الوقت، والطعم بطريقة واضحة جدًا\n\n## الوصفة المرجعية\nابدأ بـ 15g قهوة و250g ماء بنسبة قريبة من 1:16.6، ووقت إجمالي بين 2:30 و3:15 دقائق\n\n## درجة الطحن (Grind Size)\nمتوسط إلى متوسط ناعم. النزول السريع غالبًا يعني طحنًا خشنًا، والنزول البطيء جدًا غالبًا يعني طحنًا ناعمًا أو وجود Fine particles كثيرة\n\n## حرارة الماء\nغالبًا 90-96°C. التحميص (Roasting) الفاتح يتحمل حرارة أعلى، والداكن يحتاج حرارة ألطف حتى لا تظهر المرارة (Bitterness)\n\n## تفتّح القهوة (Bloom)\nأول صبة صغيرة لترطيب القهوة قبل إكمال الصب؛ تساعد القهوة على إطلاق الغازات وتهيئ السطح لاستخلاص (Extraction) أهدأ وأكثر توازنًا\n\n## نسبة ماء التفتّح\nاستخدم ماءً يعادل ضعفي إلى ثلاثة أضعاف وزن القهوة تقريبًا، مثل 40-50g ماء مع 15g قهوة\n\n## الصب\nالصب الهادئ المتوازن أهم من الحركات الاستعراضية. الهدف أن تبلل القهوة بالتساوي دون حفر السطح أو ضرب الحواف\n\n## وقت النزول\nإذا انتهى الكوب قبل 2:15 غالبًا سيكون خفيفًا أو حامضًا؛ وإذا تجاوز 3:30 قد يظهر جفاف أو مرارة حسب البن والطحن\n\n## تعديل الطعم\nحامض وضعيف؟ جرّب طحنًا أنعم أو حرارة أعلى. مر وجاف؟ جرّب طحنًا أخشن أو حرارة أقل أو قلل التحريك\n\n## خطأ شائع\nتغيير الطحن والنسبة والحرارة وطريقة الصب في نفس التجربة ثم عدم معرفة سبب التحسن أو الفشل\n\n## نصيحة عملية\nسجّل الوصفة: البن، الجرعة، الماء، الحرارة، الطحن، الوقت، وملاحظتك عن الطعم. الذاكرة وحدها لا تكفي\n\n## لصاحب المقهى\nالـ V60 يرفع قيمة التجربة ويعطي العميل إحساسًا بالقهوة المختصة، لكنه يحتاج تدريبًا وثباتًا حتى لا يصبح بطيئًا أو متذبذب الجودة\n\n## مناسب لمن؟\nلمحبي القهوة المختصة، ولمن يريد كوبًا نظيفًا عطريًا، ولمن يحب فهم أثر كل تفصيلة في التحضير\n\n## خطوات التحضير\n\n### 1. تسخين الماء\nابدأ بماء جيد وطازج. اختر حرارة تقريبية بين 90-96°C حسب التحميص (Roasting)؛ الفاتح أعلى، والداكن ألطف.\n⏱ 30s\n\n### 2. تركيب الفلتر وترطيبه\nضع الفلتر الورقي داخل الـ V60 واشطفه جيدًا بماء ساخن لإزالة طعم الورق وتسخين الأداة والسيرفر.\n⏱ 25s\n\n### 3. وزن القهوة\nابدأ بجرعة 15g قهوة. لا تعتمد على الملعقة أو العين؛ الدقة هنا تصنع فرقًا واضحًا في الطعم.\n⏱ 10s\n\n### 4. ضبط الطحن\nاطحن بدرجة متوسطة إلى متوسطة ناعمة. لو انتهى التحضير بسرعة اجعل الطحن أنعم، ولو طال جدًا اجعله أخشن.\n⏱ 20s\n\n### 5. إضافة القهوة وتسوية السطح\nضع القهوة داخل الفلتر وسوّ السطح بهزة خفيفة. السطح المتساوي يساعد الماء على المرور بشكل أهدأ.\n⏱ 10s\n\n### 6. تفتّح القهوة (Bloom)\nاسكب 40-50g ماء بهدوء حتى تبتل كل القهوة، ثم انتظر 30-45 ثانية. هذه الخطوة تقلل الفوضى في بداية الاستخلاص (Extraction).\n⏱ 30-45s\n\n### 7. الصبة الأولى\nارفع الوزن إلى 120g تقريبًا بصب دائري هادئ من الوسط إلى الخارج دون ضرب حواف الفلتر.\n⏱ 25-30s\n\n### 8. الصبة الثانية\nارفع الوزن إلى 190g تقريبًا. حافظ على مستوى ماء متوسط فوق القهوة ولا تغرق السطح دفعة واحدة.\n⏱ 30-35s\n\n### 9. الصبة الأخيرة\nأكمل إلى 250g ثم اترك القهوة تنزل بهدوء. لا تكثر التحريك إذا لم تكن تعرف أثره على الطعم.\n⏱ 45-60s\n\n### 10. مراقبة وقت النزول\nاستهدف وقتًا إجماليًا قريبًا من 2:30 إلى 3:15. الوقت ليس حكمًا نهائيًا، لكنه مؤشر يساعدك على فهم النتيجة.\n⏱ 15s\n\n### 11. التذوق والتعديل\nإذا كان الكوب حامضًا وضعيفًا فكر في طحن أنعم أو حرارة أعلى. إذا كان مرًا وجافًا فكر في طحن أخشن أو حرارة أقل.\n⏱ 30s\n\n### 12. تثبيت الوصفة\nعندما تصل إلى كوب جميل، سجّل الوصفة ولا تغيّر كل شيء في المرة التالية. الثبات هو الفرق بين تجربة ناجحة وتجربة عشوائية.\n⏱ 15s'),
  ('chemex', 'كيميكس', 'homebrew', 'طرق التحضير', 'الكيميكس ليست مجرد إبريق أنيق للتقديم. قوتها في الفلتر السميك الذي يحبس كثيرًا من الزيوت والجزيئات الدقيقة، فيعطي كوبًا شديد النظافة ووضوحًا عاليًا في العطر والطعم. لكنها لا تجاملك: طحن ناعم جدًا، صب سريع بلا خطة، أو فلتر غير مشطوف جيدًا سيظهر فورًا في الكوب. إذا ضُبطت وصفتها، تعطي قهوة نظيفة وهادئة ومناسبة للبن العطري والفواكهي.', 4.7, ARRAY["نظيف"], '5m', 'نظيف', '## الفكرة\nترشيح نظيف جدًا بفضل الفلتر السميك وشكل الإبريق المخروطي\n\n## لماذا مهمة؟\nلأنها تعطيك كوبًا أنظف من كثير من الطرق وتكشف العطر بوضوح كبير\n\n## الوصفة المرجعية\nابدأ بـ 30g قهوة و500g ماء بنسبة قريبة من 1:16.5 ووقت إجمالي بين 4:30 و5:30 دقائق\n\n## درجة الطحن (Grind Size)\nمتوسط مائل للخشونة؛ الناعم جدًا قد يخنق الفلتر ويبطئ النزول أكثر من اللازم\n\n## حرارة الماء\nغالبًا 92-95°C مناسبة كبداية، ويمكن رفعها قليلًا مع التحميص (Roasting) الفاتح\n\n## الفلتر\nاشطف الفلتر جيدًا بماء ساخن لأن سماكته قد تترك طعم ورق واضح إذا أهملته\n\n## القوام\nأخف جسمًا من الفرنش برس وغالبًا أنظف من V60 بسبب سماكة الفلتر\n\n## الصب\nالصب على دفعات أوضح وأهدأ من ملء الأداة دفعة واحدة؛ الهدف ثبات النزول لا الاستعراض\n\n## وقت النزول\nإذا تجاوز النزول وقتًا طويلًا جدًا فكر في طحن أخشن أو تقليل التحريك\n\n## تعديل الطعم\nإذا كان الكوب باهتًا جرّب طحنًا أنعم أو حرارة أعلى، وإذا كان مرًا وجافًا جرّب طحنًا أخشن\n\n## خطأ شائع\nاستخدام طحن ناعم ثم انتظار نزول طويل جدًا ظنًا أن الوقت الأطول يعني جودة أعلى\n\n## نصيحة عملية\nالكيميكس أداة ضيافة ممتازة، لكن نجاحها يعتمد على الثبات وتسجيل الوصفة لا على شكل الإبريق وحده\n\n## لصاحب المقهى\nممتازة لتجربة تقديم راقية أو جلسة تذوق، لكنها أبطأ من أن تكون حل الذروة لكل الطلبات\n\n## مناسب لمن؟\nلمن يحب القهوة النظيفة والعطرية والمظهر الراقي في التقديم\n\n## خطوات التحضير\n\n### 1. تركيب الفلتر الصحيح\nضع الجهة السميكة من الفلتر عند جهة فتحة الصب حتى يحافظ الفلتر على شكله أثناء التحضير.\n⏱ 15s\n\n### 2. ترطيب الفلتر وتسخين الإبريق\nاشطف الفلتر جيدًا بماء ساخن ثم تخلص من ماء الشطف حتى يزول طعم الورق وتسخن الأداة.\n⏱ 30s\n\n### 3. وزن القهوة\nابدأ بـ 30g قهوة، لأن الكيميكس يتعامل غالبًا مع دفعة أكبر من V60 المعتاد.\n⏱ 10s\n\n### 4. ضبط الطحن\nاطحن بدرجة متوسطة مائلة للخشونة. إذا طال النزول كثيرًا فالغالب أن الطحن ناعم أكثر من اللازم.\n⏱ 20s\n\n### 5. إضافة القهوة وتسوية السطح\nضع القهوة داخل الفلتر وسوّ السطح بهزة خفيفة حتى يتوزع الماء لاحقًا بشكل أفضل.\n⏱ 10s\n\n### 6. تفتّح القهوة (Bloom)\nاسكب 60-80g ماء حتى تبتل القهوة كلها، ثم انتظر 35-45 ثانية لإطلاق الغازات.\n⏱ 35-45s\n\n### 7. الصبة الأولى\nارفع الماء إلى نحو 250g بصب هادئ دائري يحافظ على مستوى ماء متوازن فوق القهوة.\n⏱ 45-60s\n\n### 8. الصبة الثانية\nأكمل إلى 400g تقريبًا، وحافظ على صب مستقر دون ضرب حواف الفلتر أو إغراق السطح دفعة واحدة.\n⏱ 45-60s\n\n### 9. الصبة الأخيرة\nأكمل إلى 500g ثم اترك القهوة تنزل بهدوء حتى نهاية الاستخلاص (Extraction).\n⏱ 45-60s\n\n### 10. مراقبة وقت النزول\nاستهدف وقتًا إجماليًا قريبًا من 4:30 إلى 5:30 دقائق. البطء الزائد قد يعني طحنًا ناعمًا أو فلترًا مزدحمًا بجزيئات دقيقة.\n⏱ 20s\n\n### 11. تحريك الإبريق والتقديم\nحرّك الإبريق برفق لتجانس الاستخلاص (Extraction) ثم قدّم القهوة مباشرة حتى لا تبرد وتفقد عطرها.\n⏱ 15s\n\n### 12. تسجيل الوصفة\nسجّل البن، الجرعة، الحرارة، الوقت والطعم. الكيميكس تتحسن كثيرًا حين تتعامل معها كوصفة ثابتة لا كتجربة عشوائية.\n⏱ 15s'),
  ('french-press', 'فرنش برس', 'homebrew', 'طرق التحضير', 'الفرنش برس تعطي كوبًا ممتلئًا وواضح القوام لأن الزيوت والجزيئات الدقيقة تبقى أكثر من طرق الفلتر الورقي. ميزتها أنها بسيطة ومسامحة، لكن هذا لا يعني أن أي وصفة ستنجح. الطحن الناعم جدًا أو الكبس العنيف أو ترك القهوة فوق البن بعد التحضير يحول الكوب إلى مرارة ورواسب مزعجة. إذا فُهمت جيدًا، فهي طريقة ممتازة لمن يحب الجسم الثقيل والسهولة.', 4.7, ARRAY["غني"], '4m', 'غني', '## الفكرة\nطريقة غمر تعطي كوبًا أثقل جسمًا وأوضح قوامًا من كثير من طرق الفلتر\n\n## لماذا مهمة؟\nلأنها تشرح لك أثر الوقت والطحن بوضوح، وتمنحك كوبًا غنيًا دون تعقيد أدوات كثيرة\n\n## الوصفة المرجعية\nابدأ بـ 20g قهوة و300g ماء بنسبة قريبة من 1:15 ووقت غمر أساسه 4 دقائق\n\n## درجة الطحن (Grind Size)\nخشن إلى متوسط خشن؛ الطحن الناعم جدًا يزيد الرواسب ويعطي مرارة وجفافًا\n\n## حرارة الماء\nغالبًا 92-95°C مناسبة كبداية، ويمكن تخفيفها قليلًا مع التحميص (Roasting) الداكن\n\n## القوام\nأثقل من V60 والكيميكس لأن الفلتر المعدني يسمح بمرور زيوت وجزيئات أدق\n\n## التحريك\nتحريك خفيف يكفي؛ التحريك العنيف قد يثير القاع ويزيد العكارة\n\n## الكبس\nالهدف ليس الضغط بقوة، بل إنزال المكبس بهدوء ومن دون إثارة الرواسب\n\n## وقت التقديم\nبعد اكتمال التحضير اسكب فورًا؛ ترك القهوة فوق البن داخل الإبريق يواصل الاستخلاص (Extraction) ويزيد المرارة (Bitterness)\n\n## تعديل الطعم\nإذا كانت القهوة ضعيفة جدًا جرّب طحنًا أنعم قليلًا أو وقتًا أطول، وإذا كانت مرة ومزعجة جرّب طحنًا أخشن أو وقتًا أقل\n\n## خطأ شائع\nالاعتقاد أن الكبس بقوة علامة احتراف، بينما الاحتراف الحقيقي هو ثبات الوصفة ونظافة الكوب\n\n## نصيحة عملية\nإذا أردت كوبًا أنظف اترك القهوة تستقر لحظات إضافية قبل الصب بدل محاولة الكبس العنيف\n\n## لصاحب المقهى\nمناسبة للعروض البسيطة أو الطاولات، لكنها تحتاج وصفة واضحة حتى لا تختلف من باريستا لآخر\n\n## مناسب لمن؟\nلمن يحب القهوة الغنية والقوام الواضح والتحضير السهل في المنزل أو المكتب\n\n## خطوات التحضير\n\n### 1. تسخين الإبريق\nاشطف الفرنش برس بماء ساخن حتى لا تسحب حرارة التحضير من القهوة.\n⏱ 20s\n\n### 2. وزن القهوة\nابدأ بـ 20g قهوة، لأن الدقة في الجرعة تصنع فرقًا حتى في الطرق البسيطة.\n⏱ 10s\n\n### 3. ضبط الطحن\nاطحن بدرجة خشنة أو متوسطة خشنة. الناعم جدًا يعطي رواسب ومرارة أكثر من المطلوب.\n⏱ 20s\n\n### 4. إضافة القهوة\nضع البن المطحون في القاع وسوّ سطحه قليلًا حتى يبتل بالماء بشكل متقارب.\n⏱ 10s\n\n### 5. إضافة الماء\nاسكب 300g ماء بهدوء حتى تغمر كل القهوة، ويمكنك التحريك تحريكًا خفيفًا في البداية فقط.\n⏱ 20s\n\n### 6. بدء الغمر\nاترك القهوة حوالي 4 دقائق دون عبث مبالغ فيه؛ هنا يبدأ الاستخلاص (Extraction) الحقيقي.\n⏱ 4m\n\n### 7. كسر القشرة\nإذا تشكلت قشرة على السطح، اكسرها برفق بملعقة وأزل الرغوة إذا رغبت في كوب أنظف.\n⏱ 15s\n\n### 8. إراحة قصيرة\nاترك القهوة تستقر قليلًا حتى تهبط بعض الجزيئات الدقيقة إلى الأسفل.\n⏱ 30-60s\n\n### 9. إنزال المكبس بهدوء\nاضغط المكبس ببطء وثبات. إذا قاوم بعنف فلا تجبره؛ راجع الطحن في المرة القادمة.\n⏱ 20s\n\n### 10. الصب الفوري\nاسكب القهوة مباشرة في الأكواب أو في سيرفر منفصل حتى لا يستمر الاستخلاص (Extraction) داخل الإبريق.\n⏱ 15s\n\n### 11. التذوق والتعديل\nإذا وجدت مرارة مزعجة فكر في طحن أخشن أو تقليل الوقت، وإذا كان الكوب ضعيفًا جرّب طحنًا أنعم قليلًا.\n⏱ 20s\n\n### 12. تثبيت الوصفة\nعندما تصل إلى كوب جميل سجّل البن والجرعة والطحن والوقت. بساطة الأداة لا تعني ترك الوصفة للصدفة.\n⏱ 15s'),
  ('aeropress', 'أيروبرس', 'homebrew', 'طرق التحضير', 'الأيروبرس أداة صغيرة لكن قدراتها كبيرة. يمكنها أن تعطي كوبًا نظيفًا قريبًا من الفلتر أو كوبًا أقوى وأكثر كثافة حسب النسبة والطحن والوقت وطريقة الضغط. جمالها أنها مرنة، لكن هذه المرونة قد تربك من يغيّر كل شيء دفعة واحدة. البداية الذكية هي وصفة بسيطة قابلة للتكرار، ثم تعديل متغير واحد فقط كل مرة.', 4.7, ARRAY["سريع"], '2m', 'سريع', '## الفكرة\nأداة تجمع الغمر والترشيح مع ضغط خفيف في تجربة سريعة ومرنة\n\n## لماذا مهمة؟\nلأنها مناسبة للمبتدئ في البيت، ومحبوبة للمحترف الذي يريد مساحة واسعة للتجريب\n\n## الوصفة المرجعية\nابدأ بـ 15g قهوة و220g ماء مع وقت إجمالي قريب من 1:45 إلى 2:15 دقيقة\n\n## درجة الطحن (Grind Size)\nمتوسط إلى متوسط ناعم حسب الوقت والقوة المطلوبة\n\n## حرارة الماء\nغالبًا 85-92°C مع التحميص (Roasting) المتوسط والداكن، ويمكن رفعها قليلًا مع البن الفاتح\n\n## المرونة\nيمكن استخدام الطريقة العادية أو المقلوبة، لكن الأهم أن تثبت على طريقة واحدة أثناء التعلم\n\n## الضغط\nالضغط اللطيف والمتدرج أفضل من الضغط العنيف؛ المقاومة الشديدة تعني غالبًا طحنًا ناعمًا جدًا\n\n## القوام\nأنظف من الفرنش برس، ويمكن أن يكون أوضح أو أثقل بحسب الفلتر والوقت والنسبة\n\n## تعديل الطعم\nإذا كان الكوب ضعيفًا جرّب وقتًا أطول أو طحنًا أنعم، وإذا كان مرًا أو مجففًا جرّب وقتًا أقصر أو طحنًا أخشن\n\n## خطأ شائع\nتغيير الطحن والحرارة والوقت والوضعية معًا ثم عدم معرفة أي متغير سبب النتيجة\n\n## نصيحة عملية\nابدأ بوصفة واحدة أسبوعًا كاملًا، ثم عدّل متغيرًا واحدًا فقط حتى تفهم الأداة فعلاً\n\n## لصاحب المقهى\nممتاز كورشة تعليمية أو تجربة خاصة، لكنه يحتاج نظامًا واضحًا إذا دخل في التشغيل اليومي\n\n## مناسب لمن؟\nللسفر، المكتب، المنزل، ولمن يحب السرعة مع مساحة جيدة للتجريب\n\n## خطوات التحضير\n\n### 1. تركيب الفلتر\nضع الفلتر الورقي في الغطاء واشطفه سريعًا بماء ساخن لتقليل طعم الورق.\n⏱ 10s\n\n### 2. تجهيز الأداة\nركّب الغطاء وثبّت الأيروبرس فوق الكوب أو السيرفر إذا كنت تعمل بالطريقة العادية.\n⏱ 10s\n\n### 3. وزن القهوة\nابدأ بـ 15g قهوة. لا تترك الجرعة للتقدير لأن الأيروبرس تستجيب بوضوح لأي فرق بسيط.\n⏱ 10s\n\n### 4. ضبط الطحن\nاطحن بدرجة متوسطة إلى متوسطة ناعمة. إذا كانت المقاومة عالية جدًا وقت الضغط فكر في طحن أخشن.\n⏱ 15s\n\n### 5. إضافة القهوة والماء\nأضف القهوة ثم اسكب 220g ماء بسرعة معقولة حتى تبتل كل القهوة.\n⏱ 15s\n\n### 6. تحريك خفيف\nحرّك 5 إلى 10 ثوانٍ فقط لتوحيد التبلل دون مبالغة.\n⏱ 10s\n\n### 7. وقت الغمر\nاترك القهوة تتفاعل حوالي 60 إلى 75 ثانية بحسب الوصفة التي تعتمدها.\n⏱ 60-75s\n\n### 8. تركيب المكبس\nضع المكبس برفق لتكوين ختم خفيف ومنع التنقيط الزائد إذا احتجت ذلك.\n⏱ 5s\n\n### 9. الضغط\nاضغط ببطء وثبات خلال 20 إلى 30 ثانية. لا تحاول إنهاء التحضير بالقوة.\n⏱ 20-30s\n\n### 10. التوقف قبل القاع\nعندما تسمع آخر الهواء بصوت واضح يمكنك التوقف إذا أردت تقليل المرارة (Bitterness) الزائدة من القاع.\n⏱ 5s\n\n### 11. التذوق والتعديل\nإذا كان الكوب ضعيفًا جرّب وقتًا أطول أو طحنًا أنعم، وإذا كان مرًا فكر في وقت أقصر أو حرارة أقل.\n⏱ 20s\n\n### 12. تثبيت الوصفة\nسجّل النسبة والطحن والوقت وطريقة العمل؛ مرونة الأيروبرس جميلة فقط إذا كانت مبنية على مرجع ثابت.\n⏱ 15s'),
  ('moka-pot', 'موكا بوت', 'homebrew', 'طرق التحضير', 'الموكا بوت ليست ماكينة إسبريسو صغيرة، لكنها تستطيع أن تعطي كوبًا قويًا ومركزًا يشبه اتجاه الإسبريسو أكثر من الفلتر. نجاحها يعتمد على فهم بسيط: ماء مناسب في القاعدة، طحن متوسط مائل للنعومة، قهوة في السلة دون كبس، ونار هادئة. أكثر ما يفسدها هو الحرارة العالية التي تحرق القهوة في النهاية وتعطي طعمًا معدنيًا أو مرًا.', 4.6, ARRAY["منزلي"], '5m', 'منزلي', '## الفكرة\nتحضير مركز على النار يعتمد على ضغط البخار لعبور الماء خلال القهوة\n\n## لماذا مهمة؟\nلأنها وسيلة منزلية عملية تعطي كوبًا قويًا ويمكن البناء عليه بالحليب أو الماء\n\n## الوصفة المرجعية\nاملأ السلة قهوة دون كبس، واملأ القاعدة ماءً حتى أسفل الصمام كقاعدة آمنة ومجربة\n\n## درجة الطحن (Grind Size)\nمتوسط مائل للنعومة؛ أنعم من الفلتر وأخشن من الإسبريسو غالبًا\n\n## الماء\nيفضل كثير من الباريستا استخدام ماء ساخن مسبقًا لتقليل تعرض القهوة لحرارة زائدة أثناء البداية\n\n## الحرارة\nالنار الهادئة أو المتوسطة المنخفضة أفضل من اللهب العالي الذي يسرّع الاستخلاص (Extraction) ويفسد التوازن\n\n## القوام\nأقوى من الفلتر وأخف من الإسبريسو الحقيقي، لكنه ممتاز للمشروبات المنزلية المركزة\n\n## المرارة (Bitterness)\nغالبًا تأتي من حرارة زائدة أو استمرار الأداة على النار بعد بدء الشفط النهائي\n\n## تعديل الطعم\nإذا كان الكوب حادًا ومزعجًا جرّب طحنًا أخشن أو نارًا أهدأ، وإذا كان ضعيفًا جدًا جرّب طحنًا أنعم قليلًا\n\n## خطأ شائع\nكبس القهوة في السلة كما لو كانت بورتافلتر؛ هذا يعيق الجريان ويعطي طعمًا سيئًا\n\n## نصيحة عملية\nأبعد الأداة عن النار فور سماع صوت الفقاعات النهائية حتى لا يتحول آخر الاستخلاص (Extraction) إلى مرارة\n\n## لصاحب المقهى\nليست أداة تشغيل رئيسية عادة، لكنها مفيدة في التعليم أو في محتوى يشرح الفروق بين طرق التحضير\n\n## مناسب لمن؟\nلمن يحب القهوة القوية في البيت ويريد أساسًا جيدًا لمشروبات بالحليب أو الماء\n\n## خطوات التحضير\n\n### 1. تجهيز القاعدة\nاملأ الجزء السفلي بالماء حتى أسفل الصمام مباشرة، ولا تتجاوزه.\n⏱ 15s\n\n### 2. تسخين الماء مسبقًا\nاستخدام ماء ساخن يساعد على تقليل الوقت الذي تتعرض فيه القهوة لحرارة زائدة.\n⏱ 20s\n\n### 3. وزن القهوة\nاستخدم كمية تناسب سلة الأداة، عادة بين 15 و18g في الأحجام الصغيرة المتوسطة.\n⏱ 10s\n\n### 4. ضبط الطحن\nاطحن بدرجة متوسطة مائلة للنعومة؛ الناعم جدًا قد يخنق الأداة، والخشن جدًا يعطي كوبًا ضعيفًا.\n⏱ 20s\n\n### 5. ملء السلة\nاملأ السلة وسوّ السطح برفق دون كبس. الموكا بوت لا تريد ضغطًا مثل الإسبريسو.\n⏱ 15s\n\n### 6. تركيب الأداة بإحكام\nأغلق الموكا بوت بإحكام مع الانتباه لحرارة القاعدة إذا استخدمت ماءً ساخنًا.\n⏱ 10s\n\n### 7. وضعها على نار هادئة\nاستخدم حرارة هادئة أو متوسطة منخفضة، ويفضل ترك الغطاء مرفوعًا للمراقبة.\n⏱ 60-90s\n\n### 8. مراقبة الجريان\nعندما تبدأ القهوة بالخروج يجب أن يكون الجريان متوازنًا لا انفجاريًا.\n⏱ 20s\n\n### 9. إبعادها قبل النهاية\nعند اقتراب اللون من الشحوب أو بداية صوت الفرقعة أبعدها فورًا عن النار.\n⏱ 10s\n\n### 10. إيقاف الاستخلاص (Extraction)\nيمكن تبريد الجزء السفلي سريعًا بمنشفة باردة أو ماء بارد لإيقاف الاستخلاص (Extraction) الزائد إذا رغبت.\n⏱ 10s\n\n### 11. تحريك القهوة والتقديم\nحرّك السائل داخل الجزء العلوي قليلًا لتجانس الطبقات ثم قدّم مباشرة.\n⏱ 10s\n\n### 12. التذوق والتعديل\nإذا ظهر طعم حاد أو محترق فكر في نار أهدأ أو طحن أخشن، وإذا كان خفيفًا جدًا فكر في طحن أنعم قليلًا.\n⏱ 20s'),
  ('turkish-coffee', 'قهوة تركية', 'homebrew', 'طرق التحضير', 'القهوة التركية من أكثر طرق التحضير حساسية في أبسط تفاصيلها. جمالها في الرغوة، العطر، وثقل القوام، لكن هذه النتيجة لا تأتي من الغليان العنيف أو التقدير العشوائي. السر الحقيقي هو طحن ناعم جدًا، جرعة متوازنة، تسخين هادئ، وفهم متى ترفع الركوة قبل أن تفسد الرغوة ويتحول الكوب إلى مرارة قاسية.', 4.7, ARRAY["ناعمة جدًا"], '5m', 'ناعمة جدًا', '## الفكرة\nتحضير ناعم جدًا داخل ركوة من دون ترشيح، يعطي قوامًا واضحًا ورغوة مميزة\n\n## لماذا مهمة؟\nلأنها جزء من ثقافة القهوة في المنطقة، وتحتاج فهمًا بسيطًا لكن دقيقًا جدًا\n\n## الوصفة المرجعية\nابدأ بحوالي 7g قهوة إلى 60-70ml ماء لكل فنجان كقاعدة عملية\n\n## درجة الطحن (Grind Size)\nناعم جدًا مثل البودرة تقريبًا؛ أي خشونة واضحة ستفقد القوام والرغوة المطلوبة\n\n## السكر\nإن أردت السكر فأضفه في البداية مع الماء والقهوة، لا بعد التحضير\n\n## الحرارة\nالنار الهادئة أهم من السرعة؛ الغليان العنيف يقتل الرغوة ويظهر مرارة أقسى\n\n## الرغوة\nليست مجرد شكل جميل؛ هي علامة على تعامل هادئ وصحيح مع بداية التحضير\n\n## القوام\nأثقل من الفلتر لأن البن يبقى في الفنجان، لذلك التقديم الهادئ مهم جدًا\n\n## تعديل الطعم\nإذا كانت القهوة خفيفة جدًا فكر في زيادة البن قليلًا، وإذا كانت مرة وخشنة فكر في حرارة ألطف أو بن أقل\n\n## خطأ شائع\nترك الركوة تغلي بعنف عدة مرات ظنًا أن ذلك يزيد الجودة، بينما هو غالبًا يفسدها\n\n## نصيحة عملية\nدع البن يترسب قليلًا بعد الصب قبل الشرب، ولا تحرّك الفنجان بعشوائية\n\n## لصاحب المقهى\nنجاح القهوة التركية يعتمد على الثبات في الجرعة والنار والزمن أكثر من الزينة الخارجية\n\n## مناسب لمن؟\nلمن يحب القوام الواضح والطابع التقليدي والعطر المركز في فنجان صغير\n\n## خطوات التحضير\n\n### 1. وزن الماء\nابدأ بقياس 60-70ml ماء لكل فنجان بدل التقدير العشوائي.\n⏱ 10s\n\n### 2. إضافة القهوة\nأضف نحو 7g قهوة مطحونة ناعمًا جدًا لكل فنجان إلى الركوة.\n⏱ 10s\n\n### 3. إضافة السكر عند الحاجة\nإذا رغبت بالسكر فأضفه الآن قبل التسخين حتى يذوب مع القهوة.\n⏱ 5s\n\n### 4. الخلط البارد\nحرّك المكونات وهي باردة أو فاترة حتى تتجانس قبل وضع الركوة على النار.\n⏱ 10s\n\n### 5. بدء التسخين الهادئ\nضع الركوة على نار هادئة جدًا. الهدف رفع الحرارة تدريجيًا لا غليانًا سريعًا.\n⏱ 60-90s\n\n### 6. مراقبة الرغوة\nعندما تبدأ الرغوة بالصعود اقتربت اللحظة المهمة؛ لا تتركها تنفجر أو تغلي بقوة.\n⏱ 20s\n\n### 7. رفع الركوة في اللحظة المناسبة\nارفعها عندما ترتفع الرغوة قبل الانفجار، ويمكنك توزيع جزء من الرغوة في الفناجين إذا رغبت.\n⏱ 10s\n\n### 8. إعادة هادئة عند الحاجة\nإذا كانت وصفتك تعتمد رفعًا ثانيًا فافعل ذلك بلطف ومن دون غليان عنيف.\n⏱ 20s\n\n### 9. الصب بهدوء\nاسكب القهوة في الفناجين بهدوء حتى لا تنهار الرغوة بالكامل ولا تثار الرواسب بسرعة.\n⏱ 10s\n\n### 10. انتظار الترسيب\nامنح القهوة نصف دقيقة تقريبًا حتى يهدأ البن في القاع ويصفو السطح.\n⏱ 30s\n\n### 11. التذوق والتعديل\nإذا كانت مرة وقاسية ففكر في نار أهدأ أو جرعة أخف، وإذا كانت خفيفة ففكر في جرعة أعلى قليلًا.\n⏱ 20s\n\n### 12. تثبيت الوصفة\nسجّل كمية الماء والبن ونوع السكر والزمن التقريبي. الثبات هو سر القهوة التركية الجيدة.\n⏱ 15s'),
  ('clever-dripper', 'كليفر دريبر', 'homebrew', 'طرق التحضير', 'الكليفر دريبر أداة ذكية جدًا لمن يريد كوب فلتر نظيف من دون مهارة صب معقدة. هو يجمع الغمر والترشيح: تنقع القهوة أولًا مثل الفرنش برس، ثم تنزل عبر الفلتر الورقي عند وضع الأداة فوق الكوب. هذه البساطة تمنحه ثباتًا جيدًا، لكنه ما زال يحتاج وصفة واضحة في الوقت والطحن حتى لا يتحول إلى مرارة أو كوب باهت.', 4.7, ARRAY["متوازن"], '3m', 'متوازن', '## الفكرة\nغمر يليه ترشيح ورقي، لذلك يجمع سهولة الفرنش برس ونظافة الفلتر\n\n## لماذا مهمة؟\nلأنها تمنح المبتدئ نتائج مستقرة من دون القلق الكبير حول حركات الصب اليدوي\n\n## الوصفة المرجعية\nابدأ بـ 18g قهوة و300g ماء بنسبة قريبة من 1:16.5 ووقت إجمالي بين 2:30 و3:30 دقائق\n\n## درجة الطحن (Grind Size)\nمتوسط؛ أنعم قليلًا من كيميكس وأخشن من الإسبريسو بمسافة كبيرة\n\n## حرارة الماء\nغالبًا 92-95°C مناسبة كبداية، ويمكن تعديلها حسب التحميص (Roasting) والطعم\n\n## الميزة\nثبات أعلى من بعض طرق الصب لأن القهوة تنقع أولًا ولا تعتمد بالكامل على مهارة الصب\n\n## القوام\nأنظف من الفرنش برس وأكثر امتلاءً قليلًا من بعض وصفات V60 حسب النسبة\n\n## وقت الفتح\nتأخير فتح الصمام يزيد الاستخلاص (Extraction)؛ لذلك التوقيت هنا مؤثر بوضوح على الطعم\n\n## تعديل الطعم\nإذا كانت القهوة ضعيفة جرّب وقتًا أطول أو طحنًا أنعم قليلًا، وإذا كانت مرة جرّب وقتًا أقل أو طحنًا أخشن\n\n## خطأ شائع\nنسيان القهوة داخل الأداة مدة طويلة ثم لوم البن على الجفاف والمرارة (Bitterness)\n\n## نصيحة عملية\nابدأ المؤقت من أول صبة، وافتح الصمام في نفس اللحظة كل مرة حتى تبني مرجعًا ثابتًا\n\n## لصاحب المقهى\nممتازة للتدريب أو لتقديم فلتر ثابت لفريق غير خبير في الصب اليدوي\n\n## مناسب لمن؟\nللمبتدئ الذي يريد كوبًا نظيفًا وسهل التكرار دون تعقيد كبير\n\n## خطوات التحضير\n\n### 1. تركيب الفلتر وترطيبه\nضع الفلتر الورقي داخل الكليفر واشطفه جيدًا بماء ساخن.\n⏱ 20s\n\n### 2. تسخين الكوب أو السيرفر\nالتسخين المسبق يساعد على ثبات حرارة الكوب النهائي.\n⏱ 10s\n\n### 3. وزن القهوة\nابدأ بـ 18g قهوة كقاعدة سهلة وواضحة.\n⏱ 10s\n\n### 4. ضبط الطحن\nاستخدم طحنًا متوسطًا. إذا كان السائل يخرج قوي المرارة (Bitterness) فقد تحتاج طحنًا أخشن أو وقتًا أقل.\n⏱ 15s\n\n### 5. إضافة القهوة\nضع القهوة في الأداة وسوّ السطح برفق.\n⏱ 10s\n\n### 6. إضافة الماء كاملًا\nاسكب 300g ماء فوق القهوة وتأكد من التبلل الكامل.\n⏱ 20s\n\n### 7. تحريك خفيف\nحرّك مرة أو مرتين فقط لتوحيد التبلل من دون إثارة مبالغ فيها.\n⏱ 10s\n\n### 8. بدء الغمر\nاترك القهوة تنقع 2:00 إلى 2:30 دقيقة تقريبًا كبداية عملية.\n⏱ 2-2.5m\n\n### 9. فتح الصمام\nضع الكليفر فوق الكوب أو السيرفر ليبدأ النزول عبر الفلتر.\n⏱ 45-60s\n\n### 10. مراقبة وقت النزول\nإذا طال النزول كثيرًا فقد يكون الطحن ناعمًا أو الفلتر مزدحمًا بجزيئات دقيقة.\n⏱ 20s\n\n### 11. التذوق والتعديل\nإذا كانت القهوة ضعيفة زد وقت الغمر أو نعّم الطحن قليلًا، وإذا كانت مرة قلل الوقت أو اخشن الطحن.\n⏱ 20s\n\n### 12. تثبيت الوصفة\nعندما تصل إلى توازن جميل ثبّت وقت الفتح والطحن والجرعة. هذا ما يجعل الكليفر أداة ثقة يومية.\n⏱ 15s'),
  ('batch-brew', 'باتش برو', 'homebrew', 'طرق التحضير', 'الباتش برو في المقهى ليس قهوة كسولة ولا بديلًا رخيصًا عن التحضير اليدوي. إذا عُيّر جيدًا فهو من أفضل الطرق لتقديم قهوة سوداء ثابتة بسرعة في أوقات الذروة. قيمته الحقيقية في الثبات: وصفة واضحة، طحن مضبوط، تذوق يومي، وتحديد زمن صالح لبيع الدفعة قبل أن تبهت. من يهمله يظلم قسم القهوة السوداء كاملًا في المقهى.', 4.6, ARRAY["عملي"], '6m', 'عملي', '## الفكرة\nتحضير فلتر بكميات أكبر لتقديم سريع وثابت في المقهى\n\n## لماذا مهمة؟\nلأنها توفر سرعة الخدمة مع جودة مستقرة إذا كانت الوصفة والمعايرة واضحة\n\n## الوصفة المرجعية\nابدأ بنسبة قريبة من 1:15 إلى 1:17 حسب البن وحجم الدفعة وطبيعة المعدة\n\n## الطحن\nيضبط حسب حجم الدفعة ووقت نزول الماكينة؛ دفعة 2 لتر ليست مثل دفعة صغيرة\n\n## الماء\nجودة الماء وحرارته وثباتهما تؤثر مباشرة في الحلاوة (Sweetness) والوضوح تمامًا كما في التحضير اليدوي\n\n## الثبات\nنجاح الباتش برو ليس في تشغيل الزر، بل في تكرار نفس الكوب على مدار اليوم\n\n## الحفظ\nالقهوة لا تبقى ممتازة لساعات بلا حد؛ لا بد من زمن صلاحية واضح بعد التحضير\n\n## التذوق\nيجب تذوق أول دفعة من اليوم وأي دفعة بعد تغيير البن أو الطحن أو تنظيف المعدة\n\n## تعديل الطعم\nإذا كانت القهوة ضعيفة فكر في طحن أنعم أو نسبة أقوى، وإذا كانت مرة وجافة فكر في طحن أخشن أو نسبة ألطف\n\n## خطأ شائع\nاعتبار الباتش برو أقل أهمية من اليدوي، ثم تركه دون معايرة أو متابعة جودة\n\n## نصيحة عملية\nاكتب بطاقة داخلية لكل بن: الجرعة، الماء، وقت النزول، ومدة الصلاحية في السيرفر\n\n## لصاحب المقهى\nممتاز للذروة ورفع سرعة الخدمة بشرط الانضباط في التشغيل وعدم بيع قهوة باهتة للعميل\n\n## مناسب لمن؟\nللمقاهي التي تريد خدمة سريعة لقهوة سوداء جيدة وثابتة لا تعتمد على المزاج اللحظي للباريستا\n\n## خطوات التحضير\n\n### 1. تنظيف المعدة والسيرفر\nابدأ بإزالة أي بقايا قديمة لأن القهوة السوداء تكشف العيوب سريعًا.\n⏱ 30s\n\n### 2. وزن القهوة\nحدد جرعة واضحة حسب حجم الدفعة. لا تعتمد على التقدير أو المكيال العام.\n⏱ 20s\n\n### 3. وزن الماء أو حجم الدفعة\nاختر هدفًا واضحًا لحجم التحضير ثم اربطه بنسبة قهوة معلومة.\n⏱ 20s\n\n### 4. ضبط الطحن\nراجع الطحن يوميًا؛ الرطوبة والبن الجديد قد يغيران النتيجة حتى لو بقيت الوصفة نفسها.\n⏱ 30s\n\n### 5. تركيب الفلتر\nتأكد أن الفلتر مناسب ومثبت جيدًا حتى لا يتأثر الجريان أو النظافة.\n⏱ 15s\n\n### 6. بدء التحضير\nشغّل الدفعة وتابع بداية التوزيع المائي والزمن العام للمعدة.\n⏱ 3-5m\n\n### 7. مراقبة وقت النزول\nالزمن مؤشر مهم؛ الاختصار الشديد أو البطء الشديد يستحقان مراجعة الطحن أو الوصفة.\n⏱ 20s\n\n### 8. تذوق أول دفعة\nلا تقدم أول دفعة للعميل قبل أن تتذوقها وتفهم توازنها.\n⏱ 20s\n\n### 9. تدوين الملاحظات\nسجّل البن، الجرعة، الماء، الزمن، والانطباع الحسي حتى لا تعيد نفس الخطأ لاحقًا.\n⏱ 20s\n\n### 10. تحديد مدة الصلاحية\nضع قاعدة واضحة: كم دقيقة تبقى الدفعة صالحة للبيع قبل أن تستبدل؟\n⏱ 10s\n\n### 11. تقديم منظم\nحرّك السيرفر بلطف قبل التقديم للحفاظ على تجانس السائل بين أول وآخر كوب.\n⏱ 10s\n\n### 12. مراجعة أثناء اليوم\nإذا تغير الطقس أو البن أو حجم الطلبات، راجع الجودة ولا تفترض أن الإعداد الصباحي يكفي لليوم كله.\n⏱ 20s'),
  ('iced-filter', 'فلتر مثلج', 'homebrew', 'طرق التحضير', 'الفلتر المثلج ليس قهوة ساخنة عادية أضفت لها ثلجًا في النهاية. الفكرة الأدق أن تحسب الثلج جزءًا من إجمالي الماء، ثم تحضّر القهوة ساخنة ومركزة قليلًا فوقه حتى تبرد فورًا وتحافظ على العطر والنظافة. إذا تجاهلت هذه الفكرة ستخرج بنتيجة مخففة وباهتة. وإذا فهمتها جيدًا ستحصل على كوب بارد سريع ومنعش وواضح الطعم.', 4.7, ARRAY["بارد"], '3m', 'بارد', '## الفكرة\nتحضير فلتر ساخن مركز قليلًا فوق ثلج محسوب ضمن الوصفة النهائية\n\n## لماذا مهمة؟\nلأنها تعطيك قهوة باردة نظيفة وعطرية بسرعة، من دون انتظار ساعات مثل الكولد برو\n\n## الوصفة المرجعية\nابدأ بـ 15g قهوة، 150g ماء ساخن، و100g ثلج ليكون المجموع النهائي 250g تقريبًا\n\n## درجة الطحن (Grind Size)\nغالبًا أنعم قليلًا من V60 الساخن لأن كمية الماء الساخن المستخدمة أقل\n\n## الثلج\nليس إضافة عشوائية؛ هو جزء من نسبة الماء الكلية ويؤثر مباشرة في التوازن النهائي\n\n## الماء\nجودة الماء والثلج مهمة جدًا، لأن أي رائحة أو طعم غير مرغوب يظهر سريعًا في الكوب البارد\n\n## القوام\nأوضح عطرًا من الكولد برو وأكثر انتعاشًا وحيوية في الحموضة (Acidity) إذا كان البن مناسبًا\n\n## الحرارة\nاستخدم ماءً ساخنًا مناسبًا مثل 90-94°C، لكن تذكّر أن جزءًا من التبريد يحدث فور الصب فوق الثلج\n\n## تعديل الطعم\nإذا كان الكوب مخففًا جدًا فكر في تقليل الثلج أو زيادة قوة الاستخلاص (Extraction) الساخن، وإذا كان حادًا جدًا فراجع النسبة أو الطحن\n\n## خطأ شائع\nتحضير فلتر عادي كامل ثم رمي ثلج كثير عليه فيفقد الكوب كل توازنه\n\n## نصيحة عملية\nاستخدم ثلجًا نظيفًا وكبيرًا نسبيًا، لأن الثلج الرديء يذوب بسرعة ويخرب النكهة بسرعة أكبر\n\n## لصاحب المقهى\nمناسب جدًا للمناخ الفلسطيني ويعطي تجربة صيفية ممتازة بشرط ثبات الوصفة وعدم التخفيف العشوائي\n\n## مناسب لمن؟\nلمن يريد قهوة باردة سريعة وعطرية من دون انتظار طويل أو طعم باهت\n\n## خطوات التحضير\n\n### 1. وزن الثلج\nضع 100g ثلج في السيرفر أو الكوب كجزء أساسي من الوصفة، لا كزينة لاحقة.\n⏱ 10s\n\n### 2. تركيب الفلتر وشطفه\nاشطف الفلتر وسخّن الأداة جيدًا، ثم تخلص من ماء الشطف قبل وضع الأداة فوق الثلج.\n⏱ 20s\n\n### 3. وزن القهوة\nابدأ بـ 15g قهوة كبداية متوازنة لكوب بارد واضح.\n⏱ 10s\n\n### 4. ضبط الطحن\nاستخدم طحنًا متوسطًا مائلًا للنعومة قليلًا مقارنة ببعض وصفات V60 الساخن.\n⏱ 15s\n\n### 5. إضافة القهوة وتسوية السطح\nضع القهوة في الفلتر وسوّ السطح حتى يمر الماء بشكل متقارب.\n⏱ 10s\n\n### 6. تفتّح القهوة (Bloom)\nاسكب 35-45g ماء ساخن واترك القهوة 30-40 ثانية حتى تتحرر الغازات.\n⏱ 30-40s\n\n### 7. الصبة الأولى\nارفع الوزن إلى نحو 100g ماء ساخن مع صب هادئ ومتوازن.\n⏱ 25-30s\n\n### 8. الصبة الأخيرة\nأكمل إلى 150g ماء ساخن ثم اترك القهوة تنزل فوق الثلج مباشرة.\n⏱ 35-45s\n\n### 9. تحريك السيرفر\nبعد اكتمال التحضير حرّك السائل مع الثلج بلطف حتى تتوزع البرودة ويتجانس الكوب.\n⏱ 10s\n\n### 10. مراقبة التخفيف\nإذا ذاب الثلج بسرعة كبيرة قبل التقديم فقد تحتاج مراجعة حجمه أو سرعة العمل.\n⏱ 10s\n\n### 11. التذوق والتعديل\nإذا كان الكوب مخففًا جدًا فكر في طحن أنعم أو تقليل الثلج، وإذا كان حادًا جدًا فكر في ماء أكثر أو طحن أخشن قليلًا.\n⏱ 20s\n\n### 12. التقديم السريع\nقدّم القهوة المثلجة فورًا لتحافظ على العطر والانتعاش قبل أن يتغير التوازن بزيادة الذوبان.\n⏱ 10s'),
  ('siphon', 'سايفون', 'homebrew', 'طرق التحضير', 'السايفون طريقة تحضير مسرحية وجذابة، لكنها ليست مجرد عرض بصري. هي طريقة تعتمد ضغط البخار ثم السحب عبر الفلتر، ويمكنها أن تعطي كوبًا نظيفًا وعطريًا إذا فُهمت جيدًا. لكنها تتطلب انتباهًا أكثر من الطرق اليومية السريعة: ثبات في الحرارة، توقيت صحيح، نظافة جيدة، وفهم متى تحرّك ومتى تترك الأداة تعمل بهدوء.', 4.7, ARRAY["استعراضي"], '6m', 'استعراضي', '## الفكرة\nتحضير بالبخار والضغط ثم السحب عبر فلتر، يعطي تجربة بصرية وكوبًا عطريًا نظيفًا\n\n## لماذا مهمة؟\nلأنها تجمع بين التعليم والعرض الحي وتكشف أثر الحرارة والتوقيت بوضوح\n\n## الوصفة المرجعية\nابدأ بـ 20g قهوة و300g ماء بنسبة قريبة من 1:15 ووقت إجمالي نحو 5 إلى 6 دقائق\n\n## درجة الطحن (Grind Size)\nمتوسط؛ الناعم جدًا قد يبطئ السحب النهائي، والخشن جدًا قد يعطي كوبًا ضعيفًا\n\n## الحرارة\nالهدف حرارة مستقرة لا غليان عشوائي. التحكم هنا أهم من القوة\n\n## الفلتر\nنظافة الفلتر والزجاج جزء من جودة الكوب لا مجرد شكل خارجي\n\n## القوام\nغالبًا أنظف من الفرنش برس وأقرب للوضوح مع جسم متوسط وعطر جميل\n\n## التحريك\nالتحريك الزائد قد يرفع الرواسب ويؤثر في صفاء السحب؛ يكفي تحريك محسوب ومقصود\n\n## وقت السحب\nإذا كان الرجوع للأسفل بطيئًا جدًا فراجع الطحن أو نظافة الفلتر أو طريقة التحريك\n\n## تعديل الطعم\nإذا كان الكوب ضعيفًا فكر في وقت أطول أو طحن أنعم قليلًا، وإذا كان جافًا فكر في وقت أقل أو طحن أخشن\n\n## خطأ شائع\nاستخدام السايفون كعرض فقط من دون تدريب فعلي على الوصفة والتوقيت والنظافة\n\n## نصيحة عملية\nاحفظ وصفة واحدة أولًا وكررها بإتقان قبل الانتقال إلى التجارب الاستعراضية المعقدة\n\n## لصاحب المقهى\nمثالي للدورات والتجارب الخاصة والطاولات التفاعلية، لكنه يحتاج فريقًا مدربًا وليس مناسبًا لكل لحظة زحام\n\n## مناسب لمن؟\nللمهتمين بالتجربة البصرية والعطرية ولمن يريد وسيلة تعليمية مميزة في القهوة المختصة\n\n## خطوات التحضير\n\n### 1. تركيب الفلتر جيدًا\nثبّت فلتر السايفون داخل الجزء العلوي وتأكد أنه مشدود في مكانه بشكل صحيح.\n⏱ 20s\n\n### 2. إضافة الماء\nضع 300g ماء في الوعاء السفلي كبداية عملية لوصفة واضحة.\n⏱ 10s\n\n### 3. بدء التسخين\nابدأ التسخين حتى يصعد معظم الماء إلى الوعاء العلوي بفعل ضغط البخار.\n⏱ 90-120s\n\n### 4. وزن القهوة\nجهّز 20g قهوة بطحن متوسط، لأن الدقة هنا مهمة لتوازن الوصفة.\n⏱ 10s\n\n### 5. إضافة القهوة في الوعاء العلوي\nعندما يستقر الماء في الأعلى أضف القهوة برفق داخل الوعاء العلوي.\n⏱ 10s\n\n### 6. تحريك أولي محسوب\nحرّك مرة أو مرتين فقط لتتبلل القهوة كلها من دون إثارة مبالغ فيها.\n⏱ 10s\n\n### 7. وقت الاستخلاص (Extraction)\nاترك القهوة تتفاعل نحو 45 إلى 60 ثانية حسب البن والنتيجة المطلوبة.\n⏱ 45-60s\n\n### 8. إبعاد الحرارة\nأزل مصدر الحرارة في الوقت المناسب ليبدأ السحب إلى الأسفل عبر الفلتر.\n⏱ 10s\n\n### 9. مراقبة السحب\nراقب عودة القهوة إلى الوعاء السفلي؛ السحب السلس علامة جيدة على التوازن والنظافة.\n⏱ 45-60s\n\n### 10. تقييم السرعة\nإذا كان السحب بطيئًا جدًا ففكر في طحن أخشن أو فلتر أنظف أو تحريك أقل في المرة القادمة.\n⏱ 15s\n\n### 11. تحريك الوعاء السفلي بلطف\nبعد اكتمال السحب يمكنك تحريك الوعاء السفلي برفق لتجانس السائل قبل التقديم.\n⏱ 10s\n\n### 12. التقديم والتنظيف\nقدّم القهوة مباشرة ثم نظف الأداة سريعًا؛ بقايا الزيوت في السايفون تؤثر لاحقًا في الطعم والمظهر.\n⏱ 30s'),
  ('coffee-grinder', 'مطحنة القهوة', 'equipment', 'معدات المقهى', 'المطحنة ليست قطعة جانبية في بار القهوة. هي المعدة التي قد ترفع جودة الكوب أو تفسدها قبل أن يبدأ التحضير. ماكينة إسبريسو قوية مع طحن غير ثابت ستعطي نتائج متذبذبة، بينما مطحنة جيدة تجعل الوصفة قابلة للتكرار. في المقهى المختص تحديدًا، السؤال ليس فقط: أي مطحنة أشتري؟ بل: كم مطحنة أحتاج؟ ولماذا أفصل بين الإسبريسو والفلتر أو البن المتغير؟', 4.9, ARRAY["أساسي"], '—', 'أساسي', '## الفكرة\nالمطحنة تتحكم في حجم جزيئات القهوة، وبالتالي تتحكم مباشرة في سرعة الاستخلاص (Extraction) والطعم والثبات\n\n## لماذا مهمة؟\nلأن أفضل بن وأغلى ماكينة لن ينقذا كوبًا طحنه غير ثابت أو غير مناسب لطريقة التحضير\n\n## Blade vs Burr\nمطاحن الشفرات تقطع القهوة عشوائيًا، أما مطاحن Burr فهي الأفضل للقهوة المختصة لأنها تطحن بثبات أعلى\n\n## ثبات الطحن\nكلما كان الطحن أكثر انتظامًا، صار الاستخلاص (Extraction) أوضح وأقل فوضى بين الحموضة (Acidity) والمرارة (Bitterness)\n\n## مطحنة الإسبريسو\nتحتاج ضبطًا دقيقًا جدًا لأن فرقًا بسيطًا في الطحن قد يغير وقت جرعة الإسبريسو والطعم والكريما (Crema)\n\n## مطحنة الفلتر\nتحتاج مجال طحن أوسع للـ V60 والكيميكس والفرنش برس والكولد برو، ولا يصح غالبًا تبديل نفس مطحنة الإسبريسو طوال اليوم\n\n## هل نحتاج مطحنتين؟\nمقهى بسيط ببن واحد قد يبدأ بمطحنة واحدة قوية، لكن المقهى المختص غالبًا يحتاج مطحنتين: واحدة للإسبريسو وأخرى للفلتر أو البن المتغير\n\n## بن إضافي (Guest Coffee) أو قهوة منزوعة الكافيين (Decaf)\nإذا كان المقهى يقدم نوعًا إضافيًا من البن أو قهوة منزوعة الكافيين (Decaf)، فقد يحتاج مطحنة مستقلة حتى لا تختلط النكهات والإعدادات. وإذا كان الطلب قليلًا، يمكن طحن جرعة واحدة عند الطلب (Single Dose) بطريقة منظمة بدل شراء مطحنة ثالثة\n\n## السرعة في الذروة\nالمطحنة ليست جودة فقط؛ سرعة الطحن والجرعات المتتالية تؤثر على وقت انتظار العميل في أوقات الضغط\n\n## بقايا المطحنة (بقايا القهوة العالقة داخل المطحنة (Retention))\nبعض المطاحن تحتفظ ببقايا قهوة داخلية بعد الطحن، وهذا يسبب هدرًا أو خلطًا بين جرعات قديمة وجديدة\n\n## الحرارة\nالمطحنة التي تسخن كثيرًا في الذروة قد تغير سلوك الطحن والطعم، لذلك التحمل التجاري مهم للمقاهي\n\n## الصيانة\nالسكاكين أو التروس Burrs تحتاج تنظيفًا ومتابعة واستبدالًا عند الحاجة؛ المطحنة المهملة تجعل القهوة باهتة ومتذبذبة\n\n## خطأ شائع\nشراء ماكينة إسبريسو غالية ثم توفير الميزانية على المطحنة، مع أن المطحنة هي أساس ثبات جرعة الإسبريسو اليومية\n\n## نصيحة عملية\nلا تختَر المطحنة بالاسم فقط؛ اخترها حسب حجم الطلب، نوع التحضير، توفر الصيانة، سرعة الخدمة، ودقة الضبط\n\n## لصاحب المقهى\nضع خطة مطاحن واضحة من البداية: مطحنة للإسبريسو الأساسي، وأخرى للفلتر أو البن المختلف، ثم قيّم لاحقًا هل تحتاج مطحنة إضافية للقهوة منزوعة الكافيين (Decaf) أو البن المؤقت حسب الطلب الفعلي\n\n## مناسب لمن؟\nلصاحب المقهى، الباريستا، وأي شخص يريد قهوة ثابتة لا تعتمد على الحظ\n\n## خطوات التحضير\n\n### 1. حدد استخدام المطحنة\nقبل الشراء اسأل: هل هي للإسبريسو فقط، للفلتر فقط، أم لبن متغير؟ الاستخدام يحدد نوع المطحنة.\n⏱ 30s\n\n### 2. احسب حجم الطلب\nالمقهى الهادئ ليس مثل موقع مزدحم. سرعة الطحن والتحمل اليومي يجب أن يناسبان وقت الذروة لا الوقت الهادئ فقط.\n⏱ 45s\n\n### 3. افصل الإسبريسو عن الفلتر\nإذا كان عندك إسبريسو وطرق تحضير يدوية، اجعل لكل مسار مطحنة أو حلًا منفصلًا حتى لا تضيع المعايرة طوال اليوم.\n⏱ 30s\n\n### 4. اختر Burr لا Blade\nللمقهى أو القهوة المختصة، تجنب مطاحن الشفرات العشوائية. الثبات يبدأ من نظام طحن احترافي.\n⏱ 20s\n\n### 5. راجع دقة الضبط\nالإسبريسو يحتاج تعديلات دقيقة جدًا. المطحنة التي تقفز بين الدرجات قد تصعّب الوصول لوصفة ثابتة.\n⏱ 30s\n\n### 6. اختبر الهدر والاحتفاظ\nاسأل عن كمية بقايا القهوة العالقة داخل المطحنة (بقايا القهوة العالقة داخل المطحنة (Retention)) وسهولة التنظيف؛ فبقايا القهوة القديمة تؤثر على الطعم والهدر.\n⏱ 30s\n\n### 7. تأكد من توفر الصيانة\nمطحنة ممتازة بلا وكيل أو قطع غيار قد تتحول إلى مشكلة تشغيلية في أول عطل.\n⏱ 30s\n\n### 8. ضع خطة للبن الإضافي أو القهوة منزوعة الكافيين (Decaf)\nإذا ستقدم بنًا إضافيًا أو قهوة منزوعة الكافيين (Decaf)، حدّد هل تحتاج مطحنة إضافية أم يكفي طحن جرعة واحدة عند الطلب (Single Dose) بطريقة منظمة.\n⏱ 30s\n\n### 9. نظف بانتظام\nنظافة المطحنة ليست رفاهية. الزيوت القديمة والرواسب تغير الرائحة والطعم وتزيد التكتل.\n⏱ 45s\n\n### 10. راقب التكتل والتوزيع\nإذا كانت الجرعة تخرج متكتلة جدًا، قد تحتاج تنظيفًا أو ضبطًا أو أدوات توزيع تساعد على ثبات الاستخلاص (Extraction).\n⏱ 30s\n\n### 11. سجّل المعايرة\nدوّن إعداد الطحن ووقت جرعة الإسبريسو والنتيجة عند تغيير البن أو الرطوبة أو درجة التحميص (Roasting).\n⏱ 30s\n\n### 12. راجع الخطة بعد التشغيل\nبعد شهر من العمل الفعلي، راقب: هل مطحنة واحدة تكفي؟ هل الذروة تتأخر؟ هل تحتاج مطحنة فلتر أو مطحنة قهوة منزوعة الكافيين (Decaf) منفصلة؟ القرار يجب أن يبنى على الطلب الفعلي لا على التخمين.\n⏱ 60s'),
  ('espresso-machine', 'ماكينة الإسبريسو', 'equipment', 'معدات المقهى', 'ماكينة الإسبريسو قلب بار القهوة، لكنها ليست وحدها سر النجاح. الماكينة الجيدة تعطي حرارة وضغطًا وبخارًا أكثر ثباتًا، وهذا يساعد الباريستا على تكرار جرعة الإسبريسو وتبخير الحليب بسرعة وجودة. لكن شراء ماكينة أكبر أو أغلى من حاجة المشروع قد يربك الميزانية، وشراء ماكينة ضعيفة قد يخنق التشغيل وقت الذروة. القرار الصحيح يبدأ من حجم الطلبات والمنيو وخطة الصيانة، لا من الشكل فقط.', 4.9, ARRAY["مقهى"], '—', 'مقهى', '## الفكرة\nماكينة الإسبريسو توفر الماء المضغوط والحرارة والبخار اللازمين للجرعة إسبريسو (Espresso Shot) والمشروبات الحليبية\n\n## لماذا مهمة؟\nلأن ثبات الحرارة والضغط يساعد على تكرار جرعة الإسبريسو بدل أن يتغير الطعم كل ساعة\n\n## عدد المجموعات\nمجموعة واحدة قد تكفي لكشك صغير، أما المقاهي ذات الذروة فتحتاج غالبًا مجموعتين أو أكثر حسب حجم الطلب\n\n## قوة البخار\nإذا كان المنيو مليئًا باللاتيه والكابتشينو، فقوة البخار وسرعة التبخير عامل حاسم لا تفصيل جانبي\n\n## الاستقرار الحراري\nالماكينة الضعيفة قد تتعب عند الطلبات المتتالية، فيتغير الاستخلاص (Extraction) وتتباطأ الخدمة\n\n## مساحة البار\nالماكينة يجب أن تناسب الكونتر ومسار العمل، لا أن تكون جميلة فقط وتخنق حركة الباريستا\n\n## الصيانة والوكيل\nماكينة بلا صيانة متاحة أو قطع غيار قد تتحول إلى توقف مكلف في وقت حساس\n\n## الماء والفلترة\nالماء غير المناسب يضر الماكينة ويؤثر على الطعم؛ الفلترة ليست اختيارًا تجميليًا\n\n## خطأ شائع\nشراء ماكينة ضخمة لتبدو احترافية رغم أن حجم الطلب لا يحتاجها، أو شراء رخيصة ثم دفع الثمن في الأعطال\n\n## نصيحة عملية\nاختر الماكينة حسب المنيو والذروة وعدد الباريستا ومساحة البار وتوفر الصيانة\n\n## لصاحب المقهى\nلا تفصل قرار الماكينة عن المطحنة والفلترة وتدريب الفريق؛ هذه منظومة واحدة\n\n## مناسب لمن؟\nصاحب المقهى والباريستا المسؤول عن تجهيز وتشغيل بار الإسبريسو\n\n## خطوات التحضير\n\n### 1. حدد نوع المشروع\nهل هو كشك، ركن قهوة، مقهى متوسط، أم فرع مزدحم؟ حجم المشروع يحدد حجم الماكينة.\n⏱ 30s\n\n### 2. احسب ذروة الطلب\nلا تقيس الحاجة على اليوم الهادئ؛ اسأل كم مشروبًا قد يطلب في نصف ساعة مزدحمة.\n⏱ 45s\n\n### 3. راجع المنيو\nإذا كانت أغلب الطلبات حليبية، أعطِ قوة البخار أولوية كبيرة.\n⏱ 30s\n\n### 4. اختر عدد المجموعات\nمجموعة واحدة للمساحات الصغيرة، ومجموعتان أو أكثر عند وجود ضغط تشغيل فعلي.\n⏱ 30s\n\n### 5. افحص مساحة الكونتر\nتأكد أن الماكينة تناسب البار وتترك مساحة للمطحنة والكبس والتبخير والتنظيف.\n⏱ 30s\n\n### 6. تأكد من الفلترة\nلا تشغل الماكينة قبل معرفة جودة الماء وخطة الفلترة المناسبة.\n⏱ 30s\n\n### 7. اسأل عن الصيانة\nتأكد من توفر وكيل وقطع غيار وفنيين قبل الشراء لا بعد أول عطل.\n⏱ 30s\n\n### 8. خطط للكهرباء والتصريف\nراجع متطلبات الكهرباء والماء والصرف قبل تركيب الكونتر النهائي.\n⏱ 45s\n\n### 9. درّب الفريق\nحتى أفضل ماكينة تحتاج باريستا يفهم الوصفة والتنظيف والتبخير.\n⏱ 60s\n\n### 10. راجع الأداء بعد التشغيل\nبعد أسبوعين من التشغيل، راقب التأخير، ثبات جرعة الإسبريسو، البخار، والتنظيف لتعرف إن كانت الخطة مناسبة.\n⏱ 60s'),
  ('coffee-scale', 'ميزان القهوة', 'equipment', 'معدات المقهى', 'ميزان القهوة هو الفرق بين وصفة واضحة وتخمين متكرر. في القهوة المختصة، لا يكفي أن تقول ملعقة أو كوب ماء؛ الوزن هو ما يجعل النتيجة قابلة للتكرار. الميزان مهم للإسبريسو، V60، كيميكس، أيروبرس، وحتى تدريب الفريق. هو أداة صغيرة لكنها تمنع هدرًا كبيرًا وتساعدك تفهم لماذا نجح الكوب أو فشل.', 4.8, ARRAY["أساسي"], '—', 'أساسي', '## الفكرة\nالميزان يحوّل التحضير من تقدير بالعين إلى وصفة قابلة للتكرار\n\n## لماذا مهم؟\nلأن اختلاف بضعة غرامات قد يغير قوة الكوب وتوازنه بوضوح\n\n## للإسبريسو\nيساعد على وزن الجرعة داخل السلة وكمية القهوة الخارجة (Yield) في الكوب (Yield) بدل الاعتماد على اللون فقط\n\n## للفلتر\nيساعد على ضبط نسبة القهوة إلى الماء (Brew Ratio)، مثل 15g قهوة إلى 250g ماء\n\n## المؤقت\nوجود مؤقت في الميزان مفيد جدًا لمتابعة وقت الاستخلاص (Extraction) والنزول\n\n## الدقة\nللقهوة يفضل ميزان يقرأ حتى 0.1g خصوصًا مع الإسبريسو\n\n## السرعة\nالميزان البطيء في القراءة يربك الباريستا أثناء الصب أو إيقاف الاستخلاص (Extraction)\n\n## التحمل\nفي المقهى اختر ميزانًا يتحمل الماء والحرارة والاستخدام اليومي\n\n## خطأ شائع\nاستخدام ملاعق أو تقدير بصري ثم الاستغراب من تغير الطعم كل مرة\n\n## نصيحة عملية\nزن البن والماء أو كمية القهوة الخارجة (Yield)، وسجل الوصفة الناجحة حتى تستطيع تكرارها\n\n## لصاحب المقهى\nالميزان ليس أداة هواة فقط؛ هو أداة تدريب وضبط جودة وتقليل هدر\n\n## مناسب لمن؟\nالهاوي، الباريستا، وصاحب المقهى الذي يريد ثباتًا في المنتج\n\n## خطوات التحضير\n\n### 1. اختر دقة مناسبة\nابحث عن ميزان يقرأ 0.1g خصوصًا إذا ستستخدمه للإسبريسو.\n⏱ 20s\n\n### 2. تأكد من وجود مؤقت\nالمؤقت يساعدك تربط الوزن بالزمن، وهذا أساس قراءة الوصفة.\n⏱ 15s\n\n### 3. اختبر سرعة القراءة\nالميزان البطيء يجعل الصب أو إيقاف الاستخلاص (Extraction) أصعب من اللازم.\n⏱ 20s\n\n### 4. ضعه في مكان ثابت\nاستخدم سطحًا مستويًا بعيدًا عن الاهتزاز حتى لا تتغير القراءة.\n⏱ 10s\n\n### 5. زن الجرعة\nقبل التحضير زن البن بدل الاعتماد على الملعقة أو العين.\n⏱ 10s\n\n### 6. زن الماء أو كمية القهوة الخارجة (Yield)\nفي الفلتر زن الماء، وفي الإسبريسو زن كمية القهوة الخارجة (Yield) داخل الكوب.\n⏱ 20s\n\n### 7. سجل الوصفة\nدوّن الجرعة، الماء، الوقت، والطعم حتى تعرف ماذا تعدل لاحقًا.\n⏱ 30s\n\n### 8. نظف الميزان\nامسح الماء والقهوة فورًا حتى لا تتلف الحساسات مع الوقت.\n⏱ 15s'),
  ('gooseneck-kettle', 'إبريق صب', 'equipment', 'معدات المقهى', 'إبريق الصب ليس مجرد شكل جميل في صور القهوة. عنقه الطويل الرفيع يعطيك تحكمًا في سرعة الماء واتجاهه، وهذا مهم في V60 والكيميكس والفلتر المثلج. في التحضير اليدوي، طريقة الصب قد تغير الطعم مثلما يغير الطحن والحرارة. الإبريق الجيد يجعل الصب هادئًا ومتوازنًا بدل أن يتحول الماء إلى دفعة عشوائية تحفر سطح القهوة.', 4.8, ARRAY["ترشيح"], '—', 'ترشيح', '## الفكرة\nإبريق بعنق رفيع يمنحك تحكمًا أفضل في سرعة واتجاه الصب\n\n## لماذا مهم؟\nلأن الصب العشوائي قد يسبب استخلاص (Extraction)ًا غير متوازن حتى لو كان البن والطحن جيدين\n\n## التحكم بالتدفق\nالتدفق الهادئ يساعد على تبلل القهوة دون حفر السطح أو ضرب الحواف\n\n## حرارة الماء\nالإبريق الكهربائي بضبط حرارة مفيد جدًا لمن يحضر فلتر يوميًا\n\n## السعة\nاختر سعة تناسب وصفاتك؛ الإبريق الضخم قد يكون مزعجًا للوصفات الصغيرة\n\n## الاتزان في اليد\nالوزن والمقبض يؤثران على ثبات يد الباريستا أثناء الصب\n\n## لـ V60 والكيميكس\nكلما كان الصب أدق، صار التحكم في وقت النزول والتوازن أسهل\n\n## خطأ شائع\nشراء إبريق جميل لكنه سيئ التدفق أو ثقيل جدًا في الاستخدام اليومي\n\n## نصيحة عملية\nدرّب يدك على صب دائري هادئ وثابت قبل البحث عن وصفات معقدة\n\n## لصاحب المقهى\nالإبريق الجيد يرفع ثبات تحضير الفلتر ويقلل اعتماد النتيجة على مزاج الباريستا\n\n## مناسب لمن؟\nمحبو الفلتر، الباريستا، وأي مقهى يقدم V60 أو كيميكس أو فلتر مثلج\n\n## خطوات التحضير\n\n### 1. حدد الاستخدام\nهل تحتاجه للبيت أم للمقهى؟ الاستخدام التجاري يحتاج تحملًا وسرعة أكبر.\n⏱ 20s\n\n### 2. اختر تحكم حرارة إن أمكن\nإذا تحضر فلتر كثيرًا، إبريق بضبط حرارة يوفر وقتًا وثباتًا.\n⏱ 20s\n\n### 3. اختبر التدفق\nصب ماءً فقط وشاهد هل يخرج التدفق هادئًا ومسيطرًا أم متقطعًا وعنيفًا.\n⏱ 30s\n\n### 4. اختر سعة مناسبة\nلا تختَر الأكبر دائمًا؛ السعة الكبيرة قد تكون ثقيلة على وصفات صغيرة.\n⏱ 20s\n\n### 5. درّب الصب\nتمرّن على الصب في منتصف القهوة ثم دوائر هادئة دون ضرب حواف الفلتر.\n⏱ 60s\n\n### 6. راقب وقت النزول\nإذا تغير وقت النزول كثيرًا، قد يكون الصب أحد الأسباب وليس الطحن فقط.\n⏱ 30s\n\n### 7. نظف الإبريق\nتراكم الترسبات داخل الإبريق يؤثر على الماء وطول عمر الأداة.\n⏱ 30s'),
  ('tamper', 'تامبر', 'equipment', 'معدات المقهى', 'التامبر أداة بسيطة لكنها مؤثرة في الإسبريسو. وظيفته أن يضغط القهوة داخل السلة بشكل مستوٍ حتى يمر الماء بمقاومة متوازنة. المشكلة ليست في أن تكبس بقوة خارقة، بل أن تكبس بشكل مستقيم وثابت كل مرة. التامبر السيئ أو غير المناسب لمقاس السلة قد يترك أطرافًا رخوة ويسمح للماء بالهروب من طريق أسهل.', 4.7, ARRAY["إسبريسو"], '—', 'إسبريسو', '## الفكرة\nضغط القهوة داخل البورتافلتر لتكوين سطح مقاوم ومتوازن للماء\n\n## لماذا مهم؟\nلأن السطح المائل أو غير المتساوي يسبب استخلاص (Extraction)ًا غير عادل وقنوات مائية\n\n## القوة\nلا تحتاج قوة مبالغًا فيها؛ تحتاج ضغطًا ثابتًا ومستويًا كل مرة\n\n## المقاس\nيجب أن يناسب قطر السلة، لأن التامبر الصغير يترك أطرافًا غير مضغوطة جيدًا\n\n## الاستواء\nالكبس المستوي أهم من رقم القوة نفسه\n\n## ما قبل الكبس\nالتوزيع الجيد قبل الكبس يقلل الفراغات ويجعل التامبر يؤدي دوره بشكل أفضل\n\n## التامبر الموجه\nبعض التامبرز الحديثة تساعد على الاستواء والثبات، لكنها لا تعوض طحنًا أو توزيعًا سيئًا\n\n## خطأ شائع\nالمبالغة في القوة مع سطح مائل ثم لوم البن أو الماكينة على جرعة الإسبريسو السيئة\n\n## نصيحة عملية\nاجعل يدك مستقيمة وركز على سطح مستوٍ بدل محاولة الكبس بقوة كبيرة\n\n## لصاحب المقهى\nتوحيد نوع التامبر وتدريب الفريق على نفس الطريقة يقلل اختلاف جرعة الإسبريسو بين الباريستا\n\n## مناسب لمن؟\nكل من يحضّر إسبريسو يدويًا في البيت أو المقهى\n\n## خطوات التحضير\n\n### 1. اختر المقاس الصحيح\nتأكد أن التامبر مناسب لسلة البورتافلتر، وليس أصغر بفارق واضح.\n⏱ 20s\n\n### 2. وزع القهوة أولًا\nلا تستخدم التامبر لعلاج توزيع سيئ؛ سوّ القهوة قبل الكبس.\n⏱ 15s\n\n### 3. ضع البورتافلتر بثبات\nاستخدم سطحًا مستقرًا حتى لا تميل يدك أثناء الضغط.\n⏱ 10s\n\n### 4. اكبس باستقامة\nاضغط بيد مستقيمة وسطح مستوٍ. الاستواء أهم من استعراض القوة.\n⏱ 10s\n\n### 5. تأكد من السطح\nانظر سريعًا إلى السطح بعد الكبس؛ الميلان الواضح علامة تحتاج تصحيح.\n⏱ 10s\n\n### 6. ركب واستخلص مباشرة\nلا تترك القهوة مكبوسة طويلًا قبل الاستخلاص (Extraction) حتى لا تتأثر بالحرارة والرطوبة.\n⏱ 10s\n\n### 7. نظف التامبر\nامسح سطح التامبر من بقايا القهوة حتى لا تتراكم وتؤثر على الكبس.\n⏱ 10s'),
  ('leveling-tamper', 'مكبس تامبر احترافي', 'equipment', 'معدات المقهى', 'مكبس التامبر الاحترافي أو التامبر الموجّه يساعد الباريستا على كبس القهوة بسطح مستوٍ وثبات أعلى. فكرته ليست أن يجعل الإسبريسو ممتازًا وحده، بل أن يقلل اختلاف الكبس بين شخص وآخر. في المقهى، هذه التفاصيل الصغيرة تصنع فرقًا عندما يعمل أكثر من باريستا على نفس البار. المهم أن يكون المقاس مناسبًا لسلة البورتافلتر، وأن يظل التوزيع والطحن صحيحين قبل الكبس.', 4.7, ARRAY["إسبريسو"], '—', 'إسبريسو', '## الفكرة\nمكبس يساعد على جعل سطح القهوة مستويًا وثابتًا قبل الاستخلاص (Extraction)\n\n## لماذا مهم؟\nلأنه يقلل اختلاف الكبس بين الباريستا، خصوصًا في المقاهي التي يعمل فيها أكثر من شخص\n\n## المقاس\nاختر المقاس المناسب لسلة البورتافلتر مثل 51mm أو 53mm أو 58mm حسب الماكينة\n\n## ليس بديلًا للتوزيع\nإذا كانت القهوة متكتلة أو غير موزعة جيدًا، فلن يحل التامبر المشكلة وحده\n\n## الاستواء\nأهم ميزة فيه أنه يقلل الميلان، لأن السطح المائل يسبب مرور الماء من جهة أضعف\n\n## القوة\nبعض الأنواع تساعد على ضغط أكثر ثباتًا، لكن القوة ليست أهم من الاستواء والتكرار\n\n## خطأ شائع\nشراء تامبر احترافي مع مقاس غير مناسب للسلة، فتظل الأطراف غير مضغوطة جيدًا\n\n## نصيحة عملية\nاختر التامبر بعد معرفة مقاس سلتك الحقيقي، ولا تعتمد على التخمين أو شكل المنتج فقط\n\n## لصاحب المقهى\nمفيد لتوحيد جودة جرعة الإسبريسو بين الفريق، لكنه يحتاج تدريبًا بسيطًا وطريقة تشغيل واضحة\n\n## مناسب لمن؟\nالباريستا، وصاحب المقهى، ومن يحضر الإسبريسو ويريد ثباتًا أعلى في الكبس\n\n## خطوات التحضير\n\n### 1. تأكد من مقاس السلة\nقبل الشراء اعرف مقاس البورتافلتر أو السلة بدقة؛ اختلاف بسيط قد يترك أطرافًا غير مضغوطة.\n⏱ 20s\n\n### 2. وزع القهوة أولًا\nاستخدم توزيعًا جيدًا قبل الكبس، لأن التامبر يضغط السطح ولا يرتب القهوة من الداخل وحده.\n⏱ 15s\n\n### 3. اضبط عمق التامبر إن وجد\nبعض المكابس تسمح بتعديل العمق؛ اضبطه بما يناسب جرعتك وسلتك.\n⏱ 20s\n\n### 4. اكبس بهدوء\nاستخدم ضغطًا مستقيمًا دون ميلان أو حركة جانبية مبالغ فيها.\n⏱ 10s\n\n### 5. افحص السطح\nبعد الكبس، تأكد أن السطح مستوٍ ولا توجد أطراف رخوة واضحة.\n⏱ 10s\n\n### 6. راقب الاستخلاص (Extraction)\nإذا بقي تدفق الإسبريسو غير متوازن، راجع الطحن والتوزيع والجرعة بدل لوم التامبر وحده.\n⏱ 30s\n\n### 7. وحّد طريقة الفريق\nدرّب الفريق على نفس الخطوات حتى لا يتحول اختلاف الاستخدام إلى سبب جديد لتذبذب جرعة الإسبريسو.\n⏱ 30s'),
  ('distribution-tool', 'أداة توزيع', 'equipment', 'معدات المقهى', 'أداة التوزيع ليست حلًا سحريًا، لكنها تساعد على جعل القهوة داخل السلة أكثر انتظامًا قبل الكبس. في الإسبريسو، الماء يبحث دائمًا عن أسهل طريق. إذا كانت القهوة متكتلة أو فيها فراغات، قد تحصل مسارات مائية تفسد جرعة الإسبريسو. التوزيع الجيد يقلل هذه المشكلة، خصوصًا مع مطاحن تسبب تكتلًا أو مع ضغط عمل سريع في البار.', 4.7, ARRAY["ثبات"], '—', 'ثبات', '## الفكرة\nتوزيع القهوة داخل السلة قبل الكبس لتقليل الفراغات والتكتلات\n\n## لماذا مهمة؟\nلأن الماء يهرب من المناطق الضعيفة، فتظهر جرعة إسبريسو (Espresso Shot) غير متوازنة حتى لو كانت الوصفة صحيحة\n\n## WDT\nأداة الإبر الرفيعة تساعد على تفكيك التكتلات وتحسين توزيع الطحن داخل السلة\n\n## Distributor\nأداة التسوية السطحية تساعد على ترتيب السطح لكنها لا تصلح وحدها التكتلات العميقة دائمًا\n\n## العلاقة بالطحن\nالتوزيع لا يعوض مطحنة سيئة، لكنه يقلل أثر التكتل ويزيد ثبات التحضير\n\n## قبل الكبس\nاستخدم التوزيع قبل التامبر، لأن التامبر يضغط ما هو موجود ولا يرتب الداخل وحده\n\n## خطأ شائع\nاستخدام أداة توزيع كأنها بديل كامل عن ضبط الطحن والجرعة والتامبر\n\n## نصيحة عملية\nابدأ بطريقة توزيع بسيطة وثابتة، ولا تضف عشر أدوات تربك الفريق\n\n## لصاحب المقهى\nأداة صغيرة قد تحسن الثبات إذا كان الفريق مدربًا عليها، لكنها تحتاج معيارًا واضحًا في التشغيل\n\n## مناسب لمن؟\nالباريستا والمقاهي التي تريد تقليل تذبذب جرعة إسبريسو (Espresso Shot) الإسبريسو\n\n## خطوات التحضير\n\n### 1. افحص الجرعة\nتأكد أن كمية القهوة داخل السلة مناسبة قبل استخدام أي أداة توزيع.\n⏱ 10s\n\n### 2. فكك التكتلات\nإذا تستخدم WDT، حرّك الإبر بلطف داخل السلة لتفكيك التكتلات لا لبعثرة القهوة خارجها.\n⏱ 15s\n\n### 3. سوّ السطح\nبعد تفكيك التكتلات، سوّ السطح قليلًا حتى يصبح جاهزًا للكبس.\n⏱ 10s\n\n### 4. استخدم التامبر\nاكبس باستقامة وثبات بعد التوزيع مباشرة.\n⏱ 10s\n\n### 5. راقب تدفق الإسبريسو\nإذا بقي تدفق الإسبريسو يتدفق من جهة واحدة، راجع الطحن والتوزيع والسلة لا الأداة وحدها.\n⏱ 30s\n\n### 6. وحّد طريقة الفريق\nعلّم الفريق نفس عدد الحركات ونفس الخطوات حتى لا تتحول الأداة إلى مصدر اختلاف.\n⏱ 30s'),
  ('bean-sprayer', 'بخاخة ترطيب حبوب البن', 'equipment', 'معدات المقهى', 'بخاخة ترطيب حبوب البن أداة صغيرة تُستخدم أحيانًا قبل الطحن لتقليل الكهرباء الساكنة وتطاير القهوة المطحونة. الفكرة بسيطة: رشة خفيفة جدًا على الحبوب قبل الطحن، وليست غسلًا أو تبليلًا زائدًا. فائدتها تظهر أكثر مع بعض المطاحن والبيئات الجافة، لكنها ليست أداة أساسية لكل مقهى. استخدامها الخاطئ بكمية ماء كبيرة قد يسبب تكتلًا أو يزعج المطحنة.', 4.5, ARRAY["اختياري"], '—', 'اختياري', '## الفكرة\nرشة ماء خفيفة جدًا على الحبوب قبل الطحن لتقليل الكهرباء الساكنة وتطاير الطحن\n\n## لماذا مهمة؟\nقد تساعد على تقليل الفوضى والهدر حول المطحنة، خصوصًا في الأجواء الجافة\n\n## RDT\nتسمى أحيانًا تقنية Ross Droplet Technique، ومعناها استخدام قطرات قليلة جدًا قبل الطحن\n\n## ليست غسيلًا للبن\nالمطلوب رشة خفيفة جدًا، لا تبليل الحبوب أو إضافة ماء واضح داخل المطحنة\n\n## متى تفيد؟\nتفيد أكثر مع مطاحن أو حبوب تسبب تطايرًا واضحًا أو احتفاظًا مزعجًا بالطحن\n\n## متى لا تحتاجها؟\nإذا كانت المطحنة نظيفة والطحن لا يتطاير ولا يسبب فوضى، فقد لا تحتاجها في التشغيل اليومي\n\n## خطأ شائع\nالمبالغة في رش الماء حتى تتكتل الحبوب أو يدخل ماء زائد إلى المطحنة\n\n## نصيحة عملية\nاستخدمها بحذر وبكمية بسيطة جدًا، وراقب هل فعلاً خفّت الفوضى أم لا\n\n## لصاحب المقهى\nأداة اختيارية وليست أولوية شراء قبل المطحنة والميزان والتنظيف، لكنها مفيدة في بعض الحالات\n\n## مناسب لمن؟\nالهاوي أو الباريستا الذي يعاني من تطاير الطحن أو فوضى واضحة حول المطحنة\n\n## خطوات التحضير\n\n### 1. ابدأ بكمية صغيرة\nضع جرعة البن المطلوبة للطحن في كوب أو علبة صغيرة.\n⏱ 10s\n\n### 2. رش رشة خفيفة جدًا\nاستخدم رشة واحدة خفيفة أو كمية قليلة جدًا. الهدف تقليل الكهرباء الساكنة لا تبليل البن.\n⏱ 5s\n\n### 3. حرّك الحبوب\nحرّك الحبوب بلطف حتى تتوزع الرطوبة البسيطة على السطح.\n⏱ 5s\n\n### 4. اطحن مباشرة\nلا تترك البن مرطبًا فترة طويلة؛ اطحنه مباشرة بعد الرشة الخفيفة.\n⏱ 20s\n\n### 5. راقب النتيجة\nلاحظ هل قلّ تطاير الطحن حول المطحنة وهل أصبحت الجرعة أنظف.\n⏱ 20s\n\n### 6. تجنب المبالغة\nإذا لاحظت تكتلًا أو رطوبة واضحة، قلل كمية الرش أو توقف عن استخدامها.\n⏱ 10s\n\n### 7. نظف المطحنة بانتظام\nحتى مع البخاخة، النظافة الدورية أهم من الاعتماد على أداة صغيرة لحل كل شيء.\n⏱ 30s'),
  ('milk-pitcher', 'إبريق تبخير الحليب', 'equipment', 'معدات المقهى', 'إبريق الحليب يبدو بسيطًا، لكنه يؤثر على جودة التبخير والتحكم في اللاتيه آرت. حجم الإبريق، شكل الفوهة، وكمية الحليب داخله كلها عوامل تحدد هل ستحصل على رغوة حريرية أم فقاعات خشنة. الإبريق لا يصنع مهارة الباريستا، لكنه يساعد المهارة على الظهور بشكل ثابت.', 4.7, ARRAY["حليب"], '—', 'حليب', '## الفكرة\nإبريق يساعد على تبخير الحليب وصبه بدقة في مشروبات اللاتيه والكابتشينو\n\n## لماذا مهم؟\nلأن شكل الإبريق وحجمه يؤثران على الدوامة والرغوة والتحكم في الصب\n\n## الحجم\nاستخدم حجمًا يناسب كمية الحليب؛ إبريق كبير لكمية صغيرة يصعّب التبخير\n\n## الفوهة\nالفوهة الحادة تساعد على تفاصيل اللاتيه آرت، والفوهة الأوسع قد تناسب الصب العام\n\n## كمية الحليب\nلا تملأ الإبريق أكثر من اللازم؛ تحتاج مساحة لتمدد الحليب وتكوين الدوامة\n\n## الحرارة\nالإبريق يساعدك تشعر بحرارة الحليب بيدك، لكن التدريب والميزان الحراري مفيدان للمبتدئ\n\n## النظافة\nبقايا الحليب القديمة تؤثر على الطعم والرائحة والسلامة\n\n## خطأ شائع\nاستخدام إبريق واحد لكل الأحجام ثم إهدار الحليب أو فشل الرغوة\n\n## نصيحة عملية\nخصص أحجامًا مختلفة للأكواب المختلفة حتى تقلل الهدر وتحسن القوام\n\n## لصاحب المقهى\nاختيار أباريق مناسبة يقلل هدر الحليب ويحسن سرعة وجودة المشروبات الحليبية\n\n## مناسب لمن؟\nالباريستا وكل مقهى يقدم مشروبات بالحليب\n\n## خطوات التحضير\n\n### 1. اختر الحجم المناسب\nاستخدم إبريقًا يناسب حجم المشروب حتى لا تهدر الحليب ولا تفقد التحكم.\n⏱ 20s\n\n### 2. املأ للحد الصحيح\nاملأ الإبريق تقريبًا إلى أسفل بداية الفوهة، واترك مساحة للتمدد.\n⏱ 10s\n\n### 3. نظف عصا البخار\nقبل التبخير مرر بخارًا قصيرًا ونظف العصا من أي بقايا.\n⏱ 10s\n\n### 4. ابدأ بإدخال الهواء\nفي البداية أدخل كمية هواء صغيرة مناسبة للمشروب المطلوب.\n⏱ 10s\n\n### 5. اصنع دوامة\nحافظ على دوران الحليب حتى يصبح القوام ناعمًا ومتجانسًا.\n⏱ 20s\n\n### 6. توقف عند الحرارة المناسبة\nلا تحرق الحليب؛ الحرارة الزائدة تفقد الحلاوة (Sweetness) وتعطي طعمًا مطبوخًا.\n⏱ 10s\n\n### 7. نظف فورًا\nامسح عصا البخار واغسل الإبريق بعد الاستخدام مباشرة.\n⏱ 15s'),
  ('water-filtration', 'فلترة الماء', 'equipment', 'معدات المقهى', 'الماء ليس تفصيلًا جانبيًا في القهوة. هو غالبية الكوب، وهو أيضًا ما يمر داخل ماكينة الإسبريسو والسخانات والأنابيب طوال اليوم. ماء سيئ قد يجعل القهوة باهتة أو حادة، وقد يسبب ترسبات وأعطالًا مكلفة. الفلترة الصحيحة ليست نوعًا واحدًا للجميع؛ تبدأ من فحص الماء في موقعك ثم اختيار حل يناسب الطعم وحماية المعدات.', 4.9, ARRAY["جودة"], '—', 'جودة', '## الفكرة\nتحسين الماء لحماية المعدات وإظهار طعم القهوة بشكل أفضل\n\n## لماذا مهمة؟\nلأن الماء يؤثر على الاستخلاص (Extraction) والطعم، ويؤثر على عمر ماكينة الإسبريسو والسخانات\n\n## فحص الماء\nلا تختَر فلترًا عشوائيًا قبل معرفة صلابة الماء والمعادن والكلور في موقعك\n\n## الطعم\nماء غير مناسب قد يجعل القهوة مسطحة، حادة، أو ضعيفة الحلاوة (Sweetness)\n\n## حماية الماكينة\nالترسبات الكلسية قد تسبب أعطالًا وانسدادًا وتكاليف صيانة عالية\n\n## ليس فلترًا واحدًا للجميع\nحل الماء في رام الله قد لا يناسب مدينة فلسطينية أخرى؛ الفحص هو البداية الصحيحة\n\n## تغيير الفلاتر\nالفلتر له عمر تشغيلي. إذا انتهى عمره ولم يتغير فقد يصبح وجوده شكليًا فقط\n\n## خطأ شائع\nتجاهل الماء حتى تظهر الأعطال أو يشتكي العملاء من تغير الطعم\n\n## نصيحة عملية\nافحص الماء عند بداية المشروع وبعد أي تغيير في المصدر أو المنطقة\n\n## لصاحب المقهى\nضع خطة فلترة وصيانة مكتوبة، لأن الماء يؤثر على الطعم والتكلفة التشغيلية معًا\n\n## مناسب لمن؟\nكل مقهى جاد، وكل شخص يستخدم ماكينة إسبريسو أو معدات غالية\n\n## خطوات التحضير\n\n### 1. افحص ماء الموقع\nابدأ بتحليل الصلابة والمعادن والكلور بدل اختيار فلتر بالاسم فقط.\n⏱ 60s\n\n### 2. راجع متطلبات المعدات\nاقرأ توصيات ماكينة الإسبريسو والسخان بخصوص جودة الماء المقبولة.\n⏱ 30s\n\n### 3. اختر نظامًا مناسبًا\nقد تحتاج فلتر كربون، معالجة صلابة، أو نظامًا مركبًا حسب نتيجة الفحص.\n⏱ 60s\n\n### 4. ركّب قبل التشغيل\nلا تنتظر ظهور الترسبات؛ الفلترة يجب أن تكون جزءًا من التجهيز الأساسي.\n⏱ 60s\n\n### 5. راقب الطعم\nتذوق القهوة بعد تركيب الفلتر، لأن حماية المعدة لا تكفي إذا صار الطعم ضعيفًا.\n⏱ 30s\n\n### 6. حدد موعد الاستبدال\nاكتب تاريخ تركيب الفلتر وموعد تغييره حسب الاستهلاك لا حسب الذاكرة.\n⏱ 30s\n\n### 7. درّب الفريق\nعلّم الفريق علامات المشكلة: تغير الطعم، ضعف البخار، أصوات غريبة، أو بطء تدفق الماء.\n⏱ 45s'),
  ('knock-box', 'صندوق تفريغ القهوة', 'equipment', 'معدات المقهى', 'صندوق تفريغ القهوة يبدو تفصيلًا صغيرًا، لكنه جزء مهم من سرعة ونظافة بار الإسبريسو. الباريستا يفرغ البورتافلتر عشرات أو مئات المرات يوميًا. إذا كان مكان التفريغ بعيدًا أو صغيرًا أو غير ثابت، سيتأثر الإيقاع وتزيد الفوضى حول البار. التفاصيل الصغيرة المتكررة هي التي تصنع تشغيلًا محترفًا.', 4.6, ARRAY["تشغيل"], '—', 'تشغيل', '## الفكرة\nمكان مخصص لتفريغ بقايا القهوة من البورتافلتر بسرعة ونظافة\n\n## لماذا مهم؟\nلأن التفريغ يحدث مئات المرات في اليوم في بعض المقاهي، وأي بطء يتكرر كثيرًا\n\n## الموقع\nيجب أن يكون قريبًا من ماكينة الإسبريسو ومسار عمل الباريستا الطبيعي\n\n## الثبات\nالصندوق الخفيف أو المتحرك يسبب إزعاجًا وفوضى أثناء التفريغ\n\n## الحجم\nالحجم الصغير جدًا يمتلئ بسرعة، والكبير جدًا قد يضيع مساحة من البار\n\n## النظافة\nسهولة التفريغ والغسيل مهمة حتى لا تتراكم الروائح والرطوبة\n\n## خطأ شائع\nاعتباره كماليات ثم استخدام سلة بعيدة أو غير مناسبة وقت التشغيل\n\n## نصيحة عملية\nضعه في نقطة لا تجبر الباريستا على الالتفاف أو قطع مسار التحضير\n\n## لصاحب المقهى\nتحسين مسار التفريغ يقلل الفوضى ويرفع سرعة الخدمة بتكلفة بسيطة\n\n## مناسب لمن؟\nكل بار إسبريسو منزلي جاد أو مقهى تجاري\n\n## خطوات التحضير\n\n### 1. حدد مكانه على البار\nضعه قريبًا من الماكينة دون أن يعطل مساحة الكبس أو التبخير.\n⏱ 20s\n\n### 2. اختر حجمًا مناسبًا\nاربط الحجم بعدد الطلبات؛ الصندوق الصغير جدًا سيتعب الفريق وقت الذروة.\n⏱ 20s\n\n### 3. تأكد من الثبات\nجرّبه أثناء الطرق؛ يجب ألا يتحرك أو يصدر ضجيجًا مزعجًا.\n⏱ 15s\n\n### 4. سهّل التفريغ\nتأكد أن إفراغه وغسله لا يحتاجان تفكيكًا معقدًا في نهاية اليوم.\n⏱ 20s\n\n### 5. نظفه دوريًا\nبقايا القهوة الرطبة قد تسبب روائح وفوضى إذا تُركت طويلًا.\n⏱ 30s\n\n### 6. راجع مسار العمل\nإذا كان الباريستا يلتف كثيرًا للتفريغ، فالمكان غير مناسب حتى لو كان الصندوق جيدًا.\n⏱ 30s'),
  ('rinser', 'غسالة أكواب البار', 'equipment', 'معدات المقهى', 'غسالة الأكواب أو الأباريق خلف البار ليست رفاهية في مقهى مزدحم. هي أداة تسرّع شطف أباريق الحليب والأكواب وبعض أدوات البار بين الطلبات، وتقلل تراكم بقايا الحليب والروائح. لكنها تحتاج تخطيطًا مبكرًا في الكونتر لأن مكانها يحتاج ماء وتصريف ومساحة حركة، ولا يصح أن تضاف عشوائيًا بعد تنفيذ البار.', 4.7, ARRAY["نظافة"], '—', 'نظافة', '## الفكرة\nأداة شطف سريعة للأباريق وبعض أدوات البار باستخدام ضغط الماء\n\n## لماذا مهمة؟\nلأنها تقلل الوقت بين الطلبات وتحافظ على نظافة أفضل خصوصًا مع الحليب\n\n## الموقع\nيجب أن تكون قريبة من محطة التبخير والغسيل، لا في زاوية بعيدة تكسر مسار العمل\n\n## التصريف\nتحتاج تصريفًا صحيحًا حتى لا تتحول إلى مصدر ماء وفوضى داخل البار\n\n## ضغط الماء\nضعف الضغط يجعلها مزعجة وغير فعالة، لذلك التجهيز مهم قبل التركيب\n\n## النظافة\nتساعد لكنها لا تلغي الغسيل العميق والتعقيم حسب نظام التشغيل\n\n## خطأ شائع\nإضافتها بعد تنفيذ الكونتر دون حساب الماء والتصريف والمساحة\n\n## نصيحة عملية\nخطط لها في مرحلة التصميم، خصوصًا إذا منيو الحليب كبير والذروة عالية\n\n## لصاحب المقهى\nتستحق الاهتمام في المقاهي متوسطة وعالية الطلب لأنها توفر وقتًا وتقلل فوضى البار\n\n## مناسب لمن؟\nالمقاهي التي تقدم مشروبات حليبية كثيرة أو تعمل بضغط طلبات واضح\n\n## خطوات التحضير\n\n### 1. راجع تصميم الكونتر\nحدد مكان الغسالة قبل تنفيذ البار وليس بعده.\n⏱ 30s\n\n### 2. تأكد من الماء والتصريف\nتحتاج خط ماء وتصريف مناسب حتى تعمل بلا فوضى.\n⏱ 45s\n\n### 3. ضعها قرب محطة الحليب\nالمكان الصحيح قرب التبخير لأن الأباريق تُستخدم هناك باستمرار.\n⏱ 20s\n\n### 4. اختبر ضغط الماء\nالضغط الضعيف يجعل الشطف بطيئًا وغير مرضٍ.\n⏱ 20s\n\n### 5. درّب الفريق\nالغسالة للشطف السريع، وليست بديلًا عن التنظيف الكامل عند الحاجة.\n⏱ 30s\n\n### 6. نظف منطقة الغسالة\nامسح حولها باستمرار حتى لا تتجمع بقايا الحليب والماء.\n⏱ 30s'),
  ('batch-brewer', 'جهاز باتش برو', 'equipment', 'معدات المقهى', 'جهاز الباتش برو ليس اختصارًا رخيصًا للقهوة السوداء. في المقهى الصحيح، هو أداة لتقديم قهوة فلتر ثابتة بسرعة، خصوصًا وقت الذروة. لكن الجهاز وحده لا يكفي؛ تحتاج مطحنة مناسبة، وصفة واضحة، ماء جيد، ووقت صلاحية للدفعة. قهوة باتش برو ممتازة قد ترفع رضا العملاء، وقهوة متروكة لساعات قد تضر سمعة المنيو كله.', 4.7, ARRAY["تشغيل"], '—', 'تشغيل', '## الفكرة\nجهاز يحضر قهوة فلتر بكميات أكبر لتقديمها بسرعة وثبات\n\n## لماذا مهم؟\nلأنه يقلل انتظار العميل ويخفف ضغط الباريستا عند وجود طلب على القهوة السوداء\n\n## الوصفة\nليست زرًا فقط؛ تحتاج نسبة قهوة وماء وطحن ووقت نزول واضح\n\n## المطحنة\nجودة الباتش برو تبدأ من مطحنة مناسبة للفلتر لا من الجهاز وحده\n\n## وقت الصلاحية\nالقهوة الجاهزة لا تبقى ممتازة لساعات بلا حد؛ يجب تحديد مدة بيع واضحة\n\n## السيرفر\nالسيرفر الحراري الجيد يحافظ على الحرارة دون طبخ القهوة أو إفسادها\n\n## الذروة\nمفيد جدًا للمقاهي التي تبيع قهوة سوداء بكميات أو في أوقات صباحية مزدحمة\n\n## خطأ شائع\nتحضير دفعة كبيرة وتركها طوال اليوم ثم اعتبار الباتش برو سبب الطعم السيئ\n\n## نصيحة عملية\nتذوق أول دفعة كل يوم وسجل الطحن والوقت والانطباع\n\n## لصاحب المقهى\nإذا كان جمهورك يطلب قهوة سوداء، فالباتش برو قد يكون أسرع وأثبت من الاعتماد الكامل على التحضير اليدوي\n\n## مناسب لمن؟\nالمقاهي ذات الحركة المتوسطة والعالية أو التي تريد تقديم قهوة سوداء ثابتة بسرعة\n\n## خطوات التحضير\n\n### 1. حدد حجم الدفعة\nاختر كمية مناسبة للمبيعات الفعلية حتى لا تبيع قهوة قديمة.\n⏱ 30s\n\n### 2. اضبط المطحنة\nاستخدم طحن فلتر مناسب وراقب وقت النزول والطعم.\n⏱ 30s\n\n### 3. زن القهوة\nلا تستخدم كميات تقديرية؛ كل دفعة يجب أن تكون بوصفة واضحة.\n⏱ 20s\n\n### 4. راجع الماء والفلتر\nالماء والفلتر يؤثران على النكهة والوضوح مثل أي طريقة تحضير أخرى.\n⏱ 30s\n\n### 5. ابدأ التحضير\nشغّل الجهاز وتابع التوزيع والزمن، خصوصًا مع بن جديد.\n⏱ 3-5m\n\n### 6. تذوق الدفعة\nلا تقدم الدفعة قبل التذوق؛ ابحث عن الحلاوة (Sweetness) والوضوح وغياب المرارة (Bitterness) الجافة.\n⏱ 30s\n\n### 7. حدد وقت صلاحية\nاكتب قاعدة تشغيل: متى تُباع الدفعة ومتى تُستبدل؟\n⏱ 20s\n\n### 8. نظف السلال والسيرفر\nالزيوت القديمة تجعل القهوة التالية باهتة أو مرة حتى لو كانت الوصفة صحيحة.\n⏱ 45s'),
  ('refrigeration', 'تبريد البار', 'equipment', 'معدات المقهى', 'تبريد البار ليس مجرد ثلاجة توضع في أي مكان. الحليب، الكريمة، الصوصات، وبعض المكونات تحتاج حفظًا صحيحًا وقربًا من محطة العمل. الثلاجة البعيدة تبطئ الخدمة، والثلاجة الضعيفة ترفع الهدر وتضر السلامة والجودة. في المقهى، موقع الثلاجة وحجمها وتنظيمها جزء من تصميم التشغيل اليومي.', 4.7, ARRAY["تشغيل"], '—', 'تشغيل', '## الفكرة\nحفظ الحليب والمكونات بالقرب من نقطة الاستخدام بسرعة وأمان\n\n## لماذا مهم؟\nلأن المشروبات الحليبية والمكونات الحساسة تتأثر بسرعة بالحرارة وسوء التخزين\n\n## الموقع\nالثلاجة يجب أن تكون قريبة من محطة التبخير والتحضير، لا في مكان يقطع حركة الباريستا\n\n## السعة\nالسعة يجب أن تناسب الذروة، وليس فقط كمية يوم هادئ\n\n## درجة الحرارة\nالمراقبة مهمة للحليب والمكونات، خصوصًا في بيئة فلسطين الحارة صيفًا\n\n## التنظيم\nترتيب الداخل يقلل وقت البحث والهدر وخلط المنتجات القديمة بالجديدة\n\n## السلامة\nضع قواعد واضحة للفتح والإغلاق والتنظيف وتدوير المخزون\n\n## خطأ شائع\nاختيار ثلاجة صغيرة أو بعيدة ثم معاناة يومية في الخدمة والهدر\n\n## نصيحة عملية\nاحسب كمية الحليب وقت الذروة ومكان استخدامه قبل اختيار الثلاجة\n\n## لصاحب المقهى\nالتبريد الجيد يحمي الجودة ويقلل الهدر ويجعل البار أسرع وأهدأ\n\n## مناسب لمن؟\nكل مقهى يقدم مشروبات حليبية أو مكونات مبردة\n\n## خطوات التحضير\n\n### 1. راجع المنيو\nحدد المنتجات التي تحتاج تبريدًا: حليب، بدائل حليب، صوصات، حلويات أو مكونات باردة.\n⏱ 30s\n\n### 2. احسب الذروة\nاختر السعة حسب أعلى ضغط تشغيل لا حسب يوم هادئ.\n⏱ 30s\n\n### 3. حدد الموقع\nضع الثلاجة قرب محطة الاستخدام حتى لا يضيع الباريستا وقتًا في الحركة.\n⏱ 30s\n\n### 4. راقب الحرارة\nاستخدم قراءة واضحة وتحقق يوميًا من ثبات الحرارة.\n⏱ 20s\n\n### 5. نظم الداخل\nرتب المنتجات حسب الاستخدام وتاريخ الانتهاء لتقليل الهدر.\n⏱ 30s\n\n### 6. نظف دوريًا\nالتنظيف المستمر يحافظ على السلامة والرائحة وجودة المكونات.\n⏱ 45s\n\n### 7. راجع بعد التشغيل\nإذا كان الفريق يفتح الثلاجة كثيرًا أو يتحرك بعيدًا، فقد تحتاج تعديل موقع أو حجم.\n⏱ 45s'),
  ('pos-system', 'نظام نقاط البيع', 'equipment', 'معدات المقهى', 'نظام نقاط البيع ليس كاشير فقط. هو عين صاحب المقهى على المبيعات، ساعات الذروة، المنتجات الأقوى، متوسط الفاتورة، وحتى قرارات المنيو. اختيار نظام سيئ قد يربك الفريق ويضيع البيانات، واختيار نظام واضح يجعل الإدارة أذكى. في المقاهي الحديثة، البيانات ليست رفاهية؛ هي جزء من فهم المشروع وتحسينه.', 4.8, ARRAY["إدارة"], '—', 'إدارة', '## الفكرة\nنظام لإدارة الطلبات والدفع والبيانات التشغيلية للمقهى\n\n## لماذا مهم؟\nلأنه يكشف ما يبيع فعلًا، ومتى تحدث الذروة، وأين توجد فرص التحسين\n\n## سهولة الاستخدام\nالنظام المعقد يبطئ الكاشير ويزيد الأخطاء وقت الضغط\n\n## التقارير\nابحث عن تقارير واضحة للمبيعات، المنتجات، الفترات، وطرق الدفع\n\n## إدارة المنيو\nتعديل المنتجات والأسعار والعروض يجب أن يكون بسيطًا وآمنًا\n\n## المخزون\nبعض الأنظمة تساعد على متابعة المكونات أو المنتجات الجاهزة حسب حاجة المشروع\n\n## الربط\nقد تحتاج ربطًا مع الدفع، المحاسبة، الولاء، الطلبات الخارجية أو المتجر الإلكتروني\n\n## الدعم الفني\nنظام بلا دعم جيد قد يتحول إلى أزمة وقت تعطل الدفع\n\n## خطأ شائع\nاختيار الأرخص فقط ثم اكتشاف أن التقارير ضعيفة أو الفريق لا يفهمه\n\n## نصيحة عملية\nجرّب النظام في سيناريو ذروة حقيقي قبل الاعتماد النهائي\n\n## لصاحب المقهى\nتابع التقارير أسبوعيًا، لا تنظر للمبيعات اليومية فقط؛ الأهم فهم السلوك والربحية\n\n## مناسب لمن؟\nصاحب المقهى والمدير وكل مشروع يريد قرارات مبنية على بيانات\n\n## خطوات التحضير\n\n### 1. حدد احتياجك\nهل تحتاج كاشير فقط أم تقارير ومخزون وولاء وربط طلبات؟\n⏱ 30s\n\n### 2. جرّب سرعة الطلب\nاختبر إدخال طلبات متكررة وقت الزحام، لا في عرض هادئ فقط.\n⏱ 45s\n\n### 3. راجع التقارير\nتأكد أن التقارير واضحة وتفيدك في اتخاذ قرار، لا مجرد أرقام كثيرة.\n⏱ 45s\n\n### 4. اختبر تعديل المنيو\nجرّب إضافة منتج وتعديل سعر وعرض قبل الاعتماد.\n⏱ 30s\n\n### 5. تحقق من الدعم\nاسأل عن الدعم وقت الأعطال وسرعة الاستجابة.\n⏱ 30s\n\n### 6. درّب الفريق\nالنظام الجيد يفشل إذا لم يعرف الفريق استخدامه بسرعة ودقة.\n⏱ 60s\n\n### 7. راجع البيانات أسبوعيًا\nاستخدم التقارير لتحسين المنيو والدوام والمخزون، لا لتخزين الأرقام فقط.\n⏱ 60s'),
  ('water-boiler', 'سخان ماء احترافي', 'equipment', 'معدات المقهى', 'سخان الماء الاحترافي يحافظ على توفر ماء ساخن ثابت للشاي، الأمريكانو، والتحضير اليدوي عند الحاجة. في بيئة تجارية، الغلاية المنزلية قد تصبح عنق زجاجة وقت الضغط. السخان المناسب يختصر الوقت، يقلل الفوضى، ويحافظ على سرعة الخدمة، لكن اختياره يجب أن يرتبط بحجم الطلب ومساحة البار وجودة الماء.', 4.6, ARRAY["بار"], '—', 'بار', '## الفكرة\nتوفير ماء ساخن جاهز ومستقر للاستخدام المتكرر في البار\n\n## لماذا مهم؟\nلأن انتظار غلاية صغيرة وقت الزحام يبطئ الخدمة ويزيد توتر الفريق\n\n## السعة\nاختر السعة حسب الطلب على الشاي والأمريكانو والتحضير اليدوي\n\n## الحرارة\nالثبات مهم، خصوصًا إذا يستخدم الماء في وصفات فلتر أو مشروبات محددة\n\n## الموقع\nيجب أن يكون قريبًا من نقطة الاستخدام دون أن يزحم البار أو يسبب خطرًا\n\n## الفلترة\nالماء الداخل للسخان يحتاج فلترة مناسبة لحماية الجهاز والطعم\n\n## السلامة\nالماء الساخن المستمر يحتاج تركيبًا آمنًا وتدريبًا واضحًا للفريق\n\n## خطأ شائع\nالاعتماد على غلاية منزلية في مشروع تجاري ثم تعطيل الخدمة وقت الضغط\n\n## نصيحة عملية\nاحسب الطلبات الساخنة في الذروة قبل اختيار حجم السخان\n\n## لصاحب المقهى\nالسخان الجيد يرفع سرعة الخدمة ويقلل الاعتماد على حلول مؤقتة وفوضوية\n\n## مناسب لمن؟\nالمقاهي، الأكشاك، والبوثات التي تقدم مشروبات ساخنة كثيرة\n\n## خطوات التحضير\n\n### 1. احسب الطلب\nكم كوب شاي أو أمريكانو أو فلتر تحتاج في وقت الذروة؟\n⏱ 30s\n\n### 2. اختر السعة المناسبة\nلا تختر حجمًا صغيرًا لمجرد توفير مساحة إذا كان سيبطئ الخدمة.\n⏱ 30s\n\n### 3. راجع الكهرباء والماء\nتأكد من متطلبات التركيب قبل تصميم الكونتر النهائي.\n⏱ 45s\n\n### 4. اربطه بالفلترة\nاستخدم ماء مناسبًا لحماية السخان وتحسين الطعم.\n⏱ 30s\n\n### 5. حدد مكانه\nضعه في نقطة سهلة الوصول وآمنة للفريق.\n⏱ 20s\n\n### 6. درّب الفريق\nوضح طريقة الاستخدام والتنظيف والسلامة عند التعامل مع الماء الساخن.\n⏱ 45s\n\n### 7. نظف وازل الترسبات\nضع جدول صيانة حسب جودة الماء والاستخدام اليومي.\n⏱ 45s'),
  ('display-fridge', 'ثلاجة عرض', 'equipment', 'معدات المقهى', 'ثلاجة العرض تبيع بعين العميل قبل أن يتكلم. ترتيب الحلويات والمنتجات، الإضاءة، نظافة الزجاج، ودرجة الحرارة كلها تؤثر على قرار الشراء. لكنها ليست ديكورًا فقط؛ هي أيضًا حفظ وسلامة وتدوير مخزون. ثلاجة جميلة بلا تنظيم قد لا تبيع، وثلاجة مزدحمة بلا ترتيب قد تخفي أفضل منتجاتك.', 4.6, ARRAY["بيع"], '—', 'بيع', '## الفكرة\nعرض المنتجات الباردة أو الحلويات بطريقة تحفظها وتدفع العميل للشراء\n\n## لماذا مهمة؟\nلأن العميل غالبًا يقرر شراء الحلى عندما يراه بوضوح وجاذبية\n\n## الإضاءة\nالإضاءة الجيدة تبرز المنتج، لكن يجب ألا تؤثر على حرارته أو جودته\n\n## الترتيب\nضع المنتجات الأكثر ربحية أو الأكثر رغبة في مستوى نظر العميل\n\n## النظافة\nزجاج متسخ أو بخار داخلي يعطي انطباعًا سيئًا حتى لو المنتج ممتاز\n\n## الحرارة\nالحفظ الصحيح مهم للسلامة والجودة، وليس فقط للشكل\n\n## تدوير المخزون\nيجب تطبيق قاعدة الأقدم أولًا حتى لا تنتهي منتجات في الخلف\n\n## خطأ شائع\nملء الثلاجة عشوائيًا حتى تصبح مزدحمة ولا يظهر المنتج بوضوح\n\n## نصيحة عملية\nاعرض عددًا أقل بشكل أجمل بدل ازدحام يخفي الجودة\n\n## لصاحب المقهى\nثلاجة العرض يمكن أن ترفع متوسط الفاتورة إذا صُممت ونُظمت بعناية\n\n## مناسب لمن؟\nالمقاهي التي تبيع حلويات، ساندويتشات، منتجات باردة أو عناصر جاهزة\n\n## خطوات التحضير\n\n### 1. حدد المنتجات\nما الذي سيعرض: حلويات، ساندويتشات، عصائر، أو منتجات جاهزة؟\n⏱ 30s\n\n### 2. اختر الحجم المناسب\nاربط الحجم بالمبيعات اليومية لا بالرغبة في ملء مساحة كبيرة فقط.\n⏱ 30s\n\n### 3. راجع الإضاءة\nتأكد أن المنتج يظهر شهيًا وواضحًا دون إضاءة مزعجة.\n⏱ 20s\n\n### 4. نظم الرفوف\nضع المنتجات الأعلى ربحية أو الأكثر جذبًا في أماكن واضحة.\n⏱ 30s\n\n### 5. راقب الحرارة\nتأكد من ثبات درجة الحرارة حسب نوع المنتجات.\n⏱ 20s\n\n### 6. نظف الزجاج يوميًا\nنظافة الواجهة جزء من البيع، وليست مهمة تنظيف فقط.\n⏱ 30s\n\n### 7. طبق تدوير المخزون\nاستخدم قاعدة الأقدم أولًا لتقليل الهدر والحفاظ على السلامة.\n⏱ 45s\n\n### 8. راجع البيع\nراقب ما يباع وما يبقى، وعدّل العرض بدل الاكتفاء بتعبئة الثلاجة.\n⏱ 60s'),
  ('arabica', 'أرابيكا', 'beans', 'البن والتحميص', 'أرابيكا (Arabica) هي أكثر أنواع البن حضورًا في القهوة المختصة، لكنها ليست شهادة جودة وحدها. طعمها قد يكون زهريًا أو فاكهيًا أو سكريًا أو شوكولاتيًا حسب الارتفاع، التربة، المعالجة (Processing)، التحميص (Roasting)، وطريقة التحضير. للهواة: لا تشترِ القهوة لأنها أرابيكا فقط؛ اقرأ بلد المنشأ (Origin) والمعالجة (Processing) وتاريخ التحميص (Roasting). للباريستا وصاحب المقهى: أرابيكا ممتازة ترفع تجربة الكوب، لكنها تحتاج وصفة ثابتة، تخزينًا جيدًا، وسعرًا مناسبًا لجمهورك.', 4.5, ARRAY["معقدة"], '—', 'معقدة', '## ما هي؟\nنوع بن غالبًا يمنح نكهات أنظف وأكثر تعقيدًا من الأنواع التجارية الرخيصة.\n\n## لماذا تهم الهاوي؟\nتساعدك على فهم سبب اختلاف الطعم بين قهوة وأخرى بدل الاكتفاء بكلمة قهوة مختصة.\n\n## ماذا يهم الباريستا؟\nتحتاج ضبط طحن واستخلاص (Extraction) دقيقًا لأن نكهات الحموضة (Acidity) والحلاوة (Sweetness) تظهر أو تختفي بسرعة.\n\n## ماذا يهم صاحب المقهى؟\nليست كل أرابيكا مناسبة للبيع اليومي؛ اختر محصولًا ثابتًا وسهل التكرار ومقبول التكلفة.\n\n## خطأ شائع\nاعتبار كلمة أرابيكا وحدها ضمانًا للجودة.\n\n## نصيحة عملية\nاسأل دائمًا عن المصدر، المعالجة (Processing)، تاريخ التحميص (Roasting)، ومناسبتها للإسبريسو أو الفلتر.'),
  ('robusta', 'روبوستا', 'beans', 'البن والتحميص', 'روبوستا (Robusta) ليست عيبًا دائمًا وليست عدوة القهوة المختصة. هي نوع بن يحتوي عادةً على كافيين أعلى وجسم أثقل ومرارة أوضح، وقد يعطي كريما (Crema) قوية في الإسبريسو. للهواة: ليست كل روبوستا رديئة، لكن الرديء منها يظهر بطعم خشن وجاف. للباريستا وصاحب المقهى: روبوستا عالية الجودة قد تكون مفيدة في خلطات الإسبريسو التجارية، خصوصًا إذا أردت جسمًا أو كريما (Crema) أو ثباتًا مع الحليب.', 4.5, ARRAY["كافيين أعلى"], '—', 'كافيين أعلى', '## ما هي؟\nنوع بن أقوى في الكافيين والجسم، وغالبًا أكثر مقاومة في الزراعة من أرابيكا.\n\n## لماذا تهم الهاوي؟\nتفسر لك لماذا تبدو بعض أكواب الإسبريسو أثقل أو أكثر مرارة.\n\n## ماذا يهم الباريستا؟\nقد تساعد في تحسين الكريما (Crema) والجسم، لكنها تحتاج توازنًا حتى لا تطغى المرارة (Bitterness).\n\n## ماذا يهم صاحب المقهى؟\nقد تخفض تكلفة الخلطة أو تزيد ثباتها، بشرط اختيار جودة عالية وعدم استخدامها كحل رخيص فقط.\n\n## خطأ شائع\nرفض روبوستا بالكامل أو استخدامها بلا فهم للجودة.\n\n## نصيحة عملية\nجرّبها بنسبة صغيرة داخل خلطة الإسبريسو، وقارن الطعم سوداء ومع الحليب.'),
  ('liberica', 'ليبريكا', 'beans', 'البن والتحميص', 'ليبريكا (Liberica) نوع أقل انتشارًا وله شخصية مختلفة عن أرابيكا وروبوستا. قد يظهر بطابع خشبي، دخاني، فاكهي غريب، أو عطر واضح، لذلك لا يناسب كل الأذواق ولا كل قوائم المقاهي. للهواة: جرّبه كتجربة تذوق لا كقهوة يومية متوقعة. للباريستا وصاحب المقهى: يمكن استخدامه كمنتج موسمي أو تجربة تعليمية تجذب المهتمين، لكن لا تعتمد عليه كخيار أساسي قبل اختبار تقبّل الجمهور.', 4.5, ARRAY["جريء"], '—', 'جريء', '## ما هي؟\nنوع بن نادر نسبيًا وله شخصية مختلفة وقد تكون جريئة جدًا.\n\n## لماذا تهم الهاوي؟\nتفتح لك باب فهم أن القهوة ليست أرابيكا وروبوستا فقط.\n\n## ماذا يهم الباريستا؟\nتحتاج تقديمًا ذكيًا لأن الطعم قد يكون مفاجئًا وغير مألوف.\n\n## ماذا يهم صاحب المقهى؟\nمناسب كعرض محدود أو تجربة تذوق، وليس بالضرورة كمنتج ثابت في المنيو.\n\n## خطأ شائع\nتوقع طعم مألوف أو الحكم عليه من أول رشفة فقط.\n\n## نصيحة عملية\nقدمه بكميات صغيرة مع شرح مبسط للعميل عن سبب اختلافه.'),
  ('excelsa', 'إكسلسا', 'beans', 'البن والتحميص', 'إكسلسا (Excelsa) يُذكر غالبًا ضمن عائلة ليبريكا، لكنه يُستخدم في التعليم والتذوق كطابع مختلف يضيف عمقًا وحموضة وفاكهية إلى بعض الخلطات. للهواة: لا تبحث عنه كاسم مشهور مثل أرابيكا، بل افهمه كنكهة مساعدة أو تجربة مختلفة. للباريستا وصاحب المقهى: قد يفيد في بناء خلطة لها طبقات نكهية، لكن استخدامه يحتاج تذوقًا واختبارًا حتى لا يصبح الطعم غريبًا أو حادًا.', 4.5, ARRAY["فاكهي"], '—', 'فاكهي', '## ما هو؟\nطابع بن مميز قد يعطي نكهات فاكهية وحموضة مختلفة وعمقًا في الخلطة.\n\n## لماذا يهم الهاوي؟\nيساعدك على فهم كيف تضيف بعض الأنواع طبقة نكهة دون أن تكون هي الأساس.\n\n## ماذا يهم الباريستا؟\nيحتاج ضبطًا في الوصفة لأن الحموضة (Acidity) قد تظهر جميلة أو مزعجة حسب الاستخلاص (Extraction).\n\n## ماذا يهم صاحب المقهى؟\nمفيد للتميّز في خلطة خاصة، لكنه ليس خيارًا سهل البيع لكل جمهور.\n\n## خطأ شائع\nالتعامل معه كبديل مباشر لأرابيكا أو كنوع معروف للجميع.\n\n## نصيحة عملية\nاستخدمه في التذوق أو الخلطات الخاصة، وراقب تقبل العملاء قبل اعتماده.'),
  ('coffee-processing', 'معالجة البن', 'beans', 'البن والتحميص', 'معالجة البن (Coffee Processing) هي الطريقة التي تُفصل بها بذرة القهوة عن ثمرة القهوة بعد الحصاد، وهي من أكثر العوامل تأثيرًا على الطعم قبل التحميص (Roasting). المعالجة (Processing) المغسولة غالبًا تعطي كوبًا أنظف وأكثر وضوحًا، والطبيعية قد تعطي حلاوة وفاكهية أعلى، والعسلية تقع بينهما. للهواة: اسم البلد لا يكفي لفهم الطعم. للباريستا وصاحب المقهى: اختيار المعالجة (Processing) يغير وصفة التحضير وسهولة بيع القهوة للعميل.', 4.5, ARRAY["مهم"], '—', 'مهم', '## ما هي؟\nمرحلة تجهيز القهوة بعد الحصاد وقبل التحميص (Roasting).\n\n## مغسولة Washed\nغالبًا أنظف، أوضح، وأسهل في قراءة الحموضة (Acidity) والنكهات.\n\n## طبيعية Natural\nغالبًا أكثر فاكهية وحلاوة، لكنها قد تكون أثقل أو متخمّرة إذا لم تكن متقنة.\n\n## عسلية Honey\nمنطقة وسط بين المغسولة والطبيعية من حيث الحلاوة (Sweetness) والجسم.\n\n## لماذا تهم صاحب المقهى؟\nتؤثر على ثبات الطعم، شرح المنيو، وتقبل العميل.\n\n## خطأ شائع\nالحكم على القهوة من البلد فقط وتجاهل المعالجة (Processing).'),
  ('roast-levels', 'درجات التحميص', 'beans', 'البن والتحميص', 'درجات التحميص (Roast Levels) لا تعني فاتح أو غامق فقط؛ هي قرار يغير الحموضة (Acidity)، الحلاوة (Sweetness)، الجسم، المرارة (Bitterness)، ووضوح النكهات. التحميص (Roasting) الفاتح يبرز شخصية البن لكنه قد يكون حادًا إن أُسيء تحضيره. المتوسط غالبًا أكثر توازنًا. الداكن يعطي جسمًا ومرارة أعلى وقد يخفي تفاصيل المصدر. للهواة: لا يوجد تحميص أفضل دائمًا. للباريستا وصاحب المقهى: اختر التحميص (Roasting) حسب المشروب والجمهور وليس حسب الذوق الشخصي فقط.', 4.5, ARRAY["نكهة"], '—', 'نكهة', '## فاتح Light\nيوضح الحموضة (Acidity) والعطر وشخصية المصدر، لكنه يحتاج طحنًا وتحضيرًا أدق.\n\n## متوسط Medium\nغالبًا يوازن بين الحلاوة (Sweetness) والجسم والوضوح، ومناسب لجمهور أوسع.\n\n## داكن Dark\nيزيد المرارة (Bitterness) والجسم ونكهات التحميص (Roasting)، وقد يخفي تفاصيل البن.\n\n## لماذا يهم الهاوي؟\nيفسر لماذا تبدو بعض القهوة حامضة أو مرة أو متوازنة.\n\n## لماذا يهم صاحب المقهى؟\nاختيار التحميص (Roasting) يؤثر على رضا العملاء وثبات المشروبات.\n\n## خطأ شائع\nاعتبار الداكن أقوى دائمًا أو الفاتح أفضل دائمًا.'),
  ('grind-size', 'درجات الطحن', 'beans', 'البن والتحميص', 'درجات الطحن (Grind Size) هي الجسر بين البن والماء. الطحن الناعم يبطئ مرور الماء ويزيد الاستخلاص (Extraction)، والخشن يسرّع الماء ويقلل الاستخلاص (Extraction). لذلك درجة الطحن (Grind Size) التي تصلح للإسبريسو لا تصلح عادةً للفرنش برس أو V60. للهواة: تغيير الطحن قد يحل طعمًا حامضًا أو مرًا أكثر من تغيير نوع البن. للباريستا وصاحب المقهى: ثبات الطحن أساس ثبات الطعم وسرعة الخدمة وتقليل الهدر.', 4.5, ARRAY["استخلاص"], '—', 'استخلاص', '## ناعم Fine\nمناسب غالبًا للإسبريسو لأنه يحتاج مقاومة وضغطًا.\n\n## متوسط Medium\nمناسب لكثير من طرق التقطير مثل V60 حسب الوصفة.\n\n## خشن Coarse\nمناسب غالبًا للفرنش برس وبعض طرق النقع.\n\n## علامة طحن ناعم جدًا\nمرارة، جفاف، بطء شديد، أو انسداد في الإسبريسو.\n\n## علامة طحن خشن جدًا\nحموضة حادة، خفة، وماء يمر بسرعة.\n\n## خطأ شائع\nاستخدام درجة طحن واحدة لكل طرق التحضير.'),
  ('coffee-freshness', 'طزاجة القهوة', 'beans', 'البن والتحميص', 'طزاجة القهوة (Coffee Freshness) لا تعني أن أفضل كوب هو في يوم التحميص (Roasting) نفسه. بعد التحميص (Roasting) تخرج من البن غازات، وبعض القهوة تحتاج فترة راحة قصيرة حتى يصبح الاستخلاص (Extraction) أهدأ، خصوصًا في الإسبريسو. للهواة: اشترِ كمية تناسب استهلاكك ولا تخزنها قرب الحرارة والرطوبة. للباريستا وصاحب المقهى: إدارة تاريخ التحميص (Roasting) والمخزون تؤثر على ثبات الوصفة، الهدر، ورضا العميل.', 4.5, ARRAY["تخزين"], '—', 'تخزين', '## ما معنى الطزاجة؟\nقهوة حديثة التحميص (Roasting) نسبيًا ومخزنة بطريقة صحيحة، لا قهوة خرجت من المحمصة قبل دقائق فقط.\n\n## راحة البن Degassing\nفترة يخرج فيها الغاز من البن بعد التحميص (Roasting) ليصبح الاستخلاص (Extraction) أكثر استقرارًا.\n\n## للإسبريسو\nغالبًا يحتاج البن أيام راحة أكثر من الفلتر حتى لا يكون الاستخلاص (Extraction) مضطربًا.\n\n## للفلتر\nيمكن استخدامه أبكر أحيانًا، لكن الطعم يتغير يومًا بعد يوم.\n\n## خطأ شائع\nاستخدام البن فور التحميص (Roasting) دائمًا أو تركه مفتوحًا لأسابيع.\n\n## نصيحة عملية\nاحفظه في كيس محكم، بعيدًا عن الضوء والحرارة والرطوبة.'),
  ('single-origin', 'سنجل أوريجن', 'beans', 'البن والتحميص', 'سنجل أوريجن (Single Origin) يعني أن القهوة من مصدر محدد نسبيًا: بلد، منطقة، مزرعة، تعاونية، أو دفعة إنتاج. قيمته أنه يكشف شخصية المصدر والمعالجة (Processing) والتحميص (Roasting) بوضوح، لكنه ليس دائمًا أفضل من الخلطة. للهواة: هو خيار ممتاز للتذوق والتعلم. للباريستا وصاحب المقهى: رائع للفلتر والتجارب الموسمية، لكنه قد يكون أقل ثباتًا أو أعلى تكلفة من الخلطات اليومية.', 4.5, ARRAY["مصدر"], '—', 'مصدر', '## ما هو؟\nقهوة من مصدر محدد بدل خلط عدة مصادر بلا توضيح.\n\n## لماذا يهم الهاوي؟\nيساعدك على ربط الطعم بالمصدر والمعالجة (Processing) والتحميص (Roasting).\n\n## لماذا يهم الباريستا؟\nممتاز للتذوق والفلتر وتعليم العملاء عن الفروقات.\n\n## لماذا يهم صاحب المقهى؟\nيرفع صورة المقهى المختصة، لكنه يحتاج شرحًا وتسعيرًا مناسبًا.\n\n## خطأ شائع\nاعتباره دائمًا أفضل من الخلطات.\n\n## نصيحة عملية\nقدمه كخيار فلتر أو إصدار موسمي بدل الاعتماد عليه وحده لكل المشروبات.'),
  ('espresso-blend', 'خلطة الإسبريسو', 'beans', 'البن والتحميص', 'خلطة الإسبريسو (Espresso Blend) ليست خلطًا عشوائيًا ولا تعني جودة أقل. الخلطة الجيدة تُبنى لتحقيق هدف واضح: ثبات الطعم، توازن الحلاوة (Sweetness) والحموضة (Acidity) والجسم، كريما (Crema) جيدة، ونتيجة مناسبة مع الحليب. للهواة: الخلطة قد تكون أسهل وألطف من سنجل أوريجن حاد. للباريستا وصاحب المقهى: الخلطة الناجحة هي العمود الفقري للمشروبات اليومية لأنها تقلل التذبذب وتساعد الفريق على تقديم كوب ثابت.', 4.5, ARRAY["خلطة"], '—', 'خلطة', '## ما هي؟\nمزج مصادر أو محاصيل مختلفة لصناعة طعم ثابت ومتوازن.\n\n## لماذا تهم الهاوي؟\nتعطي غالبًا كوبًا أسهل وأكثر توازنًا، خصوصًا مع الحليب.\n\n## لماذا تهم الباريستا؟\nتساعد على ثبات الوصفة وتقليل مفاجآت الحموضة (Acidity) أو المرارة (Bitterness).\n\n## لماذا تهم صاحب المقهى؟\nهي أساس المنيو اليومي: إسبريسو، لاتيه، كابتشينو، وفلات وايت.\n\n## خطأ شائع\nاعتبار الخلطة أقل قيمة من سنجل أوريجن دائمًا.\n\n## نصيحة عملية\nاختبر الخلطة سوداء ومع الحليب قبل اعتمادها تجاريًا.'),
  ('bloom', 'تفتّح القهوة (Bloom)', 'terms', 'مصطلحات القهوة', 'تفتّح القهوة (Bloom) أو Bloom هو أول ترطيب للبن المطحون في التحضير بالفلتر. في هذه اللحظة تخرج الغازات المحبوسة بعد التحميص (Roasting)، ويبدأ سطح القهوة بالانتفاخ والفقاعات. للمبتدئ: هي خطوة قصيرة قبل إكمال الصب. للباريستا: تساعد على ترطيب القهوة بالتساوي وتقليل الاستخلاص (Extraction) غير المنتظم.', 4.5, ARRAY["مهم"], '30s', 'مهم', '## المعنى\nترطيب القهوة أولًا قبل إكمال الصب\n\n## لماذا يهم؟\nيساعد الماء على الوصول لكل القهوة بدل المرور من مسارات عشوائية\n\n## علامة جيدة\nانتفاخ وفقاعات خفيفة خصوصًا مع البن الطازج\n\n## خطأ شائع\nصب كل الماء مرة واحدة وتجاهل مرحلة التفتّح'),
  ('crema', 'كريما الإسبريسو (Crema)', 'terms', 'مصطلحات القهوة', 'الكريما (Crema) هي الطبقة الذهبية الرغوية التي تظهر فوق الإسبريسو بعد الاستخلاص (Extraction). شكلها جميل ويعطي انطباعًا أوليًا، لكنها ليست حكمًا نهائيًا على جودة القهوة. للمبتدئ: وجودها لا يعني دائمًا أن الكوب ممتاز. للباريستا: لونها وسماكتها قد تعطي إشارات عن الطزاجة والتحميص (Roasting) والاستخلاص (Extraction)، لكنها تحتاج تذوقًا لتأكيد الجودة.', 4.5, ARRAY["مهم"], '—', 'مهم', '## ما هي؟\nطبقة رغوية ذهبية فوق الإسبريسو\n\n## متى تكون مفيدة؟\nتعطي إشارة أولية عن الطزاجة وطريقة الاستخلاص (Extraction)\n\n## متى تخدعك؟\nقد تكون قوية مع قهوة عادية أو تحميص داكن جدًا\n\n## القاعدة الذهبية\nاحكم بالطعم لا بالشكل فقط'),
  ('body', 'قوام القهوة (Body)', 'terms', 'مصطلحات القهوة', 'قوام القهوة (Body) أو Body هو إحساس ثقل القهوة وامتلائها في الفم. قد تكون القهوة خفيفة مثل الشاي، أو متوسطة وناعمة، أو ثقيلة وكريمية. هذا الإحساس لا يعني أن القهوة أفضل أو أسوأ وحده؛ بل يساعدك على فهم أسلوب الكوب وما يناسب ذوقك أو منيو المقهى.', 4.5, ARRAY["مهم"], '—', 'مهم', '## خفيف\nيشبه الشاي، مناسب لمن يحب الوضوح والنظافة\n\n## متوسط\nمتوازن وسهل القبول عند أغلب الناس\n\n## ثقيل\nكريمي وواضح، يظهر كثيرًا في الإسبريسو وبعض التحضيرات\n\n## يتأثر بـ\nنوع البن، التحميص (Roasting)، الطحن، وطريقة التحضير'),
  ('extraction', 'الاستخلاص (Extraction)', 'terms', 'مصطلحات القهوة', 'الاستخلاص (Extraction) هو انتقال نكهات ومركبات القهوة من البن المطحون إلى الماء. إذا كان الاستخلاص (Extraction) ناقصًا تظهر القهوة حادة وضعيفة. وإذا كان زائدًا تظهر مرة وجافة. للمبتدئ: هو سبب كبير وراء اختلاف طعم نفس البن من مرة لأخرى. لصاحب المقهى: فهمه يساعد على ثبات الجودة وتقليل شكاوى العملاء.', 4.5, ARRAY["مهم"], '—', 'مهم', '## استخلاص (Extraction) ناقص\nحموضة حادة، طعم ضعيف، ونهاية قصيرة\n\n## استخلاص (Extraction) متوازن\nحلاوة، وضوح، وقوام مريح\n\n## استخلاص (Extraction) زائد\nمرارة واضحة، جفاف، وثقل مزعج\n\n## مفاتيح التحكم\nالطحن، الوقت، الحرارة، كمية الماء، ونسبة التحضير (Brew Ratio)'),
  ('brew-ratio', 'نسبة التحضير (Brew Ratio)', 'terms', 'مصطلحات القهوة', 'نسبة التحضير (Brew Ratio) هي العلاقة بين كمية القهوة وكمية الماء أو كمية القهوة الخارجة (Yield) في الكوب (Yield). هي لغة الوصفات في عالم القهوة؛ لأنها تجعل النتيجة قابلة للتكرار بدل الاعتماد على التخمين. للمقهى، النسبة الواضحة تعني جودة أكثر ثباتًا وتدريبًا أسهل للفريق.', 4.5, ARRAY["مهم"], '—', 'مهم', '## في الفلتر\nقد تبدأ من 1:15 إلى 1:17 حسب البن والذوق\n\n## في الإسبريسو\nمثال شائع: 18 غ بن يعطي 36 غ قهوة خارجة\n\n## لماذا تهم؟\nتساعدك على تكرار الكوب الناجح\n\n## خطأ شائع\nاستخدام الملعقة والعين بدل الميزان'),
  ('tds', 'نسبة المواد الذائبة (TDS)', 'terms', 'مصطلحات القهوة', 'TDS اختصار لـ Total Dissolved Solids، ويعني نسبة المواد الذائبة في القهوة. ببساطة: يقيس مدى تركيز المشروب. لا يحتاجه كل هاوٍ، لكنه مفيد للمحترفين والمقاهي التي تريد ضبط الوصفات بدقة ومقارنة النتائج بعيدًا عن الانطباع الشخصي فقط.', 4.5, ARRAY["متقدم"], '—', 'متقدم', '## المعنى المبسط\nمدى تركيز القهوة في الكوب\n\n## أداة القياس\nجهاز Refractometer عند المحترفين\n\n## لا يعني وحده\nأن القهوة جيدة أو سيئة\n\n## يفيد في\nالتدريب، ضبط الوصفات، ومراقبة الثبات'),
  ('channeling', 'تسرّب الماء من مسار واحد داخل القهوة (Channeling)', 'terms', 'مصطلحات القهوة', 'Channeling يعني أن الماء وجد طريقًا سهلًا داخل القهوة ومرّ من مسار واحد بدل أن يمر بالتساوي خلال كل البن. النتيجة تكون كوبًا متناقضًا: جزء مستخلص زيادة وجزء لم يُستخلص كفاية. يحدث كثيرًا في الإسبريسو بسبب توزيع غير متساوٍ أو كبس مائل أو طحن غير مناسب.', 4.5, ARRAY["مهم"], '—', 'مهم', '## ما الذي يحدث؟\nالماء يهرب من منطقة سهلة داخل القهوة\n\n## النتيجة\nحموضة ومرارة في نفس الكوب أحيانًا\n\n## الأسباب\nتوزيع سيئ، كبس غير مستوٍ، طحن غير مناسب\n\n## الحل\nتوزيع أفضل، كبس مستقيم، وضبط الطحن'),
  ('microfoam', 'رغوة الحليب الناعمة جدًا (Microfoam)', 'terms', 'مصطلحات القهوة', 'Microfoam هي رغوة حليب ناعمة جدًا (Microfoam) ومندمجة مع الحليب، وليست فقاعات كبيرة فوق السطح. هي التي تجعل اللاتيه والكابتشينو بقوام حريري وتسمح برسم اللاتيه آرت. للمبتدئ: الهدف ليس تكثير الرغوة فقط، بل جعلها ناعمة ولامعة ومتجانسة.', 4.5, ARRAY["مهم"], '—', 'مهم', '## الشكل الصحيح\nسطح لامع وناعم مثل الطلاء الخفيف\n\n## الشكل الخاطئ\nفقاعات كبيرة ورغوة منفصلة\n\n## تستخدم في\nلاتيه، كابتشينو، فلات وايت\n\n## تحتاج إلى\nتبخير صحيح ودمج جيد للحليب'),
  ('dial-in', 'ضبط الوصفة (Dialing In)', 'terms', 'مصطلحات القهوة', 'Dialing In يعني ضبط وصفة الإسبريسو حتى تصل إلى طعم متوازن. يشمل تعديل درجة الطحن (Grind Size)، جرعة البن، كمية القهوة الخارجة (Yield) في الكوب (Yield)، ووقت الاستخلاص (Extraction). في المقهى لا يحدث هذا مرة واحدة فقط؛ بل يتكرر مع تغيّر البن، عمره بعد التحميص (Roasting)، الرطوبة، وضغط العمل.', 4.5, ARRAY["مهم"], '—', 'مهم', '## المتغيرات\nالطحن، الجرعة، كمية القهوة الخارجة (Yield)، والوقت\n\n## الهدف\nطعم متوازن يمكن تكراره\n\n## خطأ شائع\nتغيير أكثر من عامل في نفس الوقت\n\n## لصاحب المقهى\nالوصفة المكتوبة تقلل الهدر وتثبت الجودة'),
  ('cupping', 'تذوق القهوة المعياري (Cupping)', 'terms', 'مصطلحات القهوة', 'Cupping هو أسلوب تذوق معياري يستخدم لمقارنة عينات القهوة بعيدًا عن تأثير أدوات التحضير المختلفة. تُطحن القهوة وتُنقع في أكواب بطريقة موحدة، ثم تُقيّم الرائحة والنكهة والحموضة (Acidity) والقوام والأثر اللاحق (Aftertaste). مفيد للهواة لفهم النكهات، ومهم للمقاهي عند اختيار البن.', 4.5, ARRAY["مهم"], '—', 'مهم', '## الهدف\nتقييم ومقارنة القهوة بعدل\n\n## يفيد في\nشراء البن، التدريب، وفهم النكهات\n\n## لا يحتاج إلى\nماكينة أو أدوات معقدة\n\n## خطأ شائع\nاعتباره جلسة تذوق عشوائية فقط'),
  ('acidity', 'الحموضة (Acidity)', 'terms', 'مصطلحات القهوة', 'الحموضة (Acidity) في القهوة لا تعني أن القهوة فاسدة أو مزعجة دائمًا. الحموضة (Acidity) الجميلة تعطي إحساسًا منعشًا يشبه الفواكه والحمضيات، أما الحموضة (Acidity) السيئة فتكون حادة ولاذعة. الفرق يظهر بالتذوق، ويتأثر بالبن، المعالجة (Processing)، التحميص (Roasting)، والاستخلاص (Extraction).', 4.5, ARRAY["مهم"], '—', 'مهم', '## حموضة جميلة\nفاكهية، نظيفة، ومنعشة\n\n## حموضة مزعجة\nحادة، لاذعة، وغير متوازنة\n\n## تظهر كثيرًا في\nبعض أنواع القهوة المختصة والتحميص (Roasting) الفاتح\n\n## تتأثر بـ\nالمنشأ (Origin)، المعالجة (Processing)، الطحن، ووقت التحضير'),
  ('bitterness', 'المرارة (Bitterness)', 'terms', 'مصطلحات القهوة', 'المرارة (Bitterness) جزء طبيعي من القهوة، لكنها تصبح مشكلة عندما تطغى على باقي النكهات وتترك جفافًا في الفم. قد تأتي من تحميص داكن جدًا، أو استخلاص (Extraction) زائد، أو ماء حار جدًا، أو طحن ناعم أكثر من اللازم. في المقهى، المرارة (Bitterness) المزعجة من أكثر أسباب رفض العميل للكوب.', 4.5, ARRAY["مهم"], '—', 'مهم', '## مرارة مقبولة\nتدعم التوازن ولا تطغى\n\n## مرارة مزعجة\nجفاف، طعم محترق، ونهاية ثقيلة\n\n## أسباب شائعة\nتحميص داكن، استخلاص (Extraction) زائد، طحن ناعم جدًا\n\n## الحل\nراجع الوصفة والطحن ودرجة الحرارة'),
  ('sweetness', 'الحلاوة الطبيعية (Sweetness)', 'terms', 'مصطلحات القهوة', 'الحلاوة (Sweetness) في القهوة لا تعني إضافة السكر. المقصود هو إحساس طبيعي يظهر عندما تكون القهوة متوازنة، وقد يشبه الكراميل أو العسل أو الفواكه الناضجة. تظهر الحلاوة (Sweetness) أكثر مع بن جيد، تحميص مناسب، واستخلاص (Extraction) مضبوط. وهي من أهم علامات الكوب الممتع.', 4.5, ARRAY["مهم"], '—', 'مهم', '## المعنى\nإحساس طبيعي بالحلاوة (Sweetness) دون سكر\n\n## تظهر مع\nبن جيد واستخلاص (Extraction) متوازن\n\n## نكهات محتملة\nكراميل، عسل، شوكولاتة، فواكه ناضجة\n\n## خطأ شائع\nاعتقاد أن الحلاوة (Sweetness) تعني إضافة محليات'),
  ('aftertaste', 'الأثر اللاحق (Aftertaste)', 'terms', 'مصطلحات القهوة', 'الأثر اللاحق (Aftertaste) هو الطعم والإحساس الذي يبقى في الفم بعد الرشفة. قد يكون لطيفًا وطويلًا مثل الشوكولاتة أو الفواكه، وقد يكون مزعجًا وجافًا أو محترقًا. هذا المصطلح مهم لأنه يكشف جودة الكوب بعد اللحظة الأولى، لا أثناء الشرب فقط.', 4.5, ARRAY["مهم"], '—', 'مهم', '## أثر جيد\nنظيف، ممتع، ويستمر بلطف\n\n## أثر سيئ\nمر، جاف، أو محترق\n\n## لماذا يهم؟\nلأن العميل يتذكر النهاية غالبًا\n\n## يتأثر بـ\nالبن، التحميص (Roasting)، الاستخلاص (Extraction)، ونظافة المعدات'),
  ('origin', 'المنشأ (Origin)', 'terms', 'مصطلحات القهوة', 'المنشأ (Origin) يعني البلد أو المنطقة التي جاءت منها القهوة. لكنه ليس القصة كاملة؛ فالمزرعة، الارتفاع، السلالة (Varietal)، المعالجة (Processing)، والتحميص (Roasting) كلها تغيّر الطعم. للمبتدئ: المنشأ (Origin) يساعدك على توقع بعض الملامح. لصاحب المقهى: لا تبنِ قرار الشراء على اسم البلد فقط.', 4.5, ARRAY["مهم"], '—', 'مهم', '## يشير إلى\nبلد، منطقة، أو مزرعة\n\n## لا يكفي وحده\nلأن المعالجة (Processing) والتحميص (Roasting) يغيّران النتيجة\n\n## يفيد في\nفهم الهوية العامة للقهوة\n\n## خطأ شائع\nشراء القهوة لأن اسم المنشأ (Origin) مشهور فقط'),
  ('varietal', 'السلالة (Varietal)', 'terms', 'مصطلحات القهوة', 'السلالة (Varietal) هي نوع نبات القهوة داخل عائلة البن، مثل بوربون، كاتورا، غيشا، وغيرها. السلالة (Varietal) قد تؤثر على النكهة والإنتاجية والمقاومة، لكنها لا تضمن الجودة وحدها. تحتاج زراعة جيدة، معالجة دقيقة، وتحميص مناسب حتى تظهر قيمتها في الكوب.', 4.5, ARRAY["متقدم"], '—', 'متقدم', '## أمثلة\nبوربون، كاتورا، غيشا\n\n## تؤثر على\nالنكهة، الإنتاج، وقابلية الزراعة\n\n## ليست ضمانًا\nالاسم وحده لا يكفي\n\n## لصاحب المقهى\nاستخدمها كجزء من القصة لا كدليل جودة مطلق'),
  ('degassing', 'تفريغ الغازات (Degassing)', 'terms', 'مصطلحات القهوة', 'بعد التحميص (Roasting) تطلق القهوة غازات، خصوصًا ثاني أكسيد الكربون. لذلك قد تحتاج القهوة إلى فترة راحة قبل أن تعطي نتيجة مستقرة، خاصة في الإسبريسو. البن الطازج جدًا ليس دائمًا الأفضل فورًا؛ أحيانًا يحتاج أيامًا ليهدأ وتصبح الوصفة أسهل في الضبط.', 4.5, ARRAY["مهم"], '—', 'مهم', '## متى يحدث؟\nبعد التحميص (Roasting) مباشرة\n\n## لماذا يهم؟\nلأن الغازات تؤثر على الاستخلاص (Extraction) والثبات\n\n## خصوصًا في\nالإسبريسو\n\n## خطأ شائع\nاستخدام البن فور التحميص (Roasting) دائمًا'),
  ('retention', 'بقايا القهوة العالقة داخل المطحنة (Retention)', 'terms', 'مصطلحات القهوة', 'Retention يعني بقاء جزء من البن المطحون داخل المطحنة بعد الطحن. هذه البقايا قد تخرج لاحقًا وتختلط بجرعة جديدة، فتؤثر على الطعم وثبات الوصفة، خصوصًا عند تغيير البن أو درجة الطحن (Grind Size). للمقهى، فهم الاحتباس يساعد على تقليل الهدر وتحسين الثبات.', 4.5, ARRAY["مهم"], '—', 'مهم', '## المشكلة\nبقايا قديمة تختلط بطحن جديد\n\n## الأثر\nتغير في الطعم وثبات الوصفة\n\n## يهم أكثر في\nالمقاهي وتغيير البن المتكرر\n\n## الحل\nتنظيف دوري، طحن تصفية عند الحاجة، وفهم سلوك المطحنة'),
  ('yield', 'كمية القهوة الخارجة في الكوب (Yield)', 'terms', 'مصطلحات القهوة', 'Yield يعني وزن القهوة السائلة الخارجة بعد الاستخلاص (Extraction). في الإسبريسو مثلًا قد تستخدم 18 غرامًا من البن للحصول على 36 غرامًا من القهوة في الكوب. هذا الرقم أهم من حجم الفنجان لأنه يساعدك على فهم قوة الكوب وتكرار الوصفة بدقة.', 4.5, ARRAY["مهم"], '—', 'مهم', '## يقاس بـ\nالغرام غالبًا\n\n## مثال شائع\n18g بن يعطي 36g قهوة خارجة\n\n## لماذا يهم؟\nيثبت الوصفة ويساعد على مقارنة النتائج\n\n## خطأ شائع\nالاعتماد على حجم الفنجان بدل الميزان'),
  ('preinfusion', 'التمهيد بالماء (Pre-infusion)', 'terms', 'مصطلحات القهوة', 'Pre-infusion هو ترطيب القهوة بضغط منخفض قبل بدء الاستخلاص (Extraction) الكامل، خصوصًا في الإسبريسو. الهدف أن تتشبع القهوة بالماء بهدوء قبل الضغط العالي، مما قد يقلل التسرّب غير المتساوي ويحسن انتظام الاستخلاص (Extraction). لكنه ليس حلًا سحريًا لو كان الطحن أو التوزيع سيئًا.', 4.5, ARRAY["مهم"], '—', 'مهم', '## المعنى\nترطيب أولي قبل الضغط الكامل\n\n## الفائدة\nقد يقلل Channeling ويحسن الانتظام\n\n## لا يعوض\nطحنًا سيئًا أو توزيعًا غير متساوٍ\n\n## يظهر في\nبعض ماكينات الإسبريسو والوصفات المتقدمة'),
  ('before-opening-cafe', 'قبل افتتاح المقهى', 'cafe', 'إنشاء مقهى', 'نجاح المقهى يبدأ قبل الافتتاح. الفكرة الجميلة لا تكفي إذا لم تكن التكاليف واضحة، والموقع مناسبًا، والمنيو قابلًا للتشغيل، والهوية مفهومة.', 4.5, ARRAY["تأسيس"], '—', 'تأسيس', '## الفكرة\nالمقهى يفشل قبل الافتتاح أحيانًا\n\n## خطأ شائع\nالبدء بالديكور قبل الدراسة\n\n## نصيحة عملية\nاجمع الأرقام قبل توقيع الإيجار'),
  ('building-coffee-menu', 'بناء منيو القهوة', 'cafe', 'إنشاء مقهى', 'المنيو الكبير لا يعني مقهى أقوى. المنيو الذكي واضح، مربح، سريع التشغيل، ويخدم هوية المكان.', 4.5, ARRAY["منيو"], '—', 'منيو', '## الفكرة\nالوضوح أهم من كثرة الأصناف\n\n## خطأ شائع\nإضافة كل المشروبات لإرضاء الجميع\n\n## نصيحة عملية\nاختبر الربحية وسرعة التحضير'),
  ('bar-workflow', 'تدفق العمل خلف البار', 'cafe', 'إنشاء مقهى', 'خلف البار، كل خطوة زائدة تتحول إلى تأخير. مكان المطحنة والماكينة والحليب والمغسلة يجب أن يخدم حركة الباريستا لا شكل الصورة فقط.', 4.5, ARRAY["مهم"], '—', 'مهم', '## الفكرة\nالمسار الجيد يقلل التأخير\n\n## خطأ شائع\nتصميم بار جميل لكنه غير عملي\n\n## نصيحة عملية\nارسم رحلة الطلب قبل تنفيذ الكونتر'),
  ('cafe-branding', 'هوية المقهى', 'cafe', 'إنشاء مقهى', 'هوية المقهى ليست شعارًا فقط؛ هي الاسم، النبرة، الألوان، طريقة التصوير، شكل المنيو، التغليف، وحتى طريقة الترحيب بالعميل.', 4.5, ARRAY["هوية"], '—', 'هوية', '## الفكرة\nالهوية تجربة كاملة\n\n## خطأ شائع\nحصر الهوية في الشعار\n\n## نصيحة عملية\nوحّد النبرة البصرية والكلامية'),
  ('location-choice', 'اختيار موقع المقهى', 'cafe', 'إنشاء مقهى', 'الموقع لا يعني شارعًا مزدحمًا فقط. المهم أن تعرف من يمر، لماذا يتوقف، كم يدفع، وهل يناسب مفهومك.', 4.5, ARRAY["موقع"], '—', 'موقع', '## الفكرة\nالموقع جمهور وسلوك\n\n## خطأ شائع\nاختيار الأغلى لأنه أوضح\n\n## نصيحة عملية\nراقب الحركة في أوقات مختلفة'),
  ('customer-experience', 'تجربة العميل', 'cafe', 'إنشاء مقهى', 'العميل لا يعود للقهوة فقط. يعود لأن الطلب واضح، الانتظار مقبول، المكان مريح، والمنتج ثابت.', 4.5, ARRAY["تجربة"], '—', 'تجربة', '## الفكرة\nالتفاصيل تصنع الولاء\n\n## خطأ شائع\nالتركيز على المنتج ونسيان الرحلة\n\n## نصيحة عملية\nاختبر التجربة كعميل لا كمالك'),
  ('staff-training', 'تدريب الفريق', 'cafe', 'إنشاء مقهى', 'المقهى لا يعمل بالماكينة وحدها. الفريق غير المدرب يسبب هدرًا وبطئًا وتجربة غير ثابتة.', 4.5, ARRAY["فريق"], '—', 'فريق', '## الفكرة\nالفريق هو جودة التشغيل\n\n## خطأ شائع\nالتدريب يوم الافتتاح فقط\n\n## نصيحة عملية\nاكتب وصفات وإجراءات بسيطة'),
  ('supplier-selection', 'اختيار الموردين', 'cafe', 'إنشاء مقهى', 'المورد الجيد لا يعطيك منتجًا فقط؛ يعطيك ثباتًا ومواعيد واضحة ودعمًا عند الحاجة.', 4.5, ARRAY["موردين"], '—', 'موردين', '## الفكرة\nالمورد جزء من التجربة\n\n## خطأ شائع\nالاختيار على السعر فقط\n\n## نصيحة عملية\nاختبر الجودة والثبات قبل التعاقد'),
  ('opening-menu-test', 'اختبار المنيو قبل الافتتاح', 'cafe', 'إنشاء مقهى', 'قبل الافتتاح، لا تختبر الطعم فقط. اختبر سرعة التحضير، تكلفة الكوب، قابلية الفريق للتنفيذ، وردة فعل العملاء التجريبيين.', 4.5, ARRAY["اختبار"], '—', 'اختبار', '## الفكرة\nاختبر قبل أن تطبع\n\n## خطأ شائع\nاعتماد المنيو من الذوق الشخصي فقط\n\n## نصيحة عملية\nنفذ يوم تجربة مصغر'),
  ('small-kiosk', 'كشك قهوة', 'cafe', 'إنشاء مقهى', 'الكشك ليس نسخة صغيرة من مقهى كامل. يحتاج منيو أذكى، معدات مختصرة، ومسار خدمة سريع.', 4.5, ARRAY["كشك"], '—', 'كشك', '## الفكرة\nمساحة صغيرة تحتاج تركيزًا أعلى\n\n## خطأ شائع\nتحميل الكشك بمنيو ضخم\n\n## نصيحة عملية\nاختر أصنافًا قليلة وسريعة وربحية'),
  ('drive-thru', 'درايف ثرو', 'cafe', 'إنشاء مقهى', 'الدرايف ثرو يعتمد على السرعة والدقة أكثر من الجلوس والتصوير. نجاحه في وضوح المنيو وتدريب الفريق ومكان التسليم.', 4.5, ARRAY["نموذج"], '—', 'نموذج', '## الفكرة\nالسرعة هي المنتج الثاني\n\n## خطأ شائع\nمنيو معقد يبطئ الطابور\n\n## نصيحة عملية\nصمم الطلبات الأكثر مبيعًا لتخرج بسرعة'),
  ('coffee-corner', 'ركن قهوة', 'cafe', 'إنشاء مقهى', 'ركن القهوة ليس ديكورًا فقط. إذا صُمم جيدًا يصبح مساحة يومية مريحة تجمع الأدوات والمنتجات بشكل عملي وجميل.', 4.5, ARRAY["ركن"], '—', 'ركن', '## الفكرة\nديكور عملي لا منظر فقط\n\n## خطأ شائع\nنسيان التخزين والكهرباء\n\n## نصيحة عملية\nخطط للمعدات والاستخدام اليومي'),
  ('why-no-generic-costs', 'لماذا لا نعطي رقمًا عامًا؟', 'costing', 'دراسة التكاليف', 'تكلفة المقهى ليست رقمًا يصلح للجميع. مدينة المشروع، المساحة، الإيجار، نوع التشغيل، المعدات، والهوية كلها تغيّر النتيجة. الرقم العام قد يطمئنك كذبًا أو يخيفك بلا سبب.', 4.5, ARRAY["مخصص"], '—', 'مخصص', '## السبب\nكل مشروع له ظروفه\n\n## الخطر\nأرقام عامة مضللة\n\n## الحل\nدراسة خاصة حسب التفاصيل'),
  ('cost-items', 'بنود يجب حسابها', 'costing', 'دراسة التكاليف', 'قبل افتتاح المقهى يجب حساب أكثر من الديكور والماكينة: إيجار، تأسيس، معدات، رواتب، مخزون أولي، رخص، تسويق، تشغيل، وهامش طوارئ.', 4.5, ARRAY["بنود"], '—', 'بنود', '## بنود مباشرة\nمعدات وديكور وتأسيس\n\n## بنود تشغيل\nرواتب ومخزون وفواتير\n\n## لا تنسَ\nهامش طوارئ'),
  ('kiosk-vs-cafe-cost', 'كشك أم مقهى كامل؟', 'costing', 'دراسة التكاليف', 'الكشك والمقهى الكامل ليسا اختلاف مساحة فقط. الكشك يحتاج تركيزًا وسرعة، والمقهى الكامل يحتاج تجربة جلوس وتشغيل أوسع.', 4.5, ARRAY["نموذج"], '—', 'نموذج', '## الكشك\nتركيز وسرعة\n\n## المقهى الكامل\nتجربة وتشغيل أوسع\n\n## الدراسة\nتحدد الأنسب لرأس المال'),
  ('rent-risk', 'الإيجار قد يكسر المشروع', 'costing', 'دراسة التكاليف', 'الإيجار ليس رقمًا شهريًا فقط؛ هو ضغط ثابت قبل أن تبيع أول كوب. إذا كان أعلى من قدرة المبيعات المتوقعة، سيضغط المشروع من أول شهر.', 4.5, ARRAY["إيجار"], '—', 'إيجار', '## الخطر\nمصروف ثابت عالي\n\n## الخطأ\nاختيار موقع قبل حساب المبيعات\n\n## الحل\nاختبار نقطة التعادل'),
  ('equipment-budget', 'ميزانية المعدات', 'costing', 'دراسة التكاليف', 'شراء أغلى معدات لا يعني نجاح المقهى، وشراء الأرخص قد يكلفك أعطالًا وهدرًا. القرار الصحيح يوازن بين الطلب والجودة والصيانة.', 4.5, ARRAY["معدات"], '—', 'معدات', '## الأغلى\nليس دائمًا الأفضل\n\n## الأرخص\nقد يرفع الأعطال\n\n## الأصح\nيناسب حجم التشغيل'),
  ('request-cost-study', 'اطلب دراسة تكاليف خاصة', 'costing', 'دراسة التكاليف', 'إذا كنت جادًا بفتح مقهى في فلسطين، لا تبدأ برقم من منشور عام. أرسل تفاصيل مشروعك لنحضّر لك دراسة تكاليف تناسب مدينتك، المساحة، نوع التشغيل، مستوى التجهيز، وطموح العلامة.', 4.5, ARRAY["مراسلة"], '—', 'مراسلة', '## المطلوب\nتفاصيل مشروعك\n\n## النتيجة\nدراسة مخصصة\n\n## الزر\nينقلك لخدمة دراسة التكاليف');
